window.__ARXIV_DATA__ = {"papers":[{"id":"2606.23688v1","title":"Lift4D: Harmonizing Single-View 3D Estimation for 4D Reconstruction In-the-Wild","abstract":"Reconstructing dynamic non-rigid objects from monocular video requires integrating visual cues from direct observations with data-driven priors over geometry and appearance. Prior approaches either learn to directly predict 4D representations from visual input or initialize a 3D representation that is subsequently deformed and refined based on video evidence. However, the former are constrained by the scarcity of 4D training data, while the latter leverage priors only for the initial reconstruction and rely solely on video supervision thereafter; neither handles complex in-the-wild scenarios with large deformations and occlusions well. We present Lift4D, a test-time optimization framework that addresses both limitations. First, we adapt an existing single-view 3D reconstruction model to yield temporally consistent per-frame predictions via causal latent conditioning, providing a coherent initialization for a deformable 3D Gaussian Splatting representation. We then ``sculpt'' this representation to match the input video through an occlusion-aware optimization that faithfully recovers visible surface details while completing unobserved regions using a view-conditioned diffusion prior. We demonstrate that Lift4D clearly improves over prior 4D reconstruction methods, particularly on challenging in-the-wild sequences with severe occlusions and non-rigid motion.","authors":["Yehonathan Litman","Xiaoxuan Ma","Manan Shah","Nicolas Ugrinovic","Kris Kitani","Fernando De la Torre","Shubham Tulsiani"],"published":"2026-06-22T17:59:54Z","updated":"2026-06-22T17:59:54Z","abstract_url":"https://arxiv.org/abs/2606.23688v1","html_url":"https://arxiv.org/html/2606.23688v1","pdf_url":"https://arxiv.org/pdf/2606.23688v1.pdf","matched_keywords":["video","3d","representation","diffusion"],"source_used":"html","source_text_chars":60515,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, 3d, representation, diffusion 相关；摘要显示其主要贡献为：Reconstructing dynamic non-rigid objects from monocular video requires integrating visual cues from direct observations with data-driven priors over geometry and appearance. Prior approaches either learn to directly predict 4D representations from visual inpu...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:15+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23682v1","title":"Keep The Essentials: Efficient Reference Conditioned Generation via Token Dropping","abstract":"Reference-based diffusion models enable highly controllable image generation by leveraging elements from input images to guide prompt-driven synthesis. However, these models are computationally expensive in runtime, and their cost scales severely with the number of input references. While the efficiency of diffusion models has been extensively studied in the context of prompt-driven generation, it remains largely under-explored in the realm of reference-based models. This setting presents unique challenges not addressed by methods focusing solely on generation. In particular, the wasteful representation of references as dense token grids offers significant opportunities for improvement. In this work, we present Sparse Context, a method for constructing sparse reference representations by retaining only a reduced subset of reference tokens. We observe that even without modifying the model, dropping a significant portion of reference tokens at inference time largely preserves its generation capabilities. To fully realize this potential, we fine-tune the model with random token dropping at varying ratios, encouraging robustness to partial reference representations. Crucially, this training strategy decouples the model from any specific token selection rule, allowing flexible control at inference time. At inference time, instead of random dropping, we apply task-aware token selection strategies that prioritize the most informative regions of the reference images, adapting the token budget to the input and task requirements. Extensive experiments show our method achieves a 4x increase in inference speed for multi-reference generation and an 2x for single reference generation. Importantly, this efficiency is achieved without compromising visual quality across both spatially-aligned editing and subject-driven generation.","authors":["Rishubh Parihar","Ayush Raina","R. Venkatesh Babu","Or Patashnik"],"published":"2026-06-22T17:59:28Z","updated":"2026-06-22T17:59:28Z","abstract_url":"https://arxiv.org/abs/2606.23682v1","html_url":"https://arxiv.org/html/2606.23682v1","pdf_url":"https://arxiv.org/pdf/2606.23682v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"html","source_text_chars":61575,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation, diffusion 相关；摘要显示其主要贡献为：Reference-based diffusion models enable highly controllable image generation by leveraging elements from input images to guide prompt-driven synthesis. However, these models are computationally expensive in runtime, and their cost scales severely with the num...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:15+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23679v1","title":"Semantic Browsing: Controllable Diversity for Image Generation","abstract":"Modern text-to-image models excel in visual fidelity and prompt adherence. However, this strict adherence comes at the cost of diversity: generated samples tend to collapse into a single visual interpretation. Existing methods to improve diversity produce outputs driven by incidental variations rather than meaningful design choices. This motivates a new variant of the diversity task where structure is enforced on the generated samples. We introduce a method for controlled diversity that enables Semantic Browsing, where users can navigate structured image galleries and experience creative exploration through a systematic traversal of meaningful, interpretable axes of variation. Achieving this level of semantic control requires a deep understanding of the scene. We exploit the fact that recent text-to-image models are trained on elaborated captions, effectively decoupling semantic decision-making from pixel generation. This enables a paradigm shift: instead of relying on stochastic variation within the text-to-image model, we induce diversity directly at the text level. By leveraging rich textual representations, we allow a Vision Language Model (VLM) to operate on the full scene context. To overcome the generic outputs typical of standard VLMs, we employ an agentic workflow that explicitly enforces structured variation attuned to the original prompt. We demonstrate that our method produces diverse and navigable design spaces where every variation corresponds to a specific, user-understandable semantic decision.","authors":["Sara Dorfman","Maya Vishnevsky","Omer Dahary","Or Patashnik","Daniel Cohen-Or"],"published":"2026-06-22T17:59:17Z","updated":"2026-06-22T17:59:17Z","abstract_url":"https://arxiv.org/abs/2606.23679v1","html_url":"https://arxiv.org/html/2606.23679v1","pdf_url":"https://arxiv.org/pdf/2606.23679v1.pdf","matched_keywords":["agent","representation"],"source_used":"html","source_text_chars":66969,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 agent, representation 相关；摘要显示其主要贡献为：Modern text-to-image models excel in visual fidelity and prompt adherence. However, this strict adherence comes at the cost of diversity: generated samples tend to collapse into a single visual interpretation. Existing methods to improve diversity produce out...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:15+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23678v1","title":"AIR: Adaptive Interleaved Reasoning with Code in MLLMs","abstract":"Following the paradigm shift initiated by OpenAI o3, interleaved reasoning with code to enhance multimodal large language models (MLLMs) has become a pivotal research frontier. The existing literature focuses primarily on tool-use within vision-perception tasks. However, such approaches typically rely on predefined heuristics for visual manipulation and are inherently incapable of addressing numerical computation problems due to their exclusive focus on visual operations. This paper empowers MLLMs with adaptive interleaved reasoning capabilities through extended reinforcement learning training on code-augmented complex numerical computation tasks. To this end, we propose a comprehensive three-component solution consisting of: a two-stage cold-start data construction pipeline, data filtering strategies for RL dataset curation, and an adaptive tool-invocation strategy leveraging a group-constrained reward function for interleaved reasoning trajectories. Extensive experiments demonstrate that after Reinforcement Learning training with the group-constrained reward function, performance improves by an average of 6.1 percentage points (pp) on evaluation benchmarks. Specifically, the accuracy for interleaved reasoning samples increases by 9.9 pp, and the overall success rate of tool-use exceeds 95%. Our data and code are available at: https://github.com/CongHan0808/AIR.git.","authors":["Cong Han","Xiaohan Lan","Haibo Qiu","Yujie Zhong"],"published":"2026-06-22T17:58:54Z","updated":"2026-06-22T17:58:54Z","abstract_url":"https://arxiv.org/abs/2606.23678v1","html_url":"https://arxiv.org/html/2606.23678v1","pdf_url":"https://arxiv.org/pdf/2606.23678v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":72751,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：Following the paradigm shift initiated by OpenAI o3, interleaved reasoning with code to enhance multimodal large language models (MLLMs) has become a pivotal research frontier. The existing literature focuses primarily on tool-use within vision-perception tas...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:15+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23675v1","title":"IMAGIN-4D: Image-Guided Controllable Interaction Generation","abstract":"Generating human-object interactions (HOI) is central to character animation, robotics, AR/VR, and embodied AI. Recent HOI generation methods synthesize motion from text, object geometry, and sparse waypoints, controlling action semantics and object trajectories. However, these signals underspecify interaction: the same prompt and trajectory can produce different grasps, approach directions, body poses, object poses, contacts, and body-object layouts. We address this ambiguity with a reference image as a visual specification of the desired interaction snapshot. However, a single global image representation conflates distinct cues and conditions all frames on identical visual evidence. We therefore introduce IMAGIN-4D, a diffusion-based HOI generator that decomposes image conditioning spatio-temporally. For spatial conditioning, IMAGIN-4D extracts supervised interaction-state tokens for body pose, object pose, body-object contact, and spatial relationships at the depicted frame. For temporal conditioning, it computes frame-aware tokens by querying image patches per generated frame, allowing sequence segments to attend to different visual cues from the same image. To balance image, text, and waypoint cues, IMAGIN-4D uses role-aware conditioning: text, waypoints, and interaction-state tokens use separate AdaLN streams, while frame-aware visual tokens cross-attend with motion tokens. Since HOI motion datasets lack paired images, we build a synthetic motion-to-image rendering pipeline from FullBodyManipulation (FBM) and introduce an image-adherence metric to evaluate whether generated motions match the reference snapshot. Experiments on FBM and BEHAVE show that IMAGIN-4D improves fine-grained interaction control over single-token and uniformly image-conditioned baselines while preserving waypoint-following and motion quality. Code and models will be released at https://imagin4d.github.io.","authors":["Sai Kumar Dwivedi","Federica Bogo","Buğra Tekin","Chenhongyi Yang","Nadine Bertsch","Tomas Hodan","Michael J. Black","Dimitrios Tzionas","Shreyas Hampali"],"published":"2026-06-22T17:58:03Z","updated":"2026-06-22T17:58:03Z","abstract_url":"https://arxiv.org/abs/2606.23675v1","html_url":"https://arxiv.org/html/2606.23675v1","pdf_url":"https://arxiv.org/pdf/2606.23675v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"html","source_text_chars":92981,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation, diffusion 相关；摘要显示其主要贡献为：Generating human-object interactions (HOI) is central to character animation, robotics, AR/VR, and embodied AI. Recent HOI generation methods synthesize motion from text, object geometry, and sparse waypoints, controlling action semantics and object trajector...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:15+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23669v1","title":"GeoFidelity-Bench: Evaluating Segment-Level Geographic Fidelity in Text-to-Image Street-View Generation","abstract":"Text-to-image models can generate visually plausible city streets, but whether their outputs correspond to a requested road segment rather than a generic city prior remains unclear. We introduce GeoFidelity-Bench, a reference-panel benchmark for segment-conditioned geographic fidelity in street-view generation. It contains 7,117 curated Mapillary images covering 109 named OpenStreetMap road segments in 25 cities across six continents. For each generated panel, the benchmark ranks the target reference panel against panels from the nearest segment in the same city, other segments in the same city, and segments from other cities, making local discrimination rather than absolute target similarity the primary test. We evaluate six open-weight text-to-image generators under city-only, street-and-neighborhood, and GPS-augmented prompts. Adding street and neighborhood names is associated with an increase of 5.5 percentage points in top-1 retrieval accuracy over city-only prompts, with a 95% confidence interval from 3.4 to 7.7 percentage points. However, the similarity margin between the target and the nearest segment in the same city remains near zero, indicating that local names improve broad local plausibility more than exact segment identity. Prompts that keep the city fixed but use incorrect street or neighborhood names further show that only part of the gain depends on the correct local names, while appending raw GPS coordinates as ordinary text yields no statistically clear additional benefit. Held-out real-image queries successfully recover segment identity, showing that the curated references contain usable segment-level signal. GeoFidelity-Bench thus reveals a persistent gap between city- or neighborhood-plausible street-view generation and faithful generation for a specific road segment.","authors":["Kaizhen Tan","Hanzhe Hong","Siru Tao"],"published":"2026-06-22T17:53:26Z","updated":"2026-06-22T17:53:26Z","abstract_url":"https://arxiv.org/abs/2606.23669v1","html_url":"https://arxiv.org/html/2606.23669v1","pdf_url":"https://arxiv.org/pdf/2606.23669v1.pdf","matched_keywords":["retrieval"],"source_used":"html","source_text_chars":55771,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 retrieval 相关；摘要显示其主要贡献为：Text-to-image models can generate visually plausible city streets, but whether their outputs correspond to a requested road segment rather than a generic city prior remains unclear. We introduce GeoFidelity-Bench, a reference-panel benchmark for segment-condi...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:15+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23665v1","title":"PHAST-Net: Attention-Guided, Physics-Informed Network for Unified Estimation of Ideal Time-Frequency Representations","abstract":"We introduce PHAST-Net, an attention-guided, physics-informed network for unified estimation of Ideal Time-Frequency Representations (ITFRs), spanning spectral, tempo-based, metrical, and harmonic representations such as Spectrograms, Tempograms, and Metrograms. PHAST-Net learns an application-general mapping from a constellation of wavelet transforms, the proposed Continuous Log-frequency Adaptive Wavelet Transform (CLAWT), to high-resolution, cross-term-suppressed time-frequency (T-F) representations. The proposed constellation of CLAWTs is selected through Cohen's class kernel analysis to maximise curvature coverage in a logarithmic-frequency T-F plane tailored to harmonic signal structure. PHAST-Net further incorporates a proposed physics-informed auxiliary reprojection loss designed to reconstruct the idealised observed CLAWT constellation from the predicted ITFR and the corresponding Cohen's class kernels during training. This auxiliary objective promotes transform consistency and energy conservation, mitigates pathological target sparsity, and enhances optimisation stability. Attention layers further promote effective cross-term suppression across the input constellation. The log-frequency formulation also enables Harmonic PHAST-Net, which estimates a Harmonic ITFR that isolates fundamental structure, supporting robust fundamental-only representations for speech and music, such as derived fundamental Tempograms and Metrograms. We further introduce Spline-PHAST-Net, which parameterises detected and associated T-F ridges as continuous spline trajectories, enabling arbitrary-grid re-rendering and signal reconstruction. Trained on an effectively unbounded procedurally generated dataset, PHAST-Net demonstrates improved accuracy over established approaches, providing a unified framework for high-resolution, cross-term-robust analysis of speech, music, and broader nonstationary signals.","authors":["James M. Cozens","Simon J. Godsill"],"published":"2026-06-22T17:49:00Z","updated":"2026-06-22T17:49:00Z","abstract_url":"https://arxiv.org/abs/2606.23665v1","html_url":"https://arxiv.org/html/2606.23665v1","pdf_url":"https://arxiv.org/pdf/2606.23665v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":121745,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：We introduce PHAST-Net, an attention-guided, physics-informed network for unified estimation of Ideal Time-Frequency Representations (ITFRs), spanning spectral, tempo-based, metrical, and harmonic representations such as Spectrograms, Tempograms, and Metrogra...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:16+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23653v1","title":"Lightweight Neural Framework for Robust 3D Volume and Surface Estimation from Multi-View Images","abstract":"Accurate volume and surface area estimation is critical for diverse applications, from marine ecology to medical diagnostics. However, existing methods often suffer from high computational costs and poor performance with sparse and noisy data. We propose a fully feed-forward framework that regresses scale-normalized volume and surface area and their associated uncertainties directly from multi-view images. By fusing 3D point cloud reconstructions with view-aligned 2D features through a graph-based decoder, our model bypasses iterative optimization, ensuring exceptional scalability and rapid inference. Experimental results demonstrate that our approach outperforms state-of-the-art methods, particularly when operating with a low number of input images. Validated across coral monitoring, dietary analysis, and anthropometry, our proposed framework provides a robust, adaptable solution for quantitative shape analysis. This architecture provides a high-speed, scalable alternative for precise geometric estimation from visual data, maintaining high performance even in resource-constrained or sparse-view scenarios.","authors":["Diego E. Farchione","Ramzi Idoughi","Peter Wonka"],"published":"2026-06-22T17:39:18Z","updated":"2026-06-22T17:39:18Z","abstract_url":"https://arxiv.org/abs/2606.23653v1","html_url":"https://arxiv.org/html/2606.23653v1","pdf_url":"https://arxiv.org/pdf/2606.23653v1.pdf","matched_keywords":["3d"],"source_used":"html","source_text_chars":66848,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：Accurate volume and surface area estimation is critical for diverse applications, from marine ecology to medical diagnostics. However, existing methods often suffer from high computational costs and poor performance with sparse and noisy data. We propose a fu...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:16+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23610v1","title":"Vera: A Layered Diffusion Model for Content-Preserving Video Editing","abstract":"Video diffusion models have enabled remarkable progress in video generation and editing. However, content preservation remains a core challenge: existing methods regenerate every pixel and often alter elements that should remain unchanged, such as characters or background scenes. We introduce Vera, a layered diffusion framework for content-preserving video editing. Instead of regenerating the entire video, Vera generates an edit layer along with an alpha matte for compositing with the source video, separating creative editing from content preservation by design. To encourage coherent composition with the source video, we extend the text-to-video DiT into a Mixture-of-Transformers (MoT) architecture, with separate DiTs for each layer that interact through joint self-attention. To support the training of Vera, we further construct a high-quality layered dataset with accurate alpha mattes, diverse scenes and dynamics, and visual effects. Across our quantitative benchmark and human preference study, Vera outperforms leading open-source video editing models in content preservation while remaining competitive in edit quality, using 486K frames of layered training data.","authors":["Hongkai Zheng","Ta-Ying Cheng","Benjamin Klein","Yisong Yue","Zhuoning Yuan"],"published":"2026-06-22T17:11:11Z","updated":"2026-06-22T17:11:11Z","abstract_url":"https://arxiv.org/abs/2606.23610v1","html_url":"https://arxiv.org/html/2606.23610v1","pdf_url":"https://arxiv.org/pdf/2606.23610v1.pdf","matched_keywords":["video","diffusion"],"source_used":"html","source_text_chars":87444,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, diffusion 相关；摘要显示其主要贡献为：Video diffusion models have enabled remarkable progress in video generation and editing. However, content preservation remains a core challenge: existing methods regenerate every pixel and often alter elements that should remain unchanged, such as characters...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:16+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23604v1","title":"Polycepta: Object-Centric Appearance Estimation for Multi-Object Tracking","abstract":"The tracking-by-detection paradigm in multi-object tracking (MOT) typically relies on static appearance descriptors to complement motion estimation. However, these descriptors are frame-independent, limiting their robustness as visual cues. Since such descriptors are often obtained from computationally intensive pretrained backbones, real-time MOT systems frequently abandon appearance cues altogether and rely solely on motion prediction and geometric association. In this work, we introduce Polycepta, an object-centric appearance state estimation framework that reformulates appearance modeling as a recursive estimation problem rather than a frame-wise matching task. Polycepta constructs and continuously updates an independent appearance state for each tracked object, enabling future appearance representations to be estimated from accumulated observations. Polycepta is encouraged to learn the appearance-state construction of object-specific representations rather than memorize them through a proposed learning strategy, enabling appearance estimation for unseen classes. A key property of Polycepta is that the quality of appearance estimation improves as object states evolve during inference. While conventional appearance descriptors remain static or degrade over time, Polycepta progressively refines appearance estimates as additional observations are accumulated. Extensive experiments on KITTI, the Waymo Open Dataset, and MOT17 demonstrate consistent reductions in identity switches and improvements in tracking performance when integrated into the tracking-by-detection pipelines. Polycepta operates at 90.57 Hz and delivers state-of-the-art performance on the KITTI benchmark when integrated into the RobMOT framework, achieving a MOTA of 92.27\\%.","authors":["Mohamed Nagy","Naoufel Werghi","Jorge Dias","Majid Khonji"],"published":"2026-06-22T17:06:32Z","updated":"2026-06-22T17:06:32Z","abstract_url":"https://arxiv.org/abs/2606.23604v1","html_url":"https://arxiv.org/html/2606.23604v1","pdf_url":"https://arxiv.org/pdf/2606.23604v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":83033,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：The tracking-by-detection paradigm in multi-object tracking (MOT) typically relies on static appearance descriptors to complement motion estimation. However, these descriptors are frame-independent, limiting their robustness as visual cues. Since such descrip...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:16+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23593v1","title":"Real-Time Multimodal Activity-Aware Error Detection in Robot-Assisted Surgery","abstract":"Robot-assisted minimally invasive surgery improves surgical precision but introduces complexity, making technical error detection essential for ensuring patient safety. Current executional error detection methods using video data often overlook fine-grained contextual descriptions of activities and error types within the hierarchical structure of surgical procedures. They also under-utilize complementary multimodal information. We propose a unified framework for executional error detection that leverages multimodal input, including video, kinematics, and descriptive textual prompts. Through activity prompting, we integrate descriptive language in gesture-level activities, instrument-object interactions, and error definitions. We also introduce activity-aware visual embeddings derived from vision encoders pretrained on surgical activity labels to compare the effectiveness of contrastive language-image embeddings with traditional image-based embeddings for error detection. By seamlessly integrating kinematic data with video and textual modalities, our framework significantly improves error detection performance. Achieving up to 5\\% and 16.6\\% F1 score improvements over state-of-the-art baselines on the JIGSAWS and SAR-RARP50 datasets, respectively, we demonstrate the value of combining curated textual prompts with multimodal data for accurate error detection.","authors":["Seyed Hamid Reza Roodabeh","Zongyu Li","Homa Alemzadeh"],"published":"2026-06-22T17:01:45Z","updated":"2026-06-22T17:01:45Z","abstract_url":"https://arxiv.org/abs/2606.23593v1","html_url":"https://arxiv.org/html/2606.23593v1","pdf_url":"https://arxiv.org/pdf/2606.23593v1.pdf","matched_keywords":["video","multimodal"],"source_used":"html","source_text_chars":52339,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, multimodal 相关；摘要显示其主要贡献为：Robot-assisted minimally invasive surgery improves surgical precision but introduces complexity, making technical error detection essential for ensuring patient safety. Current executional error detection methods using video data often overlook fine-grained c...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:16+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23581v1","title":"Kamera: Unified Position-Invariant Multimodal KV Cache for Training-Free Reuse","abstract":"Multimodal agents repeatedly re-examine the same video frames, UI screenshots, and rendered artifacts as their context window slides and reasoning iterates, yet every look-back re-encodes from scratch, because prefix caches serve reuse only at a fixed leading position. We show this recompute is avoidable, and identify exactly what naive KV reuse loses: the cross-chunk conditioning a chunk absorbs from its neighbours. This loss is asymmetric. The direct readout of a cached chunk is recovered exactly and for free by the standard state-merge. What remains is a diffuse, low-rank residue concentrated in deep layers, invisible to single-hop retrieval but precisely what multi-hop reasoning binds on. Blind reuse therefore leaves single-hop recall intact while halving multi-hop accuracy; this is the failure mode prior position-independent caches, designed for single-context or single-image reuse, do not address. We repair it with a small, training-free low-rank conditioning patch stored alongside each position-free chunk. Reuse reduces to one operator across MLA, GQA, and MHA: exact RoPE re-rotation to any target position, plus the patch that restores cross-chunk binding. This makes three window operations cheap: reorder (one patch serves every ordering of a cached set), sliding-window survival (surviving chunks relocate via rotation only, zero re-encode), and recall (an evicted chunk is rehydrated by its patch, never re-encoded). A rank-m patch recovers full task accuracy on cross-chunk-binding benchmarks, MM-NIAH across two attention families and two-page doc-QA, at a fraction of the KV footprint, and reconstructs re-prefill KV to within bf16 rounding in a production SGLang kernel across six backbones. The conditioning signal is strongest in redundant vision and video streams, making our solution most impactful where multimodal agents spend their recompute budget.","authors":["Bole Ma","Jan Eitzinger","Harald Koestler","Gerhard Wellein"],"published":"2026-06-22T16:47:00Z","updated":"2026-06-22T16:47:00Z","abstract_url":"https://arxiv.org/abs/2606.23581v1","html_url":"https://arxiv.org/html/2606.23581v1","pdf_url":"https://arxiv.org/pdf/2606.23581v1.pdf","matched_keywords":["video","retrieval","agent","multimodal"],"source_used":"html","source_text_chars":78723,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, retrieval, agent, multimodal 相关；摘要显示其主要贡献为：Multimodal agents repeatedly re-examine the same video frames, UI screenshots, and rendered artifacts as their context window slides and reasoning iterates, yet every look-back re-encodes from scratch, because prefix caches serve reuse only at a fixed leading...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:17+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23565v1","title":"HoloAgent-0: A Unified Embodied Agent Framework with 3D Spatial Memory","abstract":"LLM agents follow a practical execution loop in digital environments: they reason over structured states, invoke tools, inspect feedback, and revise actions. Extending this loop to physical robots is difficult because physical execution is continuous, embodiment-dependent, uncertain, and constrained by safety. Existing embodied-AI systems have advanced manipulation, spatial understanding, navigation, and humanoid control, but these capabilities often remain specialized modules or loosely coupled decision loops. In this work, we introduce HoloAgent-0, a unified embodied agent framework for real-world robot deployment. Embodied AgentOS converts language instructions into executable skill graphs, schedules robot resources, monitors execution, and triggers clarification or re-planning from runtime feedback. HoloAgent-0 organizes heterogeneous robot models and controllers through three coupled layers: Embodied AgentOS for closed-loop execution, 3D spatial memory for physical world grounding, and embodied skills for robot action. We deploy HoloAgent-0 on real hardware and evaluate its spatial memory, long-horizon navigation, and closed-loop execution across motion generation, object search, cross-robot coordination, and mobile manipulation.","authors":["Xiaolin Zhou","Liu Liu","Tingyang Xiao","Wei Feng","Fa Fu","Xinrui Meng","Xinjie Wang","Jialiang Han","Boyang Yu","Yun Du","Wei Sui","Zhizhong Su"],"published":"2026-06-22T16:31:48Z","updated":"2026-06-22T16:31:48Z","abstract_url":"https://arxiv.org/abs/2606.23565v1","html_url":"https://arxiv.org/html/2606.23565v1","pdf_url":"https://arxiv.org/pdf/2606.23565v1.pdf","matched_keywords":["3d","agent"],"source_used":"abstract","source_text_chars":1326,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, agent 相关；摘要显示其主要贡献为：LLM agents follow a practical execution loop in digital environments: they reason over structured states, invoke tools, inspect feedback, and revise actions. Extending this loop to physical robots is difficult because physical execution is continuous, embodim...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"abstract","created_at":"2026-06-23T04:56:17+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23557v1","title":"Dense Reward for Multi-View 3D Reasoning with Global Maps and Local Views","abstract":"Multi-view 3D Visual Question Answering (MV3D-VQA) requires integrating partial observations into a coherent 3D scene representation and selecting informative viewpoints for multi-step spatial reasoning. However, current multimodal LLMs are typically trained with sparse, answer-level supervision, which often yields inconsistent cross-view reasoning and brittle view selection. We present DR-MV3D (Dense Reward for MV3D-VQA), a map-grounded learning framework that provides dense, verifiable rewards to supervise the reasoning process. Our approach decomposes MV3D-VQA into (i) allocentric global map construction, (ii) question-conditioned view-trajectory planning, and (iii) egocentric grounding for answer prediction. To make intermediate steps learnable without manual annotations, we introduce two rewards: a global consistency reward that aligns the predicted map with geometry-consistent pseudo targets from frozen 3D vision foundation models (e.g., VGGT + SAM3), and a local trajectory reward that supervises ordered viewpoint selection. We optimize the full pipeline with trajectory-level policy optimization (GRPO). Experiments on MindCube, VSI-Bench, and BLINK (MV) show that DR-MV3D consistently improves over strong multi-image baselines, supporting the effectiveness of process-level dense supervision for multi-view 3D reasoning.","authors":["Jiho Choi","Seonho Lee","Seojeong Park","Hyunjung Shim"],"published":"2026-06-22T16:28:11Z","updated":"2026-06-22T16:28:11Z","abstract_url":"https://arxiv.org/abs/2606.23557v1","html_url":"https://arxiv.org/html/2606.23557v1","pdf_url":"https://arxiv.org/pdf/2606.23557v1.pdf","matched_keywords":["3d","representation","multimodal"],"source_used":"abstract","source_text_chars":1420,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, representation, multimodal 相关；摘要显示其主要贡献为：Multi-view 3D Visual Question Answering (MV3D-VQA) requires integrating partial observations into a coherent 3D scene representation and selecting informative viewpoints for multi-step spatial reasoning. However, current multimodal LLMs are typically trained...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"abstract","created_at":"2026-06-23T04:56:17+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23543v1","title":"VeriEvol: Scaling Multimodal Mathematical Reasoning via Verifiable Evol-Instruct","abstract":"Scaling reinforcement learning for visual mathematical reasoning requires more than generating harder questions: as data volume grows, the reward labels themselves must remain reliable. Yet existing data pipelines scale supervision while trusting the labeller, and policy-side methods assume the underlying answers are already correct. We instead treat scaling as a verifiable data-construction problem and decouple two axes before any policy update: prompt difficulty, expanded by route-specific evolution operators, and answer reliability, enforced by offline hypothesis-test falsification. We instantiate this as VeriEvol, an iterative framework with two extensible components: a type-aware evolution module that rewrites low-difficulty image-question seeds into harder, image-grounded prompts; and HTV-Agent, a verifier that accepts an answer only after multi-source counter-evidence has failed to refute it. The resulting verified data scales in volume, extends by adding evolution routes or verifier channels, and plugs directly into existing GRPO-style RL recipes. On a five-benchmark visual-math suite, scaling evolved SFT data from 10K to 250K samples raises the mean accuracy from 35.42 to 54.73; then, with backbone, SFT initialization, and GRPO recipe held fixed, VeriEvol adds a cumulative +3.88 over an un-evolved RL baseline, of which +1.82 comes from evolved prompts and +2.06 from the HTV-Agent verifier. We release the prompts, data, models, code, and the full verifier trace of every sample, so that downstream work can scale and audit the pipeline rather than only inspect its outputs.","authors":["Haoling Li","Kai Zheng","Jie Wu","Can Xu","Qingfeng Sun","Han Hu","Yujiu Yang"],"published":"2026-06-22T16:17:30Z","updated":"2026-06-22T16:17:30Z","abstract_url":"https://arxiv.org/abs/2606.23543v1","html_url":"https://arxiv.org/html/2606.23543v1","pdf_url":"https://arxiv.org/pdf/2606.23543v1.pdf","matched_keywords":["agent","multimodal"],"source_used":"html","source_text_chars":106479,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 agent, multimodal 相关；摘要显示其主要贡献为：Scaling reinforcement learning for visual mathematical reasoning requires more than generating harder questions: as data volume grows, the reward labels themselves must remain reliable. Yet existing data pipelines scale supervision while trusting the labeller...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:17+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23539v1","title":"LightSTAR: Efficient Visual Document Retrieval via Lightweight Selection with Vision-Adaptive Refinement","abstract":"Visual document retrieval requires rapidly locating relevant pages from large multi-modal corpora in response to user queries. While recent methods powered by Multi-modal Large Language Models (MLLMs) show competitive accuracy, they suffer from prohibitive computational costs by applying intensive MLLM encoding to every single page. Meanwhile, we observe that user queries are typically keyword-anchored, containing semantically rich words that are expected to appear directly in the visible text of relevant pages, offering an efficient cue for quickly narrowing down candidate pages. Building on this insight, we propose LightSTAR, an efficient framework that decomposes visual document retrieval into: 1) LLM-free Visual Selection, which utilizes content-grounded query encoding to focus on informative words and employs LLM-free visual embeddings to produce a high-recall candidate set; and 2) Vision-adaptive Semantic Refinement, which further performs fine-grained semantic matching exclusively on these top candidates via adaptive region-wise feature fusion to effectively combine textual and layout cues, optimized through a hardness-aware contrastive objective. Experimental results demonstrate that LightSTAR achieves state-of-the-art retrieval accuracy while reducing end-to-end latency by several-fold, offering a highly practical solution to the accuracy-efficiency trade-off in visual document retrieval. Code is available at https://github.com/bokufa/LightSTAR.","authors":["Tongkun Guan","Haocheng Wang","Wei Shen","Xiaokang Yang"],"published":"2026-06-22T16:16:24Z","updated":"2026-06-22T16:16:24Z","abstract_url":"https://arxiv.org/abs/2606.23539v1","html_url":"https://arxiv.org/html/2606.23539v1","pdf_url":"https://arxiv.org/pdf/2606.23539v1.pdf","matched_keywords":["retrieval"],"source_used":"html","source_text_chars":57900,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 retrieval 相关；摘要显示其主要贡献为：Visual document retrieval requires rapidly locating relevant pages from large multi-modal corpora in response to user queries. While recent methods powered by Multi-modal Large Language Models (MLLMs) show competitive accuracy, they suffer from prohibitive co...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:17+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23514v1","title":"Arbor: Explicit Geometric Conditioning for Controllable 3D Asset Generation","abstract":"Text and image conditioned 3D models now generate convincing assets, but they still offer little direct control over the space an object should occupy or avoid. In authoring, this spatial intent is often known before generation starts. A chair should fit a seating envelope, a prop should leave clearance for motion, or a part should expose a contact surface. Prompts and image views are poor carriers for such constraints, requiring the need for an explicit control interface. We present Arbor, a trainable attachment for text conditioned latent 3D generation. Arbor introduces constraint meshes as a native 3D control interface. The interface uses hull regions where geometry should exist, avoidance regions that should remain empty, and touch regions the object should contact. Unlike completion or whole object scaffold control, these meshes are not target evidence. They are local typed requirements and can include regions where no surface should appear. Arbor keeps this signal as geometry by converting constraint meshes into tokens and learning a routed attachment inside a frozen denoiser. Each latent region can therefore receive the part of the constraint that matters for its spatial location. We evaluate Arbor on automatic and artist curated control benchmarks with hull, avoidance, and touch constraints, and compare the metric trends to a user preference study. Even without dedicated compliance losses, Arbor improves constraint obedience while preserving object quality and variation under fixed constraints.","authors":["Jan-Niklas Dihlmann","Andreas Engelhardt","Simon Donne","Hendrik P. A. Lensch","Mark Boss"],"published":"2026-06-22T16:00:05Z","updated":"2026-06-22T16:00:05Z","abstract_url":"https://arxiv.org/abs/2606.23514v1","html_url":"https://arxiv.org/html/2606.23514v1","pdf_url":"https://arxiv.org/pdf/2606.23514v1.pdf","matched_keywords":["3d"],"source_used":"html","source_text_chars":80014,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：Text and image conditioned 3D models now generate convincing assets, but they still offer little direct control over the space an object should occupy or avoid. In authoring, this spatial intent is often known before generation starts. A chair should fit a se...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:17+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23503v1","title":"UniverSat: Resolution- and Modality-Agnostic Transformers for Earth Observation","abstract":"Vision Transformers (ViT) dominate computer vision. However, their reliance on rigid patch projectors hinders transfer to Earth Observation (EO), where input modalities, scales, and resolutions vary widely. We introduce UniverSat, a ViT-style backbone built around a Universal Patch Encoder that maps patches from arbitrary spatial, spectral, and temporal resolutions, and from both optical and non-optical sensors, into a shared embedding space with a shared set of weights. This enables training a single model on heterogeneous multimodal corpora via self-supervision, yielding robust, sensor-agnostic spatial features. We validate this approach with strong results across classification and segmentation on standard EO benchmarks from GeoBench, PANGEABench, and SpectralEarth. Our code and models are available at https://github.com/gastruc/UniverSat.","authors":["Yohann Perron","Guillaume Astruc","Nicolas Gonthier","Clement Mallet","Loic Landrieu"],"published":"2026-06-22T15:49:45Z","updated":"2026-06-22T15:49:45Z","abstract_url":"https://arxiv.org/abs/2606.23503v1","html_url":"https://arxiv.org/html/2606.23503v1","pdf_url":"https://arxiv.org/pdf/2606.23503v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":935,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：Vision Transformers (ViT) dominate computer vision. However, their reliance on rigid patch projectors hinders transfer to Earth Observation (EO), where input modalities, scales, and resolutions vary widely. We introduce UniverSat, a ViT-style backbone built a...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"abstract","created_at":"2026-06-23T04:56:17+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23494v1","title":"Brain-Adapter: A Dual-Stream Vision-Language MIL Framework for Comprehensive 3D CT Diagnosis of Acute Intracranial Pathologies","abstract":"Automated diagnosis of 3D brain CT scans is essential for critical care, yet it remains challenging due to the heavy reliance on manual annotations and the limited semantic understanding of conventional models. While 2D foundation vision-language models (VLMs) have shown remarkable generalization, effectively transferring their representational power to 3D volumes remains an open problem. In this paper, we propose Brain-Adapter, a novel dual-stream multiple instance learning (MIL) framework that leverages pre-trained 2D biomedical VLMs and raw diagnostic reports for robust scan-level multi-label classification. Specifically, we introduce a Text-Conditioned Attention (TCA) mechanism, utilizing raw diagnostic sentences as semantic queries to dynamically align visual cues with specific disease concepts. Concurrently, a parallel visual MIL stream captures global scan characteristics, supervised by structured labels extracted via a Large Language Model (LLM). To ensure representation coherence, a consistency constraint enforces synergy between the two streams. During inference, an Uncertainty-Aware Refinement (UAR) module dynamically calibrates and fuses these dual-stream predictions to resolve ambiguous cases. Extensive experiments demonstrate that our method significantly outperforms state-of-the-art 3D models and standard MIL approaches. By eliminating the reliance on dense annotations, Brain-Adapter provides a highly scalable and clinically viable solution for 3D acute intracranial pathology analysis.","authors":["Zhenyu Yi","Zhiyun Song","Yusong Sun","Zelin Liu","Manman Fei","Zhenhao Li","Jiaxuan Zhao","Xu Han","Lichi Zhang"],"published":"2026-06-22T15:41:16Z","updated":"2026-06-22T15:41:16Z","abstract_url":"https://arxiv.org/abs/2606.23494v1","html_url":"https://arxiv.org/html/2606.23494v1","pdf_url":"https://arxiv.org/pdf/2606.23494v1.pdf","matched_keywords":["3d","representation","instance"],"source_used":"html","source_text_chars":30625,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, representation, instance 相关；摘要显示其主要贡献为：Automated diagnosis of 3D brain CT scans is essential for critical care, yet it remains challenging due to the heavy reliance on manual annotations and the limited semantic understanding of conventional models. While 2D foundation vision-language models (VLMs...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:18+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23489v1","title":"MeshFlow: Mesh Generation with Equivariant Flow Matching","abstract":"Meshes are among the most common 3D scene representations, but directly generating meshes is challenging because the representation contains important symmetries, including permutation invariance of faces and vertices. MeshFlow learns to generate triangle meshes directly as triangle soups, avoiding the need to serialize meshes into long autoregressive sequences. We adopt equivariant optimal-transport flow matching models that respect the key symmetries of triangle soups: arbitrary permutations of faces and permutations of the vertices within each face. Toward this goal, we propose a simple yet effective modification to the Diffusion Transformer architecture, resulting in a scalable network capable of modeling a velocity field while maintaining the desired equivariance. We further introduce an optimal-transport-based training objective that improves convergence by eliminating supervision signals that violate these symmetries. MeshFlow achieves mesh quality comparable to state-of-the-art autoregressive mesh generators while providing about an 18$\\times$ speedup during inference. Project page is at https://qiisun.github.io/MeshFlow/.","authors":["Qi Sun","Kiyohiro Nakayama","Jing Nathan Yan","Qixing Huang","Alexander Rush","Leonidas Guibas","Gordon Wetzstein","Jing Liao","Guandao Yang"],"published":"2026-06-22T15:35:30Z","updated":"2026-06-22T15:35:30Z","abstract_url":"https://arxiv.org/abs/2606.23489v1","html_url":"https://arxiv.org/html/2606.23489v1","pdf_url":"https://arxiv.org/pdf/2606.23489v1.pdf","matched_keywords":["3d","representation","diffusion"],"source_used":"html","source_text_chars":103648,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, representation, diffusion 相关；摘要显示其主要贡献为：Meshes are among the most common 3D scene representations, but directly generating meshes is challenging because the representation contains important symmetries, including permutation invariance of faces and vertices. MeshFlow learns to generate triangle mes...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:18+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23473v1","title":"C^2GR: Coupled Comprehensive Generative Replay for a Continually Learnable Universal Segmentation Model","abstract":"Universal segmentation models exhibit significant potential for diverse tasks involving different imaging modalities and segmentation objectives. Task-Incremental Learning provides a privacy-preserving approach to continually evolve a universal model on tasks from sequentially-arriving medical departments. However, training the model solely on the incoming task induces forgetting on past tasks, since consecutive tasks exhibit concurrent shifts in image appearance and segmentation objective. To address this problem, we propose a novel Coupled Comprehensive Generative Replay (C^2GR) framework that simultaneously synthesizes image-mask pairs of previous tasks to mitigate forgetting under concurrent appearance and objective shifts. This requires preserving image-mask correspondence for structure-realistic generation and bridging asynchronous optimization of the generator and segmentor for segmentation-oriented generation. Specifically, we propose a Bayesian Joint Diffusion (BJD) method that formulates the correspondence as conditional distributions optimized via conditional denoising. Furthermore, we develop a Relation-aware Unified Prompt Synchronization (RUPS) scheme to simultaneously modulate the generator and segmentor via a shared task-relation-aware prompt for synchronizing their optimization. Experiments on 20 tasks spanning diverse modalities and objectives demonstrate that C^2GR exhibits only a 2.44% drop in overall performance compared to joint training with all task data, effectively alleviating forgetting from the concurrent shifts. Our code will be made publicly available at https://github.com/mar-cry/C2GR.","authors":["Wei Li","Jingyang Zhang","Guoan Wang","Junzhi Ning","Yang Chen","Guang Yang","Lixu Gu"],"published":"2026-06-22T15:19:03Z","updated":"2026-06-22T15:19:03Z","abstract_url":"https://arxiv.org/abs/2606.23473v1","html_url":"https://arxiv.org/html/2606.23473v1","pdf_url":"https://arxiv.org/pdf/2606.23473v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23455v1","title":"MeGAS: Thermomechanical Dynamic Gaussian Splatting for Thermophysical Scene Editing","abstract":"Recent advances integrate physically grounded Newtonian dynamics with neural rendering frameworks, narrowing the gap between photorealistic scene reconstruction and physics-based animation. However, existing approaches focus on mechanically driven dynamics while neglecting temperature, a fundamental yet invisible physical factor underlying phenomena such as melting, solidification, and other thermomechanical processes. In this paper, we propose MeGAS, a novel framework that incorporates thermomechanical phase-change dynamics into 3D Gaussian Splatting (3DGS). Specifically, we propose a new thermomechanical dynamic Gaussian Splatting representation that augments 3DGS with temperature attributes and employs a heat advection-diffusion solver with MPM dynamics incorporating phase transitions, enabling physically plausible and visually realistic synthesis of thermophysical phenomena. Furthermore, a new topology-adaptive Gaussian rendering strategy is proposed to mitigate cracking and floaters under extreme deformation. Extensive experiments demonstrate that MeGAS produces physically consistent thermomechanical behavior while maintaining high-fidelity photorealistic rendering, advancing toward physics-integrated world models.","authors":["Zesong Yang","Yuanhang Lei","Liyuan Cui","Yihang Chen","Jiaer Huang","Boming Zhao","Peter Yichen Chen","Hujun Bao","Zhaopeng Cui"],"published":"2026-06-22T15:05:59Z","updated":"2026-06-22T15:05:59Z","abstract_url":"https://arxiv.org/abs/2606.23455v1","html_url":"https://arxiv.org/html/2606.23455v1","pdf_url":"https://arxiv.org/pdf/2606.23455v1.pdf","matched_keywords":["3d","representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23436v1","title":"Rethinking Object-Centric Representations for Video Dynamics Modeling","abstract":"Unsupervised video object tracking aims to decompose dynamic scenes into persistent, object-centric entities without manual annotations. Many recent approaches rely on slot-based representations, where a fixed set of latent variables (\"slots\") represent individual objects across frames. To preserve object identity, these models enforce temporal consistency on slot embeddings. However, when appearance and pose are entangled, this consistency objective conflicts with object motion and viewpoint changes. As a result, slots tend to lock onto static regions (e.g., background) to satisfy the consistency objective, while foreground objects become fragmented across multiple slots or frequently swap identities. To address these limitations, we propose STAITUS, a unified framework that explicitly disentangles each slot into appearance and geometric pose (position/scale). Leveraging this disentanglement, STAITUS enforces within-frame spatial separation and applies temporal alignment only in appearance space, yielding sharper masks and more persistent identities under motion, occlusion, and object entry/exit. Furthermore, to mitigate over-segmentation, we introduce an adaptive gating mechanism that dynamically adjusts the number of active slots to match scene complexity. Extensive experiments on synthetic and real-world benchmarks demonstrate that STAITUS substantially outperforms state-of-the-art baselines in segmentation quality and tracking stability.","authors":["Amaury Wei","Ismail Nejjar","Olga Fink"],"published":"2026-06-22T14:55:41Z","updated":"2026-06-22T14:55:41Z","abstract_url":"https://arxiv.org/abs/2606.23436v1","html_url":"https://arxiv.org/html/2606.23436v1","pdf_url":"https://arxiv.org/pdf/2606.23436v1.pdf","matched_keywords":["video","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23373v1","title":"Polynomial Dice Loss for Medical Image Segmentation","abstract":"Medical image segmentation is a fundamental task for medical image processing and computer-assisted intervention, yet data imbalance and small lesion detection pose significant challenges. Dice Loss, which measures the overlap between predicted and ground truth regions, is widely used to mitigate these issues. To further emphasize its properties, we propose Polynomial Dice Loss, a polynomial extension of Dice Loss. Specifically, by leveraging the geometric characteristics of Dice Loss and formulating the loss function as a polynomial representation via Taylor expansion, we enable the adjustment of the contribution of higher-order components to the loss function. In our experiments, we evaluate the proposed method against loss functions derived from conventional Dice and Tversky coefficients. Experimental results and further analysis show that the polynomial formulation provides a simple way to control the loss shape and achieves competitive performance across multiple segmentation settings.","authors":["Hiroaki Aizawa"],"published":"2026-06-22T14:07:33Z","updated":"2026-06-22T14:07:33Z","abstract_url":"https://arxiv.org/abs/2606.23373v1","html_url":"https://arxiv.org/html/2606.23373v1","pdf_url":"https://arxiv.org/pdf/2606.23373v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23362v1","title":"TooBad: Backdoor Diffusion Models with Ultra-Low Poison Rate and Imperceptible Trigger","abstract":"Diffusion models (DMs), despite their impressive capabilities across a wide range of generative tasks, have been shown to be vulnerable to backdoor attacks. However, existing backdoor methods face critical trade-offs among key factors: attack performance, stealthiness, time complexity, and required poison rates. For example, achieving high attack performance typically demands a high poison rate and prolonged training, which undermines stealthiness, making the attack more detectable by backdoor defenses. This paper proposes TooBad (trigger optimization for backdoor diffusion models), a backdoor framework which introduces a novel DM-tailored trigger optimization technique to dramatically enhance the performance of backdoor attacks on DMs. Experiments on representative benchmarks such as CIFAR-10 show that TooBad can achieve high ASRs ($> 85$%) at only 0.5% poison rate, significantly lower than the 10% typically required by prior work on the same datasets. At 5% poison rate, TooBad reaches nearly 100% ASR within just 3-5 backdoor injection epochs, whereas existing methods need at least 30-50 epochs at double the poison rate for comparable results. Despite its potency, TooBad easily evades SOTA defenses and maintains high utility. These results reveal a critical threat on DMs and highlight the need for more robust defenses against such stealthy yet efficient attacks.","authors":["Vu Tuan Truong","Long Bao Le"],"published":"2026-06-22T14:00:06Z","updated":"2026-06-22T14:00:06Z","abstract_url":"https://arxiv.org/abs/2606.23362v1","html_url":"https://arxiv.org/html/2606.23362v1","pdf_url":"https://arxiv.org/pdf/2606.23362v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23356v1","title":"Changing Modalities: Adapting Remote Sensing Models to New Satellites and Sensors","abstract":"Machine learning models for remote sensing are trained and deployed on a static set of modalities. However, as we equip newer satellites with novel sensors and retire old ones, practitioners may wish to deploy an existing model on a substitution, superset, or subset of modalities with minimal retraining given data availability or practical computational constraints. We study the setting of updating existing models to changing modalities and identify three main scenarios: Modality Transfer (substitution), Addition (superset), and Peeking (subset). We propose DeluluNet, an architecture with modular components for all three changing modality scenarios. DeluluNet is trained end-to-end, learning a multi-modal model from a unimodal teacher and unlabeled multimodal data via modality hallucination--predicting missing modality representations from those that are present. As a result, DeluluNet can keep predicting even when input modalities change, providing a practical alternative to re-labeling and re-training in a changing world.","authors":["Tim G. Zhou","Anthony Fuller","Geoff Pleiss","Evan Shelhamer"],"published":"2026-06-22T13:56:12Z","updated":"2026-06-22T13:56:12Z","abstract_url":"https://arxiv.org/abs/2606.23356v1","html_url":"https://arxiv.org/html/2606.23356v1","pdf_url":"https://arxiv.org/pdf/2606.23356v1.pdf","matched_keywords":["representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23354v1","title":"Faithful Grounded Visual Reasoning via Learned Proxy-Tokens","abstract":"Multimodal Large Language Models (MLLMs) have achieved remarkable success in Visual Question Answering (VQA), yet their \"black-box\" nature hinders deployment in critical domains. Grounded Visual Reasoning (GVR) approaches attempt to improve interpretability by explicitly couple textual rationales with visual grounding information, which are typically textual coordinates. This mechanism lacks a learnable semantic link to the visual features, often resulting in a semantic-spatial gap where the model hallucinates coordinates that do not correspond to image evidences. In this work, we introduce Composer, a MLLM that leverages a novel visual grounding mechanism based on learned proxy-tokens to promote faithful interpretability. These discrete symbolic pointers explicitly index the image latent space, allowing the model to manipulate visual regions as addressable, semantically manipulable sets. To rigorously validate our novel grounding mechanism, we constructed ComposerGCoT, a dataset synthesized to enable holistic assessment of reasoning consistency and grounding accuracy. Experimental results indicate that Composer achieves performance parity with its coordinate-based counterpart in final answer accuracy, while improving visual grounding accuracy by +9.0 points. By demonstrating that discrete proxy-tokens capture spatial semantics more effectively than typical textual coordinates, we establish that visual grounding mechanisms with learnable semantic links represent a promising path toward trustworthy and reliable MLLMs.","authors":["Tom Hodemon","Mohamed Chaouch","Aboubacar Tuo","Angelique Loesch"],"published":"2026-06-22T13:54:48Z","updated":"2026-06-22T13:54:48Z","abstract_url":"https://arxiv.org/abs/2606.23354v1","html_url":"https://arxiv.org/html/2606.23354v1","pdf_url":"https://arxiv.org/pdf/2606.23354v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23344v1","title":"RT-DocLayout: Real-Time End-to-End Document Layout Analysis with Reading Order in the Wild","abstract":"Accurate document layout analysis remains a critical bottleneck for document parsing systems, due to the intricate coupling among heterogeneous document layout elements, geometric distortions (\\eg, paper warping and bending, perspective variations), and reading order within diverse layout structures. Existing approaches typically rely on fragmented multi-stage pipelines or computationally heavy generative Transformer architectures, leading to error propagation and limited efficiency. In this paper, we present RT-DocLayout, a highly efficient end-to-end framework for document layout analysis, designed as a front-end for document parsing tasks. The proposed model unifies classification, detection, pixel-level segmentation, and reading order prediction for layout elements within a single 33M-parameter architecture. Built upon the RT-DETR, our key contribution is a unified multi-task formulation within a single query-based decoder that simultaneously classifies, regresses bounding box, generates masks, and constructs relationship to reason reading order. By jointly learning geometric and structural representations, RT-DocLayout introduces multi-task optimization that substantially improves robustness under real-world document distortions. Extensive experiments on public benchmarks demonstrate state-of-the-art performance in document layout analysis while maintaining real-time inference speed(132.1 FPS). When coupled with downstream OCR engines, RT-DocLayout significantly improves full-document reconstruction quality, providing a scalable and practical foundation for real-world document intelligence systems.","authors":["Cheng Cui","Tingquan Gao","Xueqing Wang","Changda Zhou","Hongen Liu","Ting Sun","Yubo Zhang","Zelun Zhang","Jiaxuan Liu","Manhui Lin","Yue Zhang","Suyin Liang","Yiqing Xiang","Yi Liu"],"published":"2026-06-22T13:48:39Z","updated":"2026-06-22T13:48:39Z","abstract_url":"https://arxiv.org/abs/2606.23344v1","html_url":"https://arxiv.org/html/2606.23344v1","pdf_url":"https://arxiv.org/pdf/2606.23344v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23327v1","title":"VideoAgent: All-in-One Framework for Video Understanding and Editing","abstract":"Video editing has become essential in digital media creation, yet existing automated systems are restricted to short segment processing and domain-specific tasks. They face two critical limitations: i) inability to handle diverse video comprehension and editing operations, and ii) lack of long-video understanding for coherent narrative creation. We propose VideoAgent, an all-in-one agentic framework addressing these challenges through two key innovations. First, we develop automated video shot creation with shot planning agents for coherent narratives and cross-modal retrieval for aligned visual content. Second, we design a multi-agent orchestration framework integrating over thirty specialized editing agents. Intent parsing filters relevant tools while textual-gradient graph optimization assembles complex editing pipelines. Extensive experiments on our newly-proposed VideoEdit benchmark and public datasets demonstrate VideoAgent's superiority over existing multimodal LLMs and agentic systems. VideoAgent achieves 87-95% orchestration success rates while reducing API costs by 60%. Human evaluation across six video categories shows VideoAgent produces professional-quality content approaching human-level performance, with ratings only 4% below human-created videos. We release our code at https://github.com/HKUDS/VideoAgent.","authors":["Hengji Zhou","Lingxuan Huang","Jian Wang","Bing Zhou","Si Wu","Lianghao Xia","Chao Huang"],"published":"2026-06-22T13:37:08Z","updated":"2026-06-22T13:37:08Z","abstract_url":"https://arxiv.org/abs/2606.23327v1","html_url":"https://arxiv.org/html/2606.23327v1","pdf_url":"https://arxiv.org/pdf/2606.23327v1.pdf","matched_keywords":["video","retrieval","agent","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23298v1","title":"Ocean4D: Generative Underwater 4D Reconstruction via Medium-Aware Video Diffusion","abstract":"Underwater 4D reconstruction remains challenging due to the coupling between degraded light transport in participating media and dynamic water variations. Most existing Methods are developed under in-air assumptions and do not explicitly account for underwater absorption and backscatter. Additionally, near-static assumptions make these approaches sensitive to drifting particles and dynamic distractors , leading to unstable geometry and inconsistent cross-view results. To address these issues, we propose a generative framework for underwater 4D reconstruction, named Ocean4D, which is built on two complementary components. Specifically, 4D-GCC constructs 4D geometrically consistent conditioning with improved cross-frame coverage, while the Medium-Aware Block performs implicit medium-aware denoising in the latent diffusion process to stabilize underwater appearance under absorption and scattering. Given a monocular video and target cameras, our method generates videos along the target trajectories while preserving global structure and cross-view consistency. Extensive experiments on both dynamic and static underwater benchmarks demonstrate state-of-the-art performance on underwater reconstruction.","authors":["Yuqiang Huang","Yuxi Wang","Junyu Dong","Zhaoxiang Zhang"],"published":"2026-06-22T13:10:26Z","updated":"2026-06-22T13:10:26Z","abstract_url":"https://arxiv.org/abs/2606.23298v1","html_url":"https://arxiv.org/html/2606.23298v1","pdf_url":"https://arxiv.org/pdf/2606.23298v1.pdf","matched_keywords":["video","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23270v1","title":"BoxCtrl: 3D-Aware Visual Prompting for Geometric Image Editing","abstract":"As instruction-based editing models and multimodal large language models advance, diverse image editing tasks have become feasible. However, achieving precise and consistent geometric image editing, such as translating, scaling, and rotating in 3D space, remains a major challenge. In this work, we introduce BoxCtrl, a 3D-aware visual prompting framework. Unlike text-only or coarse 2D-guided approaches, our method introduces informative RGB 3D bounding boxes projected onto 2D images as visual prompts. The three orthogonal faces of each box are painted with distinct RGB colors, simultaneously encoding position, size, and orientation to provide a compact, intuitive in-context visual example. The key to BoxCtrl's success lies in these well-designed bounding boxes, which decouple geometric control from appearance control. This enables the model to learn consistent correspondences between faces of the same color in the latent space, leading to a precise understanding of geometric intentions and accurate editing results. We introduce a two-stage training paradigm: Supervised Fine-Tuning (SFT) followed by Reinforcement Learning (RL). To address paired data scarcity, we construct a large-scale synthetic dataset for SFT, equipping the model with fundamental editing capabilities. To bridge the synthetic-to-real domain gap, we incorporate an online RL stage leveraging unpaired real-world data. Guided by a reward function evaluating geometric accuracy and visual fidelity, our SFT-RL strategy significantly enhances geometric precision while maintaining photorealistic quality. Extensive experiments demonstrate that BoxCtrl achieves state-of-the-art performance across translation, rotation, scaling, and composite editing tasks.","authors":["Feifei Wang","Shiyuan Yang","Xiaoyu Li","Jing Liao"],"published":"2026-06-22T12:49:29Z","updated":"2026-06-22T12:49:29Z","abstract_url":"https://arxiv.org/abs/2606.23270v1","html_url":"https://arxiv.org/html/2606.23270v1","pdf_url":"https://arxiv.org/pdf/2606.23270v1.pdf","matched_keywords":["3d","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23267v1","title":"Safe Few-Step Generation via Velocity Editing","abstract":"Flow matching has recently emerged as a strong paradigm for state-of-the-art text-to-image (T2I) generation, enabling high-quality generation with a small number of sampling steps. As these models are increasingly integrated into real-world applications, ensuring safe and non-sensitive content generation has become a critical requirement. However, adapting safety and concept removal methods to this new generation framework remains an open challenge. Specifically, prior methods largely rely on iterative trajectory steering across a number of denoising steps or on CLIP-centric prompt embedding manipulation. These design assumptions pose fundamental bottlenecks for safety in flow matching-based T2I generation, where limited sampling steps constrain iterative correction and modern context-aware text encoders diminish the effectiveness of embedding-level interventions. In this paper, we propose VESFlow, a training-free safety method tailored to flow matching with extremely few sampling steps. Leveraging the fact that flow matching models learn the marginal velocity, we directly edit the velocity field via a safe-conditional posterior. VESFlow steers the trajectory toward safe outputs while leaving the conditioning prompt unchanged. Building on the observation that VESFlow leaves outputs unchanged under benign prompts, we further introduce a risk score-based filtering that bypasses velocity editing to reduce computational cost while preserving benign prompt generation. Based on this filtering, we propose VESFlow+, a stronger variant of VESFlow that not only edits the velocity toward the safe direction, but also pushes it away from the unsafe direction. Experimental results show that VESFlow+ removes the target concept, reducing the attack success rate by NudeNet to 6.3% on Ring-A-Bell and 6.8% on MMA-Diffusion on the 4-step MeanFlow model, while preserving fidelity on benign prompts.","authors":["Yujin Choi","Jaehong Yoon"],"published":"2026-06-22T12:47:57Z","updated":"2026-06-22T12:47:57Z","abstract_url":"https://arxiv.org/abs/2606.23267v1","html_url":"https://arxiv.org/html/2606.23267v1","pdf_url":"https://arxiv.org/pdf/2606.23267v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23256v1","title":"P-JEPA: Procedural Video Representation Learning via Joint Embedding Predictive Architecture","abstract":"The increasing maturity of embodied AI platforms has driven a growing interest in procedural video representation learning to support intelligent assistance systems for complex, multi-step tasks. Leveraging large-scale latent predictive training, video foundation models capture video dynamics, enabling downstream tasks such as activity understanding, spatiotemporal localization, and predictive control. However, procedural videos include actions with long-range dependencies that these models do not support, due to the quadratic complexity of self-attention. Distinct actions, for example, may be visually similar despite appearing at different points in the procedure, such as turning the stove on versus off. Here, we propose a backbone-agnostic approach that learns long-duration video representations by reducing the problem to a dense, frame-aligned action space and predicting pooled masked latent vectors. This approach allows our Procedural Joint Embedding Predictive Architecture (P-JEPA) to ingest videos over 30 minutes long, enabling effective long-form understanding of procedural steps. We evaluate P-JEPA using features extracted with VJEPA2.1, TSM, and I3D over the EgoExo4D, EgoProceL, and Assembly101 datasets, finding that it consistently improves linear separability, streaming inference, and temporal action segmentation performance, achieving state-of-the-art results on EgoExo4D fine-grained action classification while using an order of magnitude fewer parameters than LLM-based methods and running in real time.","authors":["Felix Tristram","Stefano Gasperini","Benjamin Killeen","Marcel Walch","Christian Benz","Nassir Navab","Ghazal Ghazaei"],"published":"2026-06-22T12:38:36Z","updated":"2026-06-22T12:38:36Z","abstract_url":"https://arxiv.org/abs/2606.23256v1","html_url":"https://arxiv.org/html/2606.23256v1","pdf_url":"https://arxiv.org/pdf/2606.23256v1.pdf","matched_keywords":["video","3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23254v1","title":"SteerVTE: Seamless Video Text Editing with Style and Glyph Control","abstract":"Visual text editing aims to precisely modify text in images and videos while preserving stylistic consistency and visual realism. Despite significant advances in the image domain, video text editing remains largely unexplored: it is a localized task demanding stroke-level precision within small text regions, which compounds the challenges of cross-frame accuracy, temporal coherence, and stylistic fidelity. We introduce SteerVTE, a unified framework that \\underline{\\textbf{steer}}s a frozen video diffusion model to perform precise \\underline{\\textbf{V}}ideo \\underline{\\textbf{T}}ext \\underline{\\textbf{E}}diting through style and glyph control. Built on a frozen diffusion transformer, SteerVTE attaches a lightweight text context adapter with two complementary modules: a style encoder capturing the original text's visual attributes, and dual-granularity glyph encoders encoding the target text at both the line and character levels. To overcome the inherently weak text rendering priors of video foundation models, we further propose a glyph-aware spatial-focal loss and a three-stage progressive training curriculum that scales from image to video data. To support large-scale training, we also develop an automatic synthesis pipeline and construct SteerVTE-1M, a dataset of one million triplets spanning diverse scenes, fonts, and stylistic effects. Extensive experiments demonstrate that SteerVTE substantially outperforms existing video editing baselines across text accuracy, style consistency, and temporal coherence.","authors":["Kai Zeng","Moran Li","Zhengwei Wang","Yingchen Yu","Yiheng Lin","Ruichuan An","Ming Lu","Qi She","Wentao Zhang"],"published":"2026-06-22T12:37:15Z","updated":"2026-06-22T12:37:15Z","abstract_url":"https://arxiv.org/abs/2606.23254v1","html_url":"https://arxiv.org/html/2606.23254v1","pdf_url":"https://arxiv.org/pdf/2606.23254v1.pdf","matched_keywords":["video","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23226v1","title":"PhysFlow: Frequency Decoupled with Dual-Field Rectified Flow for Remote Photoplethysmography","abstract":"Remote Photoplethysmography (rPPG) enables contactless pulse estimation from facial videos, serving as a vital tool for health monitoring. However, current deep learning methods often struggle under complex disturbances, particularly varying illumination, facial expressions, and unconstrained head movements. In such scenarios, subtle physiological signals are easily dominated by external interference, making the recovered rPPG waveform unstable and unreliable. One important reason is that most existing methods directly model the rPPG signal in a unified manner, where different signal components are coupled during reconstruction. This makes it difficult to preserve weak pulse-related variations when strong disturbance-induced changes are present. To address this challenge, we propose PhysFlow, a frequency-decoupled dual-field rectified flow framework tailored for robust rPPG estimation. Specifically, the ground-truth rPPG signal is decomposed into trend and amplitude components, which are used as separate supervisory targets. Based on the extracted facial features, PhysFlow learns two component-specific conditional velocity fields to model the two components separately. This design reduces mutual interference between different components and improves the robustness of rPPG reconstruction under complex disturbances. Moreover, the rectified flow formulation enables efficient waveform reconstruction with only a few ordinary differential equation (ODE) integration steps. Extensive experiments on multiple benchmark datasets demonstrate that PhysFlow outperforms state-of-the-art methods in both heart-rate estimation and rPPG waveform reconstruction across diverse challenging scenarios.","authors":["Zixu Li","jianjun Qian","Hang Shao","Lei Luo","Jian Yang"],"published":"2026-06-22T12:14:37Z","updated":"2026-06-22T12:14:37Z","abstract_url":"https://arxiv.org/abs/2606.23226v1","html_url":"https://arxiv.org/html/2606.23226v1","pdf_url":"https://arxiv.org/pdf/2606.23226v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23221v1","title":"RS-Gen: A Multi-Stage Agentic Framework for Reasoning and Search-Augmented Image Generation","abstract":"Recent years have witnessed remarkable progress in image generation and editing, particularly regarding instruction following and visual fidelity. However, when handling ambiguous intentions, logical reasoning, and Out-of-Distribution (OOD) knowledge, existing image models often yield sub-optimal results due to a lack of deep reasoning capabilities and real-time external information. Although emerging unified understanding-and-generation models attempt to bridge this gap, they remain constrained by their intrinsic parameter scales and static knowledge gaps. Inspired by agentic paradigms, we propose RS-Gen: a plug-and-play, training-free, multi-stage image agentic framework. RS-Gen innovatively introduces a \"Questioning-and-Solving\" closed-loop mechanism to accurately identify logical issues and knowledge gaps, autonomously planning actions to bridge information deficits and execute deep logical reasoning. Extensive experiments demonstrate that RS-Gen significantly expands the capability boundaries of foundational image generation and editing models. Specifically, on the WISE Verified and RISEBench benchmarks, RS-Gen yields substantial absolute performance gains of 0.313 for Qwen-Image and 19.70 for Qwen-Image-Edit-2511, respectively, successfully elevating both to the state-of-the-art (SOTA) level among open-source models.","authors":["Feifei Bian","Zhimin Zheng","Wei Deng","Daiguo Zhou","Jian Luan"],"published":"2026-06-22T12:09:29Z","updated":"2026-06-22T12:09:29Z","abstract_url":"https://arxiv.org/abs/2606.23221v1","html_url":"https://arxiv.org/html/2606.23221v1","pdf_url":"https://arxiv.org/pdf/2606.23221v1.pdf","matched_keywords":["agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23129v1","title":"Spectral Gating via Damped Oscillations for Adaptive Implicit Neural Representations","abstract":"Implicit Neural Representations (INRs) have been proven successful in encoding continuous signals through coordinate-based networks, yet facing a spectral dilemma: periodic activations capture fine details but act as all-pass filters that memorise noise, while spatially compact activations regularise effectively but suffer from low-frequency bias. Existing attempts to resolve this trade-off introduce computational overhead or tuning frailty. We propose to model each neuron's activation as the steady-state response of a sinusoidally-forced damped harmonic oscillator, whose amplitude naturally governs the network's spectral selectivity during training. By jointly optimising the oscillator parameters alongside the network weights, our method adapts to the target signal's spectral content without explicit regularisation. Initialised in the stopband, the network exhibits a coarse-to-fine learning curriculum that progressively expands its spectral gate, capturing low-frequency structures first and high-frequency details only when justified by the reconstruction objective. Comprehensive experiments show that our approach consistently achieves state-of-the-art or competitive results against established INRs, while requiring no task-specific tuning of any hyperparameters.","authors":["Alex Costanzino","Pierluigi Zama Ramirez","Giuseppe Lisanti","Luigi Di Stefano"],"published":"2026-06-22T11:59:47Z","updated":"2026-06-22T11:59:47Z","abstract_url":"https://arxiv.org/abs/2606.23129v1","html_url":"https://arxiv.org/html/2606.23129v1","pdf_url":"https://arxiv.org/pdf/2606.23129v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23212v1","title":"Temporally Aware Densification for Dynamic 3D Gaussian Splatting","abstract":"Despite modeling temporal motion, dynamic 3D Gaussian Splatting (3DGS) methods still inherit a static densification strategy that is ill-suited for dynamic scenes. This neglect of temporal behavior leads to under-reconstructed and blurry dynamic regions, as short-lived Gaussians receive sparse supervision and fail to densify effectively. We propose a Visibility-Aware Densification (VAD) framework that integrates temporal visibility into the densification process, ensuring that Gaussians are refined based on their actual temporal presence. A Temporally-Adaptive Thresholding (TAT) mechanism further adjusts each Gaussian's densification threshold according to its temporal lifespan, promoting balanced refinement of both static and dynamic regions. Finally, a Temporal Offset Warping (TOW) design enhances deformation capacity around temporal centers, extending the lifespan of highly dynamic Gaussians and facilitating more effective densification. Our approach achieves substantial improvements in the visual quality of dynamic regions, outperforming existing methods across three dynamic multi-view benchmark datasets. Moreover, the proposed VAD module generalizes across diverse dynamic 3DGS methods, consistently improving dynamic reconstruction as a plug-and-play component.","authors":["Vikram Sandu","Mayurdeep Pathak","Rajiv Soundararajan"],"published":"2026-06-22T11:55:21Z","updated":"2026-06-22T11:55:21Z","abstract_url":"https://arxiv.org/abs/2606.23212v1","html_url":"https://arxiv.org/html/2606.23212v1","pdf_url":"https://arxiv.org/pdf/2606.23212v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23206v1","title":"CFPO: Counterfactual Policy Optimization for Multimodal Reasoning","abstract":"Large Vision-Language Models (LVLMs) have demonstrated remarkable capabilities in multimodal reasoning. However, prevailing reinforcement learning (RL) paradigms lack explicit counterfactual enhancement and causal learning mechanisms. This fundamental deficiency results in severe grounding failures, manifesting as a tendency to ignore visual evidence in favor of language priors or exhibiting hallucination drift during long chain-of-thought reasoning. To address this root cause, we propose CounterFactual Policy Optimization (CFPO), a novel framework that enforces causal consistency between visual perception and textual reasoning. CFPO introduces a cross-modal counterfactual enhancement mechanism, which regularizes the policy by maximizing the discrepancy between the model's predictions and those from a counterfactual state where critical visual cues are suppressed. This approach seamlessly integrates with standard algorithms like GRPO and DAPO without requiring external reward models or additional supervision. Extensive experiments demonstrate that CFPO significantly improves reasoning fidelity, achieving consistent gains of 3.17%-6.25% over standard RL baselines and 1.32%-2.13% over the state-of-the-art perception-aware method (PAPO). Code is available at https://github.com/Raven-July/CFPO.","authors":["Zhangyuan Yu","Wanran Sun","Guangjing Yang","Xiaohu Wu","Qicheng Lao"],"published":"2026-06-22T11:51:51Z","updated":"2026-06-22T11:51:51Z","abstract_url":"https://arxiv.org/abs/2606.23206v1","html_url":"https://arxiv.org/html/2606.23206v1","pdf_url":"https://arxiv.org/pdf/2606.23206v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23204v1","title":"Unmasking LAION-5B: Age, Gender, Race, and Emotion Biases in Large-Scale Image Datasets","abstract":"Large-scale image-text datasets, such as LAION-5B, are foundational to modern AI systems, yet their vast scale and uncurated nature raise significant concerns about demographic and stereotypical biases. This study presents a comprehensive analysis of the demographic composition and representational, stereotypical, and intersectional biases in LAION-2B-en and LAION-2B-multi, the two main components of the LAION-5B dataset. Using state-of-the-art models -- FairFace, DeepFace, and Emo-AffectNet -- we analyze faces detected in the dataset to identify biases across age, gender, race, and expressed emotion. Our findings reveal substantial overrepresentation of young adults (20--39), White individuals, and males, alongside consistent underrepresentation of minority racial groups and middle-aged or older women across both dataset components. We also observe stereotypical associations between demographic attributes and emotions, such as ``Anger'' being predominantly linked to males and ``Happiness'' to females, pointing to systemic imbalances in the data. The consistency of these patterns across two demographic models and both components of LAION-5B demonstrates that these biases are deeply embedded in one of the most widely-used training datasets. Given the scale at which LAION-5B is used to train generative models, these demographic imbalances could shape the behavior and outputs of numerous downstream AI systems.","authors":["Iris Dominguez-Catena","Daniel Paternain","Mikel Galar"],"published":"2026-06-22T11:49:23Z","updated":"2026-06-22T11:49:23Z","abstract_url":"https://arxiv.org/abs/2606.23204v1","html_url":"https://arxiv.org/html/2606.23204v1","pdf_url":"https://arxiv.org/pdf/2606.23204v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23200v1","title":"NGPS: Structure-Preserving Self-Supervised Denoising via Neighbor-Guided Patch Sampling","abstract":"Neighboring-slice self-supervised denoising is attractive for volumetric medical imaging, yet inter-slice misalignment breaks anatomical correspondence and often yields ghosting and blurred margins when adjacent slices are used naively as targets. We propose Neighbor-Guided Patch Sampling (NGPS), a lightweight framework that constructs neighboring supervision under local inter-slice misalignment without explicit registration. To avoid learning from misleading targets, prior methods commonly mask discrepant regions, but this stabilizes training at the cost of leaving a non-trivial portion of neighboring evidence unexploited, particularly around high-frequency anatomical boundaries. NGPS addresses this by decoupling structure matching from signal retrieval: for each masked location, it searches a local neighborhood for structurally similar candidate patches using a simple guide image (e.g., fast bilateral filtering), while retrieving the supervision signal directly from the raw noisy neighbor at the matched coordinates. By matching on a noise-attenuated guide while retrieving raw values from neighboring slices, NGPS constructs local pseudo targets without a learned registration module. Across the evaluated CT and synthetic-Rician MRI settings, NGPS improves fidelity and structure-sensitive metrics. Code is available at https://github.com/cv-cho/NGPS .","authors":["Jaehyun Cho","YoungJoon Yoo"],"published":"2026-06-22T11:46:34Z","updated":"2026-06-22T11:46:34Z","abstract_url":"https://arxiv.org/abs/2606.23200v1","html_url":"https://arxiv.org/html/2606.23200v1","pdf_url":"https://arxiv.org/pdf/2606.23200v1.pdf","matched_keywords":["retrieval"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23186v1","title":"StreamPPG: Low-Latency rPPG Estimation via Consistent Privileged Learning","abstract":"Remote photoplethysmography (rPPG) estimates the blood volume pulse (BVP) signal from facial videos, enabling contact-free health monitoring. Conventional clip-wise approaches, which use video clips as input, require capturing over one hundred frames before inference, thus introducing several seconds of delay and hindering real-time use. Meanwhile, frame-wise approaches struggle to capture long-range temporal and periodic features of physiological rhythms, and therefore lead to reduced estimation accuracy. To overcome these issues, we propose StreamPPG, a unified architecture that enables low-latency frame-wise physiological signal estimation while achieving competitive accuracy compared with clip-wise approaches. StreamPPG is trained under a consistent privileged learning (CPL) strategy, which leverages ground-truth rPPG signals as privileged information to enhance the model's representation capability. Extensive experiments demonstrate that StreamPPG achieves state-of-the-art accuracy across multiple datasets while maintaining real-time throughput on edge devices.","authors":["Yiming Li","Yihan Yang","Yuguang Chu","Yuanhui Hu","Si-Yuan Cao","Xiaohan Zhang","Xiaokai Bai","Zhe Wu","Hui-Liang Shen"],"published":"2026-06-22T11:31:01Z","updated":"2026-06-22T11:31:01Z","abstract_url":"https://arxiv.org/abs/2606.23186v1","html_url":"https://arxiv.org/html/2606.23186v1","pdf_url":"https://arxiv.org/pdf/2606.23186v1.pdf","matched_keywords":["video","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23132v1","title":"T-VSS: Test-Time Visual Subspace Steering for Adversarial Robustness of Vision-Language Models","abstract":"Vision-language models (VLMs) achieve strong zero-shot recognition, but they remain highly vulnerable to adversarial perturbations. Recent test-time adaptations improve robustness without retraining, but they do not directly adapt the corrupted visual representation itself. Prompt-based methods adapt the learnable text prompts, while input-space methods optimize pixels or padding at test time. These approaches can improve predictions, but they do so through an indirect and expensive optimization path. We propose Test-time Visual Subspace Steering (T-VSS), a lightweight defense that performs test-time adaptation directly in the visual feature space. T-VSS first builds a sample-specific low-rank subspace from multi-view feature residuals anchored at the attacked image. It then learns a shared feature correction within this subspace using reliability-weighted entropy minimization. By constraining adaptation to a compact visual geometry, T-VSS steers attacked features toward more stable and discriminative predictions while avoiding noisy full-space updates. Experiments on fine-grained, ImageNet, and ImageNet-OOD benchmarks show that T-VSS improves adversarial robustness while maintaining competitive clean accuracy and better efficiency than prior test-time adaptations.","authors":["Jaehyuk Jang","Minseok Seo. Seungju Cho","Kangwook Ko","Changick Kim"],"published":"2026-06-22T10:21:24Z","updated":"2026-06-22T10:21:24Z","abstract_url":"https://arxiv.org/abs/2606.23132v1","html_url":"https://arxiv.org/html/2606.23132v1","pdf_url":"https://arxiv.org/pdf/2606.23132v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23126v1","title":"MambaADv2: Evolving Duality-enhanced State Space Model for Unsupervised Anomaly Detection","abstract":"While recent advancements in anomaly detection have demonstrated the efficacy of CNN- and Transformer-based approaches, these architectures face inherent limitations: CNNs struggle to capture long-range dependencies, whereas Transformers suffer from quadratic computational complexity. Consequently, Mamba-based architectures have attracted considerable attention, as they successfully combine superior long-range dependency modeling with linear computational complexity. By critically rethinking the structural evolution across the Mamba lineage 1-3 series, this paper proposes MambaADv2, a framework tailored for multi-class unsupervised anomaly detection. MambaADv2 comprises a pre-trained encoder and a Mamba-inspired decoder, equipped with Duality-enhanced State Space (DSS) modules across multiple scales. The proposed DSS module effectively models both global dependencies and local representations by integrating parallel-cascaded Hybrid State Space (HSS) blocks and frequency-enhanced convolution operations. The structure of the Hybrid State Space (HSS) block is tailored by following the SSD-based Mamba lineage and incorporating Mamba3-style position-aware state-space modeling, leveraging the dual computational paths of linear recurrence and parallel matrix formulation to model local continuity and global contextual comparison, thereby better serving the core anomaly detection objective of precisely reconstructing normal representations while magnifying anomalous deviations. Additionally, we propose a semantics-adaptive progressive scanning strategy that decays scanning complexity along the feature pyramid.","authors":["Xiaobin Hu","Haoyang He","Bo Yin","Yu He","Lei Xie","Jiangning Zhang","Yu-Gang Jiang","Shuicheng Yan"],"published":"2026-06-22T10:14:06Z","updated":"2026-06-22T10:14:06Z","abstract_url":"https://arxiv.org/abs/2606.23126v1","html_url":"https://arxiv.org/html/2606.23126v1","pdf_url":"https://arxiv.org/pdf/2606.23126v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23118v1","title":"LUMINA-26: Low-Light Understanding for Modeling and Interpreting Night-time Actions","abstract":"Low-light human action recognition remains a challenging problem due to poor illumination, amplified noise, motion ambiguity, and diverse real-world scenes. Existing low-light datasets often lack sufficient action diversity, capture realism, or balanced class distribution, limiting the development of robust models. To address this, we introduce LUMINA-26: Low-Light Understanding for Modeling and Interpreting Night-time Actions, comprising 6,784 clips across 26 action classes, recorded from 22 subjects across 20 indoor and outdoor locations under naturally occurring low-light conditions. We also propose Illumi-Net: An Illumination-Adaptive Mixture-of-Experts Network, which leverages video-level illumination cues to guide adaptive enhancement and transformer-based spatio-temporal feature extraction, with expert-conditioned decision fusion. Our method surpasses previous state-of-the-art performance on ELLAR (Top-1: 55.13%, Top-5: 78.87%) and establishes a strong baseline on LUMINA-26 (Top-1: 75.95%, Top-5: 93.58%), offering a practical benchmark for future low-light action recognition research.","authors":["Aman Kumar Pandey","Anil Singh Parihar"],"published":"2026-06-22T10:03:37Z","updated":"2026-06-22T10:03:37Z","abstract_url":"https://arxiv.org/abs/2606.23118v1","html_url":"https://arxiv.org/html/2606.23118v1","pdf_url":"https://arxiv.org/pdf/2606.23118v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23105v1","title":"Compression and Retrieval: Implicit Memory Retrieval for Video World Models","abstract":"Video world models hold promise for simulating interactive environments, yet maintaining consistent long-term memory across complex camera trajectories remains a critical challenge. Existing methods typically rely on computationally expensive context scaling or rigid heuristic retrieval mechanisms, which lacks generalization to varying camera trajectories and environments. In this paper, we propose Compression and Retrieval (CaR), an attention-driven implicit memory retrieval mechanism to overcome these limitations. By injecting viewpoint information via positional encoding, our method performs flexible memory retrieval through attention computation. To efficiently process extended contexts with minimal computational overhead, we further introduce a lightweight context compression network. Furthermore, we construct SceneFly, a large-scale synthetic dataset featuring realistic camera trajectories and frame-level annotations to train and evaluate long-horizon video world models. Extensive experiments demonstrate that our approach achieves state-of-the-art results on established benchmarks and exhibits strong generalization to open-domain scenes.","authors":["Zhan Peng","Jie Ma","Huiqiang Sun","Chong Gao","Zhijie Xue","Zhiyu Pan","Zhiguo Cao","Jun Liang","Jing Li"],"published":"2026-06-22T09:46:36Z","updated":"2026-06-22T09:46:36Z","abstract_url":"https://arxiv.org/abs/2606.23105v1","html_url":"https://arxiv.org/html/2606.23105v1","pdf_url":"https://arxiv.org/pdf/2606.23105v1.pdf","matched_keywords":["video","retrieval"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23069v1","title":"Rethinking Prototype-based Similarity Learning for Few-Shot Object Detection","abstract":"Few-shot object detection aims to detect novel object categories from only a few labeled examples, avoiding costly large-scale annotation. Recent prototype-based similarity learning approaches enable training-free adaptation by matching query features with class prototypes. However, they suffer from two fundamental limitations: (i) class confusion arising from inter-class similarity margin collapse, and (ii) insufficient visual cues for precise localization, as similarity scores capture only class-level semantic affinity while providing limited spatial information. To address these issues, we introduce two complementary components. Text-Anchored Semantic Mask (TSMa) leverages class-level text features as semantic anchors to identify semantically aligned channels through channel-wise interaction between visual and text features. By suppressing style-induced spurious responses and emphasizing class-intrinsic signals, TSMa enlarges inter-class similarity margins and mitigates class confusion. We further propose Stage-Aligned Hierarchical Autoregressive Regression (SHARe), which reformulates localization as a hierarchical autoregressive process that progressively refines bounding boxes across multiple stages. SHARe leverages the layer-wise characteristics of ViT representations by aligning feature abstraction levels with regression stages: deeper layers guide early coarse localization, while shallower layers rich in edge and texture cues refine spatial details in later stages. Experiments on COCO demonstrate a new state of the art, outperforming the previous best by +10.1 nAP, with extensive analysis validating each component. The code is available at https://github.com/VisualScienceLab-KHU/ReSet.","authors":["KunHo Heo","Seungjae kim","Wongyu Lee","SuYeon Kim","MyeongAh Cho"],"published":"2026-06-22T09:18:00Z","updated":"2026-06-22T09:18:00Z","abstract_url":"https://arxiv.org/abs/2606.23069v1","html_url":"https://arxiv.org/html/2606.23069v1","pdf_url":"https://arxiv.org/pdf/2606.23069v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23063v1","title":"Attention-Spectrum Regularization for Replay-Free Continual Multimodal LLMs","abstract":"Multimodal large language models (MLLMs) are increasingly required to adapt to non-stationary streams of visual domains, question types, and user instructions, yet continual fine-tuning often causes severe forgetting of previously acquired multimodal skills. Existing continual vision-language methods mainly preserve outputs, replay data or pseudo-data, regularize embedding geometry, or allocate task-specific parameters, but they provide limited control over how internal cross-modal attention patterns supporting old skills drift during adaptation. We propose Attention-Spectrum Regularization (ASR), a replay-free continual learning framework that preserves skill-conditioned structures of cross-modal attention. ASR treats cross-attention maps as two-dimensional signals, summarizes their scale and directional properties into compact spectral statistics, and stores only skill-wise prototype distributions instead of replaying past image-question pairs, generated pseudo-examples, or old-stage teacher snapshots. In later stages, a phase-invariant spectral regularizer constrains harmful drift of these prototypes while allowing instance-level attention to adapt to new tasks. We provide theoretical analysis showing that skill-conditioned spectral drift controls forgetting under a spectral sufficiency assumption, and that Fourier power spectra are stable to spatial translations and bounded perturbations. Experiments on continual VQA and multimodal instruction-tuning benchmarks, including VQA v2, VQACL, CLT-VQA, CoIN, and UCIT, show that ASR consistently improves final performance and reduces forgetting over strong replay-, regularization-, and adapter-based baselines. Preserving skill-level attention structure is an effective and lightweight mechanism for continual MLLMs. Code is available at https://github.com/Creative-zcx/attention-spectrum-replay","authors":["Chuangxin Zhao","Canran Xiao","Siyuan Ma","Mengyao Lyu","Yanbiao Ma","Jun Xia","Guiguang Ding","Yang Liu"],"published":"2026-06-22T09:13:53Z","updated":"2026-06-22T09:13:53Z","abstract_url":"https://arxiv.org/abs/2606.23063v1","html_url":"https://arxiv.org/html/2606.23063v1","pdf_url":"https://arxiv.org/pdf/2606.23063v1.pdf","matched_keywords":["instance","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23062v1","title":"VolHuMe: a High-Resolution Large Scale Dataset of Volumetric Human Meshes","abstract":"We introduce VolHuMe, a dataset of high-quality 4D human scans captured with a state-of-the-art volumetric studio using 64 RGB and 32 depth cameras. VolHuMe contains individual captures of 104 subjects and provides extensive ground truth, including SMPL-X, high-resolution meshes, multi-view RGB/depth images, rigged meshes, point clouds, garment segmentation, and detailed hand and facial geometry. Unlike prior datasets that primarily rely on full-body imagery, VolHuMe uses a close-range, high-resolution capture setup that preserves fine-grained body-part details, improving geometric fidelity and texture resolution. We benchmark VolHuMe on state-of-the-art methods across 3D and 4D human reconstruction tasks, showcasing the dataset's quality and exposing the limitations of current evaluation testbeds.","authors":["Giulia Martinelli","Niccolò Bisagno","Nicola Garau","Esa Rahtu","Nicola Conci"],"published":"2026-06-22T09:13:52Z","updated":"2026-06-22T09:13:52Z","abstract_url":"https://arxiv.org/abs/2606.23062v1","html_url":"https://arxiv.org/html/2606.23062v1","pdf_url":"https://arxiv.org/pdf/2606.23062v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23061v1","title":"MotionHalluc: Diagnosing Kinematic Hallucinations in Fine-Grained Motion Reasoning","abstract":"Motion instruction generation in cross-video comparison aims to produce corrective feedback that describes the differences between a query and a reference motion. However, existing models often generate instructions that exhibit motion hallucinations, failing to reflect actual kinematic differences between paired videos. To systematically investigate these hallucinations, we introduce MotionHalluc, a dedicated benchmark for evaluating motion hallucinations in paired-video comparison. MotionHalluc comprises 1540 fine-grained questions over 553 video pairs, evaluating hallucinations along three core dimensions: (1)directional hallucination, (2)attributional hallucination, and (3)temporal hallucination. Extensive evaluations of state-of-the-art large multimodal models demonstrate high susceptibility to these hallucinations. Furthermore, we provide Perceive-Parse-Verify (PPV) as a training-free measurements extraction and verification baseline that converts candidate instructions into executable measurement queries and supplies kinematic measurements at inference time. Our results show that this simple measurements injection yields an average 10.6% performance gain across models, suggesting that motion reasoning with explicit quantitative measurements is a key factor in reducing hallucinations in cross-video comparison. Our code and dataset will be made publicly available upon acceptance.","authors":["Weile Guo","Shenghong He","Danying Mo","Chengdong Xu","Xuexun Liu","Chao Yu"],"published":"2026-06-22T09:13:19Z","updated":"2026-06-22T09:13:19Z","abstract_url":"https://arxiv.org/abs/2606.23061v1","html_url":"https://arxiv.org/html/2606.23061v1","pdf_url":"https://arxiv.org/pdf/2606.23061v1.pdf","matched_keywords":["video","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23058v1","title":"Three-Step Hierarchical Transformer for Multi-Pedestrian Trajectory Prediction","abstract":"Pedestrian trajectory prediction requires modeling temporal dynamics, multimodal cues, and social interactions in crowded environments. Existing methods often address these factors separately or entangle them in costly attention blocks, limiting scalability, flexibility, and interpretability. We propose a three-step hierarchical Transformer that explicitly separates temporal encoding, multimodal fusion, and scene-level interaction reasoning. Lightweight GRU summaries enable efficient cross-modal attention, while social attention over time--agent tokens captures inter-pedestrian influences at manageable cost. Experiments on JTA, JRDB, and the Pedestrians and Cyclists in Road Traffic dataset show state-of-the-art performance on real-world datasets (JRDB, Urban) and competitive results on JTA. Ablation and qualitative analyses confirm the contribution of each stage and the model's ability to anticipate complex behaviors such as early turning.","authors":["Raphaël Delécluse","Hazem Wannous","Laurent Grisoni","Laurent Guimas"],"published":"2026-06-22T09:11:20Z","updated":"2026-06-22T09:11:20Z","abstract_url":"https://arxiv.org/abs/2606.23058v1","html_url":"https://arxiv.org/html/2606.23058v1","pdf_url":"https://arxiv.org/pdf/2606.23058v1.pdf","matched_keywords":["agent","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23046v1","title":"UECP: Uncertainty-Enhanced Collaborative Perception","abstract":"Collaborative perception serves as a pivotal solution to enhance the perception capability of individual agents in autonomous driving, where a core challenge lies in seeking reliable evidence to quantify and weight the contribution of each participating agent. Existing methods typically rely on a confidence map, which is co-trained with the detection head, but it is inherently correlated with the detection results and thus fails to provide unbiased physical evidence. Furthermore, how to deeply integrate evidence into the cooperative fusion process remains an open question. To address these issues, this paper first proposes an uncertainty map, a physically grounded and unambiguous metric for evaluating perception quality. This map is directly supervised by real-time sensor signals, i.e., LiDAR point density, ensuring decoupling from detection noise and thereby providing physical scenario-aware evidence for weighting agent contribution. Based on this map, we develop the Uncertainty-Enhanced Collaborative Perception (UECP) framework, centered on the Uncertainty-Aware Pyramid Fusion (UAPF) module. UAPF uses a coarse-to-fine strategy, with two key components: Uncertainty-Weighted Downsampling (UWD) for high-fidelity feature preservation, and Uncertainty-Guided Residual Fusion (UGRF) to reinforce ego features, suppressing noise and ensuring robust fusion. Extensive experiments on real-world datasets show UECP outperforms state-of-the-art methods in effectiveness and robustness by embedding the uncertainty map into fusion. Code will be publicly available.","authors":["Kang Yang","Tianci Bu","Peng Wang","Deying Li","Wen Jie","Yongcai Wang"],"published":"2026-06-22T08:55:10Z","updated":"2026-06-22T08:55:10Z","abstract_url":"https://arxiv.org/abs/2606.23046v1","html_url":"https://arxiv.org/html/2606.23046v1","pdf_url":"https://arxiv.org/pdf/2606.23046v1.pdf","matched_keywords":["agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23041v1","title":"SPAR: Semantic-Pixel Self-Alignment and Adaptive Routing for Unified Multimodal Models","abstract":"Multimodal Large Language Models (MLLMs) have achieved remarkable success in visual understanding but remain constrained in visual generation due to the fundamental feature discrepancy between semantic perception and pixel-level reconstruction. Bridging this gap requires overcoming two core challenges: endowing semantic encoders with high-fidelity reconstruction capabilities, and effectively aligning generative models with semantic spaces without relying on external teachers. To this end, we propose a novel unified multimodal framework featuring \\textbf{S}emantic-\\textbf{P}ixel self-alignment and \\textbf{A}daptive \\textbf{R}outing (\\textbf{SPAR}). First, to reconcile semantic perception with pixel-level reconstruction, we introduce an asymmetric dual-stream unified tokenizer. A lightweight semantic stream anchors discriminative features, while a Transformer-augmented pixel stream recovers fine-grained visual details into a unified compact latent space. Second, to eliminate external dependencies, we propose a self-aligned generation paradigm that natively leverages this optimized tokenizer as an internal alignment teacher for the diffusion model. Furthermore, to facilitate flexible multimodal interaction within this unified space, we introduce Dynamic Token Routing, which enables each token to adaptively aggregate multi-layer MLLM features based on its distinct semantic demands. Extensive experiments demonstrate that SPAR establishes the state-of-the-art for unified architectures, achieving exceptional generation and reconstruction quality while preserving foundational visual understanding capabilities.","authors":["Hongxiang Li","Hongxu Chen","Chenyang Zhu","Xiaoshuang Huang","Jiayin Cai","Xiaolong Jiang","Yao Hu","Long Chen"],"published":"2026-06-22T08:48:19Z","updated":"2026-06-22T08:48:19Z","abstract_url":"https://arxiv.org/abs/2606.23041v1","html_url":"https://arxiv.org/html/2606.23041v1","pdf_url":"https://arxiv.org/pdf/2606.23041v1.pdf","matched_keywords":["multimodal","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23031v1","title":"DrivingVoxels: Compositional Sparse Voxel Rasterization for Dynamic Driving Scene Reconstruction","abstract":"Reconstructing dynamic urban scenes remains challenging due to the unbounded nature of driving environments and the presence of multiple dynamic objects. Currently, potentially faster sparse voxel methods are mainly designed for static scenarios. On the other hand, dynamic approaches based on 3D Gaussian Splatting, despite their high-fidelity, are often time-consuming for driving scenarios and exhibit uncontrollable memory growth in large scenes. To address these limitations, we present DrivingVoxels, a compositional sparse voxel rendering framework for dynamic driving scenes. Our method jointly rasterizes sparse voxels from multiple independent octrees within a single rendering pass. Each rigid dynamic object is represented by an octree defined in its local coordinate frame, while a separate static octree models the stationary background. DrivingVoxels adopts a fully explicit, neural-free representation together with a LiDAR-guided structural initialization that efficiently captures scene geometry. We evaluate our framework on the PandaSet benchmark, demonstrating that DrivingVoxels performs on par on perceptual metrics and better on structural metrics for NVS and reconstruction while requiring shorter training times than previous 3DGS-base methods to an efficient optimization workflow anchored by a strong LiDAR prior.","authors":["Tania Aguirre","Luis Roldão","Moussab Bennehar","Nathan Piasco","Dzmitry Tsishkou","Simone Rossi","Pietro Michiardi"],"published":"2026-06-22T08:42:16Z","updated":"2026-06-22T08:42:16Z","abstract_url":"https://arxiv.org/abs/2606.23031v1","html_url":"https://arxiv.org/html/2606.23031v1","pdf_url":"https://arxiv.org/pdf/2606.23031v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23027v1","title":"Learning Stable Canonical Worlds for Novel View Synthesis and Beyond","abstract":"Feed-forward Gaussian splatting (FFGS) facilitates real-time novel view synthesis, yet current methods often remain tied to view-dependent predictions. As more input views are added, they may accumulate noisy or redundant evidence instead of converging to a stable scene representation. In this paper, we introduce CanonicalGS, a feed-forward pipeline that maps cluttered multi-view observations into a stable, scene-centric representation. CanonicalGS first extracts view-centric evidence from depth, semantic features, and uncertainty estimates, and then aggregates this evidence in a canonical latent world using uncertainty-aware fusion. By emphasizing reliable observations while suppressing uncertain or redundant ones, CanonicalGS produces representations that scale more effectively for novel view synthesis and transfer to downstream visual perception tasks. Experiments show up to a $2.5$ dB improvement in peak signal-to-noise ratio for synthesizing novel views and an $11\\%$ gain in semantic segmentation accuracy.","authors":["Xiaoyu Xu","Jian Zou","Sheyang Tang","Zhihua Wang","Jing Liao","Kede Ma"],"published":"2026-06-22T08:38:39Z","updated":"2026-06-22T08:38:39Z","abstract_url":"https://arxiv.org/abs/2606.23027v1","html_url":"https://arxiv.org/html/2606.23027v1","pdf_url":"https://arxiv.org/pdf/2606.23027v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23023v1","title":"Boosting Neural Video Codec via Scale-Driven Online Flow Refinement","abstract":"Although state-of-the-art neural video codecs (NVCs) have achieved remarkable performance, they suffer from limited generalization when encountering complex motion patterns unseen during training. To bridge this domain gap without the expensive cost of online fine-tuning, we propose a Training-Free Scale-Driven Online Flow Refinement (SOFR) method. Serving as a plug-and-play module, SOFR integrates motion information from coarse and fine scales and dynamically fuses them according to warping accuracy, effectively rectifying motion estimation errors with negligible computational overhead. Furthermore, we design a rate-aware strategy that selects different dynamic fusion strategies according to bitrate modes, and employs a reliability check based on warping error to ensure robustness. Extensive experiments on the USTC-TD dataset verify the effectiveness and generalization of SOFR across various NVC frameworks, including DCVC-SDD, DCVC-FM, and EHVC. Notably, it brings an average of 2.84% and 4.05% bitrate savings in terms of PSNR and MS-SSIM, respectively, to DCVC-FM with negligible coding time increase. Our code is available at https://github.com/SunnyMass/SOFR.","authors":["Tiange Zhang","Rongqun Lin","Haocheng Tang","Xiandong Meng","Weijia Jiang","Zhimeng Huang","Siwei Ma"],"published":"2026-06-22T08:36:23Z","updated":"2026-06-22T08:36:23Z","abstract_url":"https://arxiv.org/abs/2606.23023v1","html_url":"https://arxiv.org/html/2606.23023v1","pdf_url":"https://arxiv.org/pdf/2606.23023v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23019v1","title":"ScalingAttention: Discovering Intrinsic Sparse Attention Topology for Video Diffusion Transformers","abstract":"While Diffusion Transformers (DiTs) have revolutionized high-fidelity video generation, their reliance on 3D full attention creates a quadratic computational bottleneck. Existing sparse methods face a dilemma: dynamic pruning suffers from prohibitive runtime overhead and memory fragmentation, while static heuristics fail to capture fine-grained dependencies. In this work, we propose ScalingAttention, a training-free framework grounded in a key inductive bias: while individual activations are input-dependent, the high-mass attention regions for each head rapidly converge to a stable, prompt-agnostic Intrinsic Sparse Topology. This topology is weight-encoded, scale-invariant, and efficient to extract. ScalingAttention decouples topology discovery from sparsity control via: (1) WEST (Weight-Encoded Sparse Topology), which extracts a robust block-sparse prior mask offline to eliminate runtime search; (2) FAST (Fidelity-Aware Sensitivity Tuning), which adaptively tunes head-wise sparsity based on diffusion fidelity requirements. To ensure practical acceleration, we co-design a hardware-aligned bit-wise block-sparse kernel. Experiments on Wan2.1 show up to 1.90X end-to-end speedup with superior fidelity, establishing a new Pareto frontier over state-of-the-art baselines.","authors":["Ruiliang Zhou","Xuecheng Wu","Kang He","Guangyun Han","Bin Liu","Qinqin Chen","Wende Xu","Qingjie Zhao","Chengru Song"],"published":"2026-06-22T08:32:07Z","updated":"2026-06-22T08:32:07Z","abstract_url":"https://arxiv.org/abs/2606.23019v1","html_url":"https://arxiv.org/html/2606.23019v1","pdf_url":"https://arxiv.org/pdf/2606.23019v1.pdf","matched_keywords":["video","3d","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23005v1","title":"From Point Estimates to Distributions: GMM Pooling for MIL in Preterm Birth Prediction","abstract":"Preterm birth (PTB) prediction can enable targeted surveillance and timely intervention, yet most ultrasound-based models use a single selected transvaginal ultrasound (TVUS) frame per patient despite routine exams acquiring multiple cervical images. We formulate PTB prediction as a multiple instance learning (MIL) problem, representing each patient as a variable-sized bag of TVUS images with a single outcome label. To move beyond standard MIL aggregators that collapse a bag into a point estimate, we propose a Gaussian Mixture Model (GMM) pooling, which summarizes all images in a bag into a fixed-length representation by modeling their feature distribution. This design captures intra-patient variability. We evaluate the method on a private clinical cohort and on a public lymph node metastasis benchmark. For PTB prediction, GMM pooling improves over the instance-based model PR-AUC from 0.44 to 0.56. On the lymph node benchmark, it achieves state-of-the-art performance with 0.91 F1-score and 0.89 ROC-AUC for classification and 0.18 MAE for regression. The code is publicly available at https://github.com/HussainAlasmawi/GMM_Pooling.","authors":["Hussain Alasmawi","Numan Saeed","Soha Said","Mohammad Yaqub"],"published":"2026-06-22T08:18:08Z","updated":"2026-06-22T08:18:08Z","abstract_url":"https://arxiv.org/abs/2606.23005v1","html_url":"https://arxiv.org/html/2606.23005v1","pdf_url":"https://arxiv.org/pdf/2606.23005v1.pdf","matched_keywords":["representation","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22999v1","title":"Black-Box Continual Learning for Vision-Language Models","abstract":"The rapid deployment of Vision-Language Models (VLMs) in dynamic environments necessitates the ability to learn continuously without forgetting. However, traditional continual learning (CL) settings often rely on white-box paradigms, which is increasingly invalidated by the shift toward cloud-hosted models. In this paper, we introduce Black-CL, a more realistic benchmark for VLMs that enforces three primary real-world challenges: weight and architecture inaccessibility, constrained computation, and task-agnostic inference. The learner can query only output embeddings or logits, with no gradient flow through or structural modification of the backbone. Current CL methodologies, which rely on backbone backpropagation or complex parameter expansion, are fundamentally incompatible with these constraints. Under this setting, we propose BETA, a simple yet effective baseline built on the key insight that solely optimizing textual prototypes can navigate the complexities of CL. BETA integrates three core components: Semantic Projection Accumulation (SPA) for incremental knowledge acquisition, Latent Distribution Replay (LDR) for anchoring the embedding space against catastrophic forgetting, and Test-Time Prototype Adaptation (TTPA) for dynamic, instance-aware boundary refinement. Extensive experiments across ten diverse datasets and various backbones demonstrate that BETA significantly outperforms existing black-box tuners. Remarkably, with only 0.05 M trainable parameters, a 180--3000$\\times$ reduction compared to competitive methods, BETA achieves performance on par with or even exceeding white-box CL methods. We believe Black-CL and BETA provide a foundational framework for future advancements in continual learning and accelerates the transition of continual learning from academia to real-world systems.","authors":["Yuting Li","Weihang Fang","Haoyuan Gao","Linghe Kong","Yexin Li","Lichao Sun","Weiran Huang"],"published":"2026-06-22T08:14:55Z","updated":"2026-06-22T08:14:55Z","abstract_url":"https://arxiv.org/abs/2606.22999v1","html_url":"https://arxiv.org/html/2606.22999v1","pdf_url":"https://arxiv.org/pdf/2606.22999v1.pdf","matched_keywords":["instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22987v1","title":"Can Single-View Mesh Reconstruction Generalize to Robot Camera Rotation?","abstract":"Single-view mesh reconstruction predicts object meshes and spatial layouts from a single observation, making it attractive for fast robot spatial reasoning and real-to-sim digital twins. However, robot-mounted cameras naturally rotate during manipulation and navigation, while learned single-view reconstruction models often rely on view-dependent priors and may generalize poorly to out-of-distribution camera rotations. Such rotations can introduce 3D inconsistencies, incorrect layouts, and violations of physical constraints, but this failure mode remains under-evaluated. We introduce an evaluation protocol with controlled axis-wise roll, pitch, and yaw sweeps to trace errors in monocular depth estimation (MDE), canonical object meshes, camera-space layout, and physical plausibility within a representative SAM3D-style pipeline. On the Aria Digital Twin dataset and a real Franka wrist-camera sequence, camera rotations induce MDE distortion, layout drift, and collision penetration, while canonical mesh predictions remain relatively stable. A two-stage SAM3D+FoundationPose pipeline is more robust than one-stage feed-forward layout prediction, and our Gravity-Aware Refinement reduces one-stage pairwise ICP-based layout-orientation error by 47.1$\\%$. Our evaluation reveals that current single-view mesh reconstruction methods generalize poorly to robot camera rotation, and suggests that explicit gravity cues are important for reliable robotic single-view mesh reconstruction.","authors":["Yu Zhan","Guangcheng Chen","Hanjing Ye","Zhiqin Cheng","Zanjia Tong","Wenjun Xu","Hong Zhang"],"published":"2026-06-22T08:05:45Z","updated":"2026-06-22T08:05:45Z","abstract_url":"https://arxiv.org/abs/2606.22987v1","html_url":"https://arxiv.org/html/2606.22987v1","pdf_url":"https://arxiv.org/pdf/2606.22987v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22986v1","title":"Subject-Level Unknown-Identity Identification from Leap Motion Controller 2 Hand Landmarks","abstract":"This work studies subject recognition from Leap Motion Controller 2 (LMC2) hand landmark data under a subject-level unknown-identity identification protocol on the Multi View Leap2 Hand Pose (ML2HP) dataset. Using only the landmark modality, we retain the original geometric representation and enrich it with fingertip-to-palm distances and palm-normalized inter-finger angular descriptors. Evaluation is performed under a Leave-One-Subject-Out (LOSO) protocol in which, for each outer fold, one subject is excluded from the enrolled set and treated as unknown at test time. To avoid tuning on the true outer unknown subject, the unknown-rejection threshold is selected in an inner validation step by temporarily withholding one enrolled subject from the inner gallery and using it only for threshold estimation. We compare a tree ensemble baseline with two neural alternatives: a learned embedding baseline based on centroid matching and cosine-similarity-based rejection, and an MLP+OpenMax model, which represents a more established open-set recognition approach. Under this evaluation setup, Extra Trees remains the strongest overall method, indicating that the main challenge on this benchmark is not enrolled-subject discrimination alone, but robust score separation between known and unknown probes. The results support the feasibility of compact, interpretable landmark-based descriptors for contactless hand-based unknown-subject rejection and identification on a small-cohort dataset.","authors":["Bahar Moharrer","Susanna Cifani","Marco Raoul Marini","Luigi Cinque","Maria De Marsico"],"published":"2026-06-22T08:05:27Z","updated":"2026-06-22T08:05:27Z","abstract_url":"https://arxiv.org/abs/2606.22986v1","html_url":"https://arxiv.org/html/2606.22986v1","pdf_url":"https://arxiv.org/pdf/2606.22986v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22971v1","title":"Humanoid-OmniOcc: Stereo-Based Full-View Occupancy Dataset for Embodied AI","abstract":"Occupancy prediction at voxel-level granularity is essential for safe robotic navigation and interaction in complex environments. Existing occupancy datasets, however, are predominantly designed for autonomous driving with vehicle-centric biases -- forward-facing cameras, far-field geometry, and static road priors -- limiting their applicability to embodied humanoid perception. We present Humanoid-OmniOcc, a large-scale panoramic stereo-based occupancy dataset tailored for humanoid robots. The dataset encompasses 15 diverse simulated indoor scenes and 5 real-world environments, yielding over 155K samples with broad scene and style diversity. Importantly, the dataset is designed around a Real2Sim2Real closed-loop paradigm: real sensor specifications drive physically accurate simulation, simulation produces large-scale annotated training data, and models trained in simulation are directly evaluated on real-world captures -- enabling iterative refinement of the sim-to-real pipeline. We further propose \\textbf{H}umanoid \\textbf{S}urround \\textbf{S}tereo-guided \\textbf{Occ}upancy model (Humanoid-OmniOcc) that exploits robust depth priors for accurate 2D-to-3D lifting. Extensive experiments show that Humanoid-OmniOcc consistently outperforms monocular baselines and generalizes well to both unseen simulated test scenes and real-world environments, validating the effectiveness of the Real2Sim2Real design. Code and data will be available upon acceptance at https://d-robotics-ai-lab.github.io/humanoid-omniocc.","authors":["Xianda Guo","Bohao Zhang","Chenwei Huang","Shiyuan Chen","Ruilin Wang","Yiqun Duan","Cong Yang","Qin Zou","Wei Sui"],"published":"2026-06-22T07:52:25Z","updated":"2026-06-22T07:52:25Z","abstract_url":"https://arxiv.org/abs/2606.22971v1","html_url":"https://arxiv.org/html/2606.22971v1","pdf_url":"https://arxiv.org/pdf/2606.22971v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22959v1","title":"The Impact of VAE Design on Latent Pose Representations for Diffusion-based Sign Language Production","abstract":"Latent diffusion approaches to sign language production (SLP) rely on an initial stage that learns an encoding of sign pose sequences, enabling generative modeling in the resulting latent space. The autoencoder used in this stage is typically evaluated in terms of reconstruction quality using geometric metrics common in SLP. While informative, these metrics do not fully capture latent space properties that may influence the training and performance of the downstream generative model. In this work, we investigate how architectural and training objective design choices in a variational autoencoder (VAE) for sign pose encoding affect latent space structure, and how these differences translate into the performance of a latent diffusion model for text-to-sign generation. Our experiments on Phoenix14T dataset show that variations in generative performance, measured through back-translation BLEU scores, can sometimes be better explained by differences in latent space properties than by VAE reconstruction accuracy alone.","authors":["Guilhem Fauré","Mostafa Sadeghi","Sam Bigeard","Slim Ouni"],"published":"2026-06-22T07:38:55Z","updated":"2026-06-22T07:38:55Z","abstract_url":"https://arxiv.org/abs/2606.22959v1","html_url":"https://arxiv.org/html/2606.22959v1","pdf_url":"https://arxiv.org/pdf/2606.22959v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22958v1","title":"PG-MAP: Joint MAP Optimization for Inference-Time Alignment of Diffusion and Flow-Matching Models","abstract":"Inference-time alignment of pretrained text-to-image models is typically performed along a single control axis, such as classifier-free guidance, attention editing, or reward-based latent perturbations. This limitation prevents modeling joint dependencies between conditioning and latent variables and hinders transfer across generative transports. We propose PG-MAP, a training-free framework that formulates inference-time alignment as a trajectory-level Gibbs-MAP / proximal energy optimization over the conditioning $c$ and latent state $z_t$ via a forward-consistency coupling, optionally guided by a frozen preference reward. This joint formulation enables coordinated updates across modalities while remaining compatible with both diffusion and flow-matching models through transport-specific adaptations. Across diffusion backbones (SD~1.5, SDXL), PG-MAP consistently improves alignment metrics such as PickScore and Aesthetic, and can be effectively combined with tuned classifier-free guidance to achieve the strongest overall performance. On flow-matching models (SD3.5-medium), the framework reduces to a latent-only variant, achieving $\\mathbf{91.9\\%}$ PickScore and $75.7\\%$ HPS win rates against a static baseline, with controlled experiments ruling out noise-related artifacts. Human evaluations further confirm consistent preference over strong baselines, including tuned CFG and compute-matched universal guidance. Finally, an oracle-routing analysis shows that the relative importance of conditioning and latent optimization depends on prompt types, surfacing further headroom that a per-prompt selector could exploit.","authors":["Ruolan Sun","Pawel Polak"],"published":"2026-06-22T07:36:36Z","updated":"2026-06-22T07:36:36Z","abstract_url":"https://arxiv.org/abs/2606.22958v1","html_url":"https://arxiv.org/html/2606.22958v1","pdf_url":"https://arxiv.org/pdf/2606.22958v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22955v1","title":"Evo-RAD: Navigating Rare Retinal Disease Diagnosis via Self-Evolving Agentic Retrieval","abstract":"Large-scale pretrained foundation models have revolutionized general medical screening, but often falter on rare diseases because such conditions are underrepresented in real-world clinical datasets. While retrieval-augmented diagnosis attempts to mitigate this, conventional static methods frequently succumb to the hubness problem, retrieving visually similar but semantically incorrect common diseases. To address this, we propose Evo-RAD, a self-evolving agentic framework that transforms evidence acquisition into a dynamic decision-making task. We formulate retrieval as a Markov Decision Process (MDP) where a graphbased agent observes the reference set state and executes actions to purge discordant evidence (DELETE), acquire pathologically consistent samples (INSERT), or conclude the evolution (TERMINATE). Optimized via Group Relative Policy Optimization (GRPO) with a homogeneityaware reward, the agent learns to maximize the diagnostic homogeneity of the support reference set. Experiments on retinal disease benchmarks show that Evo-RAD substantially improves rare-disease diagnosis, outperforming retinal foundation models by +21.04%, while also surpassing retrieval-based and parameter-efficient fine-tuning methods by +3.56%. Code is available at https://github.com/SDH-Lab/Evo-RAD.","authors":["Wangding Xia","Ye Du","Jiashi Lin","Meng Wang","Danli Shi","Shujun Wang"],"published":"2026-06-22T07:33:51Z","updated":"2026-06-22T07:33:51Z","abstract_url":"https://arxiv.org/abs/2606.22955v1","html_url":"https://arxiv.org/html/2606.22955v1","pdf_url":"https://arxiv.org/pdf/2606.22955v1.pdf","matched_keywords":["retrieval","agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22948v1","title":"ENVS: Environment-Native Verified Search for Long-Horizon GUI Agents","abstract":"As multimodal agents move from interface understanding to real software control, successful trajectory discovery in live desktop environments becomes a key challenge. GUI tasks require long-horizon sequences of precise mouse and keyboard actions, while feedback is sparse, delayed, and costly to obtain through VM rollouts. We propose Environment-Native Verified Search (ENVS), a training-time search-and-filter pipeline that uses the environment to construct verified supervision before policy optimization: it branches over behaviorally distinct GUI actions in live OSWorld VMs, verifies successful leaves, and trains from globally balanced step-level supervision. To evaluate robustness under realistic desktop interruptions, we also introduce OSWorld-Noisy, a dynamic benchmark for recoverable desktop interruptions that preserves the original tasks while testing whether agents can refocus, dismiss, wait, or recover under live perturbations. On the 300-task OSWorld pool, ENVS reaches 30.3 pass@8 on original evaluations and 29.0 on OSWorld-Noisy, outperforming matched ARPO-style online RL while reducing compute from 184-192 to 138-153 GPU-hours; even with only 30% of its search data, ENVS reaches 27.0 pass@8, exceeding ARPO from the base model. Training from noisy environments also better preserves visual-reasoning abilities on auxiliary benchmarks, including OSWorld-G Refusal (16.7 vs. 1.9) and BLINK Functional Correspondence (26.2 vs. 23.1).","authors":["Yincheng Zhou","Athena Zhuoming Zhong","Shijie Zhang","Kevin Zhang","Teresa Xiaotao Shang","Shanghang Zhang"],"published":"2026-06-22T07:28:55Z","updated":"2026-06-22T07:28:55Z","abstract_url":"https://arxiv.org/abs/2606.22948v1","html_url":"https://arxiv.org/html/2606.22948v1","pdf_url":"https://arxiv.org/pdf/2606.22948v1.pdf","matched_keywords":["agent","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22945v1","title":"Controllable Texture Tiling with Transformed RoPE-Enhanced Diffusion Models","abstract":"Realistic integration of user-specified textures into scene images is a fundamental task in computer graphics and image editing. While existing material transfer and reference-guided inpainting methods can edit surface appearances, they often fail to address the specific requirements of texture tiling. This task necessitates precisely repeating a reference pattern according to user-defined parameters such as frequency, orientation, and scale. Furthermore, current generative approaches often struggle to maintain the structural fidelity of the reference texture, limited by either destructive pixel-level resampling or the lack of fine-grained spatial information in semantic image encoders, and they frequently fail to preserve the coherent lighting and geometry of the original scene. In this paper, we propose a novel framework for controllable and high-fidelity texture tiling based on Diffusion Transformers. Our approach introduces two key technical innovations to decouple spatial manipulation from content generation. First, we propose a Coordinate-Transformed Rotary Embedding mechanism. By applying 2D affine transformations directly to the relative positional embeddings between the target latent and the image condition, we achieve precise control over tiling patterns without explicit pixel warping, thereby utilizing the full information of the reference condition without degradation. Second, a Disjoint Attention Mask is employed to shield reference features from semantic leakage. This preserves structural integrity while seamlessly blending the synthesized texture with the scene's original lighting and geometry. Extensive experiments demonstrate that our method outperforms state-of-the-art baselines in both control accuracy and texture fidelity.","authors":["Junrong Huang","Zhiyuan Zhang","Rui Tang","Hongbo Fu","Jnig Liao"],"published":"2026-06-22T07:24:15Z","updated":"2026-06-22T07:24:15Z","abstract_url":"https://arxiv.org/abs/2606.22945v1","html_url":"https://arxiv.org/html/2606.22945v1","pdf_url":"https://arxiv.org/pdf/2606.22945v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22943v1","title":"Evaluating self-supervised echocardiographic representations across downstream extraction strategies for left-ventricular segmentation and ejection fraction estimation","abstract":"Self-supervised learning (SSL) is increasingly used in medical imaging to reduce annotation requirements, but representation quality is often judged using a single downstream evaluation setting. For dense clinical tasks, this can confound representation quality with the capacity of the downstream model used to recover task-relevant information. We present a systematic evaluation of self-supervised representations for left-ventricular segmentation and ejection fraction (EF) estimation from apical four-chamber echocardiography on EchoNet-Dynamic. Rather than relying on a single downstream probe, we compare a hierarchy of extraction strategies with increasing expressivity: heuristic extraction without mask-supervised training, frozen linear probes, frozen lightweight decoder probes, and partial fine-tuning. We apply this framework to two complementary representation families: generic frozen self-DIstillation with NO labels (DINOv3) features and a task-adapted dense self-supervised representation, Bootstrap Your Own Segmentation (BYOS). In both families, heuristic extraction substantially understated what was recoverable from the frozen representation. For DINOv3, performance improved from Dice 0.684 and EF mean absolute error (MAE) 13.01 under heuristic extraction to Dice 0.906 and EF MAE 9.65 with a frozen lightweight decoder, approaching a supervised U-Net baseline (Dice 0.915, EF MAE 9.72). For BYOS, performance improved from Dice 0.687 and EF MAE 17.83 under heuristic extraction to Dice 0.902 and EF MAE 8.74 with a frozen lightweight decoder. These results show that conclusions about self-supervised representation quality in dense echocardiographic analysis depend strongly on the downstream extraction strategy used for evaluation. We therefore argue that multi-strategy evaluation is an important methodological consideration for SSL in dense medical image analysis.","authors":["Sylwia Majchrowska","Philip Teare"],"published":"2026-06-22T07:21:43Z","updated":"2026-06-22T07:21:43Z","abstract_url":"https://arxiv.org/abs/2606.22943v1","html_url":"https://arxiv.org/html/2606.22943v1","pdf_url":"https://arxiv.org/pdf/2606.22943v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22931v1","title":"BEV-Denoise: Learning Intrinsic Noise for Accurate Bird's-Eye-View Semantic Segmentation","abstract":"In this paper, we present a framework dubbed \\textbf{BEV-Denoise} that estimates and removes intrinsic noise from learned Bird's-Eye-View (BEV) features to achieve accurate BEV semantic segmentation. Inspired by the noise estimation capability of Denoising Diffusion Probabilistic Models (DDPM), we design a UNet-based noise estimation module that learns to estimate the noise from the learned BEV features. The estimated noise is then subtracted from the BEV features and fed to BEV map decoders for the final prediction results. To facilitate supervision for the noise estimation module, we follow a sequential learning paradigm called Task Decomposition (TD) where a pre-trained BEV map autoencoder is employed to train a view transformation (VT) encoder. We share three key insights learned from our intensive experiments that are critical for improved performance. We apply our framework to four existing models, encompassing the three major VT paradigms. Experimental results on a large-scale real-world dataset, nuScenes, demonstrate the effectiveness of our framework.","authors":["Dooseop Choi","Kyounghwan An","Kyoung-Wook Min"],"published":"2026-06-22T07:06:46Z","updated":"2026-06-22T07:06:46Z","abstract_url":"https://arxiv.org/abs/2606.22931v1","html_url":"https://arxiv.org/html/2606.22931v1","pdf_url":"https://arxiv.org/pdf/2606.22931v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22924v1","title":"MythraGen: Two-Stage Retrieval Augmented Art Generation Framework","abstract":"Text-to-image generation has seen rapid advancements, especially with the development of generative models. However, challenges remain in achieving high-quality, contextually accurate image outputs that faithfully match the provided textual descriptions, especially in artistic generation. In this paper, we present a simple yet efficient retrieval augmented generation framework, namely MythraGen, for text-to-artistic image generation by integrating an art retrieval mechanism with LoRA-based model fine-tuning. Our method extracts features from a large-scale art dataset, optimizing the generation process by combining artist-specific styles and content. Particularly, retrieved images from an external art database that have the highest similarity to the query prompt are used to finetune Stable Diffusion using LoRA for desired art generation. Experimental results and user studies on the WikiArt dataset show that our proposed method can generate artworks that closely match the user's input, significantly outperforming existing solutions.","authors":["Quang-Khai Le","Cong-Long Nguyen","Minh-Triet Tran","Trung-Nghia Le"],"published":"2026-06-22T07:02:33Z","updated":"2026-06-22T07:02:33Z","abstract_url":"https://arxiv.org/abs/2606.22924v1","html_url":"https://arxiv.org/html/2606.22924v1","pdf_url":"https://arxiv.org/pdf/2606.22924v1.pdf","matched_keywords":["retrieval","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22918v1","title":"Each Judge Its Own Yardstick: Discovering Per-VLM Taxonomies for Physical Video Evaluation","abstract":"Maintaining physical consistency in video generators and world models increasingly relies on vision-language models (VLMs) as automated judges that provide reward signals, ranking decisions, and data-filtering criteria. Yet VLMs differ substantially in training data and architecture, encoding physical phenomena through distinct internal representations. A single global evaluation schema therefore gives every VLM the same axes of competence, regardless of what each can actually perceive. We propose JudgeFit, an iterative refinement procedure that discovers a per-VLM evaluation taxonomy. An initial taxonomy is constructed by prompting the target VLM to enumerate physics errors on a small set of videos and clustering the resulting descriptions. The taxonomy is then refined through a diagnostic step: we calibrate the VLM's per-dimension scores to human physical-commonsense ratings, diagnose which dimensions it scores unreliably or redundantly, and prompt an LLM to repair them, iterating until convergence. We further instantiate this procedure as a benchmark and apply it to 16 VLMs spanning eight model families. The refined taxonomy outperforms the global-schema baseline on held-out videos for every VLM tested, with a mean relative improvement of approximately 32%. Beyond aggregate accuracy, the per-VLM profiles expose model-specific blind spots that overall rankings cannot anticipate, with reliability patterns differing markedly across model families.","authors":["Yu Cao","Ziquan Liu","Zhensong Zhang","Jiankang Deng","Shaogang Gong","Jifei Song"],"published":"2026-06-22T06:58:39Z","updated":"2026-06-22T06:58:39Z","abstract_url":"https://arxiv.org/abs/2606.22918v1","html_url":"https://arxiv.org/html/2606.22918v1","pdf_url":"https://arxiv.org/pdf/2606.22918v1.pdf","matched_keywords":["video","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22913v1","title":"Intend, Reflect, Refine: An Adaptive Multimodal Reflection Framework for Autonomous Driving","abstract":"Recent Vision-Language-Action (VLA) models have advanced end-to-end autonomous driving by incorporating reasoning for better interpretability and planning quality. However, most existing approaches directly generate the final trajectory without explicitly examining its future consequences, which limits their reliability in complex and dynamic environments. To address this limitation, we propose IRR-Drive (Intend, Reflect, Refine), an adaptive multimodal reflection framework for autonomous driving. Specifically, to tightly couple high-level reasoning with physical constraints, IRR-Drive first generates a preliminary textual intention and anticipates potential interactions by predicting future semantic bird's-eye view (BEV) representations. This dual-modality (Text + BEV) reflection space explicitly models anticipated scene evolution, enabling the model to rigorously self-correct and refine its initial intent before generating the final trajectory. Furthermore, to balance planning performance and computational efficiency, we construct reflection-oriented training data and design an adaptive reflection reward, enabling the model to adaptively select its reasoning mode according to scene complexity. Instead of using reasoning primarily as an auxiliary interpretation, IRR-Drive directly integrates an adaptive reflection mechanism into the planning framework, enabling grounded, decision-aware trajectory correction that is driven by scene complexity. Our method achieves state-of-the-art performance on the NAVSIM benchmark in both PDMS and EPDMS. Extensive experiments demonstrate the effectiveness of our multimodal reflection framework and validate the efficacy of the proposed adaptive reflection strategy.","authors":["Zisheng Chen","Yuping Qiu","Jianhua Han","Tao Tang","Xiuwei Chen","Likui Zhang","Ying-Cong Chen","Hang Xu","Xiaodan Liang"],"published":"2026-06-22T06:53:58Z","updated":"2026-06-22T06:53:58Z","abstract_url":"https://arxiv.org/abs/2606.22913v1","html_url":"https://arxiv.org/html/2606.22913v1","pdf_url":"https://arxiv.org/pdf/2606.22913v1.pdf","matched_keywords":["representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22907v1","title":"Improving Robotic Imitation Learning via Trajectory Standardization","abstract":"Imitation learning for robotic manipulation relies on large sets of human demonstration trajectories, which are often noisy and temporally irregular due to variable operator speed, intermittent pauses, and inconsistent action density. A common preprocessing strategy is time-uniform downsampling to shorten sequences, but it cannot effectively remove speed-induced non-uniformity or redundant pauses. This mismatch degrades data quality and hinders policy learning. To address this issue, we propose Information-Standardized Trajectory Resampling (ISR), an offline preprocessing method for effective imitation learning. ISR resamples each trajectory by enforcing approximately equal information distance between adjacent points. Specifically, we map trajectories onto an information-modulated Riemannian manifold and perform geodesic-equidistant parameterization. We construct an information-intensity field from velocity and acceleration norms: the velocity term removes small-motion redundancy, while the acceleration term preserves high-curvature and fine-manipulation phases. We evaluate ISR on three real-world manipulation tasks with mainstream imitation learning policies. Compared with the baseline time-uniform 3x downsampling, ISR improves task success rates by about 25%, remains robust across datasets collected from different operators, and reduces both dataset size and training cost. The code and videos are publicly available at https://d-robotics-ai-lab.github.io/isr.page.","authors":["Licheng Yang","Lingfeng Qian","Fei Zheng","Yonghao He","Wei Sui","Shuangshuang Li","Hu Su"],"published":"2026-06-22T06:46:26Z","updated":"2026-06-22T06:46:26Z","abstract_url":"https://arxiv.org/abs/2606.22907v1","html_url":"https://arxiv.org/html/2606.22907v1","pdf_url":"https://arxiv.org/pdf/2606.22907v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22905v1","title":"InteractiveAvatar: Real-Time Streaming Video Generation for Consistent and Intent-Aware Avatars","abstract":"Recent diffusion-based models have enabled realistic audio-driven avatar generation in real-time streaming. However, existing approaches struggle to maintain visual temporal consistency and fail to explicitly perceive user intent in complex interactive streaming scenarios. To address these challenges, we propose InteractiveAvatar, a real-time infinite-streaming video generation framework that supports visually consistent avatar video generation and intent-aware interactions. With autoregressive distillation, InteractiveAvatar achieves real-time str-eaming generation of human avatars over arbitrarily long durations. For visual consistency, we introduce a Long-Short Visual Memory (LSVM) mechanism that flexibly compresses historical visual information into compact tokens, preserving both short-range coherence and long-term consistency. To generate avatars with speeches and actions aligned with user intent, we propose a Reasoning-Reaction Module (RRM), which incorporates a State-Cycling strategy and a Cache-Switching mechanism. Extensive experimental results over diverse scenarios demonstrate that our method achieves state-of-the-art visual consistency in long-duration generation, while enabling complex user-avatar interaction in real time.","authors":["Quanyue Song","Yishan He","Yanfei Zhang","Shihao Cheng","Zhixiang He","Zhizhi Guo","Chi Zhang","Xuelong Li","Caigui Jiang"],"published":"2026-06-22T06:41:17Z","updated":"2026-06-22T06:41:17Z","abstract_url":"https://arxiv.org/abs/2606.22905v1","html_url":"https://arxiv.org/html/2606.22905v1","pdf_url":"https://arxiv.org/pdf/2606.22905v1.pdf","matched_keywords":["video","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22890v1","title":"PHOEBI: An Open-World Benchmark for Bacterial Identification in Phase-Contrast Microscopy","abstract":"Optical microscopy enables rapid, label-free imaging of live bacteria and is the standard instrument for species identification across clinical, environmental, and industrial microbiology. Yet field samples are routinely polymicrobial and may contain organisms that were never seen during system training, and no computer-vision benchmark tests multi-label species identification from phase-contrast microscopy (PCM) of such mixtures. We introduce Phase-contrast Optical bEnchmark for Bacterial Identification ($\\textbf{PHOEBI}$), a wet-lab-prepared dataset of $120{,}000$ PCM images covering $40$ combinations of six rod-shaped species, paired with a leave-combinations-out (LCO) evaluation protocol that holds out entire species combinations to mirror the practical scenario of a model trained on catalogued mixtures that must generalise to unseen ones. On LCO, every gradient-trained per-image aggregator we test drops $0.39$ to $0.57$ F1 from the in-distribution to the held-out split, a systematic open-world recognition failure in the aggregator, not the visual representation. A linear probe of thirteen different encoders over the same features spreads only about six percentage points of F1 across general-purpose and biomedical pretraining objectives, confirming the representation is sound. We propose three lightweight $\\textit{anchor-based}$ decoders that capture per-species presence geometrically over a shared frozen tile-feature pool, scoring $\\textit{higher}$ on held-out combinations than on in-distribution validation.","authors":["Aaditya Baranwal","Md Jahid Hasan","Shruti Vyas"],"published":"2026-06-22T06:01:09Z","updated":"2026-06-22T06:01:09Z","abstract_url":"https://arxiv.org/abs/2606.22890v1","html_url":"https://arxiv.org/html/2606.22890v1","pdf_url":"https://arxiv.org/pdf/2606.22890v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22875v1","title":"FedOT: Ownership Verification and Leakage Tracing via Watermarks for Federated LDMs","abstract":"Training Latent Diffusion Models (LDMs) within Federated Learning (FL) has attracted increasing attention due to its ability to combine the powerful generative capacity of LDMs with the privacy-preserving properties of FL. However, FL requires sharing the global model with multiple participants, which risks unauthorized model distribution or resale by malicious clients. While an intuitive approach is to adopt existing VAE-based watermarking techniques for LDMs in FL, this strategy falls short in addressing such threats due to two fundamental challenges: (1) Existing methods support ownership verification but lack the ability to trace model leakage to a specific malicious client; (2) VAE-based watermarks are vulnerable, as they can be removed simply by replacing the decoder with a clean counterpart. In this paper, we propose FedOT, the first framework for ownership verification and leakage tracing in federated LDMs. Specifically, to address the first challenge, we design a chunked watermark, where the first part is for ownership verification, and the second part is used for client identification. Furthermore, to overcome the second challenge and secure the model against VAE replacement attack, we introduce Latent Vector Transformation (LVT), which strengthens the connection between the VAE and U-Net latent spaces by modifying the original latent distribution of the VAE. Consequently, any attempt to replace the VAE for watermark removal leads to significant image quality degradation, making the LDM model unusable. Extensive experiments demonstrate that FedOT achieves superior performance in both ownership verification and traceability. Project page: https://spyzixuan.github.io/FedOT/.","authors":["Wenlong Cheng","Yuan Gan","Yunqiu Xu","Jiaxu Miao"],"published":"2026-06-22T05:39:46Z","updated":"2026-06-22T05:39:46Z","abstract_url":"https://arxiv.org/abs/2606.22875v1","html_url":"https://arxiv.org/html/2606.22875v1","pdf_url":"https://arxiv.org/pdf/2606.22875v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"}],"favorites":[],"latest":{"generated_at_utc":"2026-06-23T04:56:14+00:00","category":"cs.CV","keywords":["video","retrieval","3d","agent","representation","instance","multimodal","diffusion"],"fetch_window_hours":72,"daily_window_hours":30,"match_count":76,"new_or_recent_papers":[{"id":"2606.23688v1","title":"Lift4D: Harmonizing Single-View 3D Estimation for 4D Reconstruction In-the-Wild","abstract":"Reconstructing dynamic non-rigid objects from monocular video requires integrating visual cues from direct observations with data-driven priors over geometry and appearance. Prior approaches either learn to directly predict 4D representations from visual input or initialize a 3D representation that is subsequently deformed and refined based on video evidence. However, the former are constrained by the scarcity of 4D training data, while the latter leverage priors only for the initial reconstruction and rely solely on video supervision thereafter; neither handles complex in-the-wild scenarios with large deformations and occlusions well. We present Lift4D, a test-time optimization framework that addresses both limitations. First, we adapt an existing single-view 3D reconstruction model to yield temporally consistent per-frame predictions via causal latent conditioning, providing a coherent initialization for a deformable 3D Gaussian Splatting representation. We then ``sculpt'' this representation to match the input video through an occlusion-aware optimization that faithfully recovers visible surface details while completing unobserved regions using a view-conditioned diffusion prior. We demonstrate that Lift4D clearly improves over prior 4D reconstruction methods, particularly on challenging in-the-wild sequences with severe occlusions and non-rigid motion.","authors":["Yehonathan Litman","Xiaoxuan Ma","Manan Shah","Nicolas Ugrinovic","Kris Kitani","Fernando De la Torre","Shubham Tulsiani"],"published":"2026-06-22T17:59:54Z","updated":"2026-06-22T17:59:54Z","abstract_url":"https://arxiv.org/abs/2606.23688v1","html_url":"https://arxiv.org/html/2606.23688v1","pdf_url":"https://arxiv.org/pdf/2606.23688v1.pdf","matched_keywords":["video","3d","representation","diffusion"],"source_used":"html","source_text_chars":60515,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, 3d, representation, diffusion 相关；摘要显示其主要贡献为：Reconstructing dynamic non-rigid objects from monocular video requires integrating visual cues from direct observations with data-driven priors over geometry and appearance. Prior approaches either learn to directly predict 4D representations from visual inpu...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:15+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23682v1","title":"Keep The Essentials: Efficient Reference Conditioned Generation via Token Dropping","abstract":"Reference-based diffusion models enable highly controllable image generation by leveraging elements from input images to guide prompt-driven synthesis. However, these models are computationally expensive in runtime, and their cost scales severely with the number of input references. While the efficiency of diffusion models has been extensively studied in the context of prompt-driven generation, it remains largely under-explored in the realm of reference-based models. This setting presents unique challenges not addressed by methods focusing solely on generation. In particular, the wasteful representation of references as dense token grids offers significant opportunities for improvement. In this work, we present Sparse Context, a method for constructing sparse reference representations by retaining only a reduced subset of reference tokens. We observe that even without modifying the model, dropping a significant portion of reference tokens at inference time largely preserves its generation capabilities. To fully realize this potential, we fine-tune the model with random token dropping at varying ratios, encouraging robustness to partial reference representations. Crucially, this training strategy decouples the model from any specific token selection rule, allowing flexible control at inference time. At inference time, instead of random dropping, we apply task-aware token selection strategies that prioritize the most informative regions of the reference images, adapting the token budget to the input and task requirements. Extensive experiments show our method achieves a 4x increase in inference speed for multi-reference generation and an 2x for single reference generation. Importantly, this efficiency is achieved without compromising visual quality across both spatially-aligned editing and subject-driven generation.","authors":["Rishubh Parihar","Ayush Raina","R. Venkatesh Babu","Or Patashnik"],"published":"2026-06-22T17:59:28Z","updated":"2026-06-22T17:59:28Z","abstract_url":"https://arxiv.org/abs/2606.23682v1","html_url":"https://arxiv.org/html/2606.23682v1","pdf_url":"https://arxiv.org/pdf/2606.23682v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"html","source_text_chars":61575,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation, diffusion 相关；摘要显示其主要贡献为：Reference-based diffusion models enable highly controllable image generation by leveraging elements from input images to guide prompt-driven synthesis. However, these models are computationally expensive in runtime, and their cost scales severely with the num...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:15+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23679v1","title":"Semantic Browsing: Controllable Diversity for Image Generation","abstract":"Modern text-to-image models excel in visual fidelity and prompt adherence. However, this strict adherence comes at the cost of diversity: generated samples tend to collapse into a single visual interpretation. Existing methods to improve diversity produce outputs driven by incidental variations rather than meaningful design choices. This motivates a new variant of the diversity task where structure is enforced on the generated samples. We introduce a method for controlled diversity that enables Semantic Browsing, where users can navigate structured image galleries and experience creative exploration through a systematic traversal of meaningful, interpretable axes of variation. Achieving this level of semantic control requires a deep understanding of the scene. We exploit the fact that recent text-to-image models are trained on elaborated captions, effectively decoupling semantic decision-making from pixel generation. This enables a paradigm shift: instead of relying on stochastic variation within the text-to-image model, we induce diversity directly at the text level. By leveraging rich textual representations, we allow a Vision Language Model (VLM) to operate on the full scene context. To overcome the generic outputs typical of standard VLMs, we employ an agentic workflow that explicitly enforces structured variation attuned to the original prompt. We demonstrate that our method produces diverse and navigable design spaces where every variation corresponds to a specific, user-understandable semantic decision.","authors":["Sara Dorfman","Maya Vishnevsky","Omer Dahary","Or Patashnik","Daniel Cohen-Or"],"published":"2026-06-22T17:59:17Z","updated":"2026-06-22T17:59:17Z","abstract_url":"https://arxiv.org/abs/2606.23679v1","html_url":"https://arxiv.org/html/2606.23679v1","pdf_url":"https://arxiv.org/pdf/2606.23679v1.pdf","matched_keywords":["agent","representation"],"source_used":"html","source_text_chars":66969,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 agent, representation 相关；摘要显示其主要贡献为：Modern text-to-image models excel in visual fidelity and prompt adherence. However, this strict adherence comes at the cost of diversity: generated samples tend to collapse into a single visual interpretation. Existing methods to improve diversity produce out...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:15+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23678v1","title":"AIR: Adaptive Interleaved Reasoning with Code in MLLMs","abstract":"Following the paradigm shift initiated by OpenAI o3, interleaved reasoning with code to enhance multimodal large language models (MLLMs) has become a pivotal research frontier. The existing literature focuses primarily on tool-use within vision-perception tasks. However, such approaches typically rely on predefined heuristics for visual manipulation and are inherently incapable of addressing numerical computation problems due to their exclusive focus on visual operations. This paper empowers MLLMs with adaptive interleaved reasoning capabilities through extended reinforcement learning training on code-augmented complex numerical computation tasks. To this end, we propose a comprehensive three-component solution consisting of: a two-stage cold-start data construction pipeline, data filtering strategies for RL dataset curation, and an adaptive tool-invocation strategy leveraging a group-constrained reward function for interleaved reasoning trajectories. Extensive experiments demonstrate that after Reinforcement Learning training with the group-constrained reward function, performance improves by an average of 6.1 percentage points (pp) on evaluation benchmarks. Specifically, the accuracy for interleaved reasoning samples increases by 9.9 pp, and the overall success rate of tool-use exceeds 95%. Our data and code are available at: https://github.com/CongHan0808/AIR.git.","authors":["Cong Han","Xiaohan Lan","Haibo Qiu","Yujie Zhong"],"published":"2026-06-22T17:58:54Z","updated":"2026-06-22T17:58:54Z","abstract_url":"https://arxiv.org/abs/2606.23678v1","html_url":"https://arxiv.org/html/2606.23678v1","pdf_url":"https://arxiv.org/pdf/2606.23678v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":72751,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：Following the paradigm shift initiated by OpenAI o3, interleaved reasoning with code to enhance multimodal large language models (MLLMs) has become a pivotal research frontier. The existing literature focuses primarily on tool-use within vision-perception tas...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:15+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23675v1","title":"IMAGIN-4D: Image-Guided Controllable Interaction Generation","abstract":"Generating human-object interactions (HOI) is central to character animation, robotics, AR/VR, and embodied AI. Recent HOI generation methods synthesize motion from text, object geometry, and sparse waypoints, controlling action semantics and object trajectories. However, these signals underspecify interaction: the same prompt and trajectory can produce different grasps, approach directions, body poses, object poses, contacts, and body-object layouts. We address this ambiguity with a reference image as a visual specification of the desired interaction snapshot. However, a single global image representation conflates distinct cues and conditions all frames on identical visual evidence. We therefore introduce IMAGIN-4D, a diffusion-based HOI generator that decomposes image conditioning spatio-temporally. For spatial conditioning, IMAGIN-4D extracts supervised interaction-state tokens for body pose, object pose, body-object contact, and spatial relationships at the depicted frame. For temporal conditioning, it computes frame-aware tokens by querying image patches per generated frame, allowing sequence segments to attend to different visual cues from the same image. To balance image, text, and waypoint cues, IMAGIN-4D uses role-aware conditioning: text, waypoints, and interaction-state tokens use separate AdaLN streams, while frame-aware visual tokens cross-attend with motion tokens. Since HOI motion datasets lack paired images, we build a synthetic motion-to-image rendering pipeline from FullBodyManipulation (FBM) and introduce an image-adherence metric to evaluate whether generated motions match the reference snapshot. Experiments on FBM and BEHAVE show that IMAGIN-4D improves fine-grained interaction control over single-token and uniformly image-conditioned baselines while preserving waypoint-following and motion quality. Code and models will be released at https://imagin4d.github.io.","authors":["Sai Kumar Dwivedi","Federica Bogo","Buğra Tekin","Chenhongyi Yang","Nadine Bertsch","Tomas Hodan","Michael J. Black","Dimitrios Tzionas","Shreyas Hampali"],"published":"2026-06-22T17:58:03Z","updated":"2026-06-22T17:58:03Z","abstract_url":"https://arxiv.org/abs/2606.23675v1","html_url":"https://arxiv.org/html/2606.23675v1","pdf_url":"https://arxiv.org/pdf/2606.23675v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"html","source_text_chars":92981,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation, diffusion 相关；摘要显示其主要贡献为：Generating human-object interactions (HOI) is central to character animation, robotics, AR/VR, and embodied AI. Recent HOI generation methods synthesize motion from text, object geometry, and sparse waypoints, controlling action semantics and object trajector...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:15+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23669v1","title":"GeoFidelity-Bench: Evaluating Segment-Level Geographic Fidelity in Text-to-Image Street-View Generation","abstract":"Text-to-image models can generate visually plausible city streets, but whether their outputs correspond to a requested road segment rather than a generic city prior remains unclear. We introduce GeoFidelity-Bench, a reference-panel benchmark for segment-conditioned geographic fidelity in street-view generation. It contains 7,117 curated Mapillary images covering 109 named OpenStreetMap road segments in 25 cities across six continents. For each generated panel, the benchmark ranks the target reference panel against panels from the nearest segment in the same city, other segments in the same city, and segments from other cities, making local discrimination rather than absolute target similarity the primary test. We evaluate six open-weight text-to-image generators under city-only, street-and-neighborhood, and GPS-augmented prompts. Adding street and neighborhood names is associated with an increase of 5.5 percentage points in top-1 retrieval accuracy over city-only prompts, with a 95% confidence interval from 3.4 to 7.7 percentage points. However, the similarity margin between the target and the nearest segment in the same city remains near zero, indicating that local names improve broad local plausibility more than exact segment identity. Prompts that keep the city fixed but use incorrect street or neighborhood names further show that only part of the gain depends on the correct local names, while appending raw GPS coordinates as ordinary text yields no statistically clear additional benefit. Held-out real-image queries successfully recover segment identity, showing that the curated references contain usable segment-level signal. GeoFidelity-Bench thus reveals a persistent gap between city- or neighborhood-plausible street-view generation and faithful generation for a specific road segment.","authors":["Kaizhen Tan","Hanzhe Hong","Siru Tao"],"published":"2026-06-22T17:53:26Z","updated":"2026-06-22T17:53:26Z","abstract_url":"https://arxiv.org/abs/2606.23669v1","html_url":"https://arxiv.org/html/2606.23669v1","pdf_url":"https://arxiv.org/pdf/2606.23669v1.pdf","matched_keywords":["retrieval"],"source_used":"html","source_text_chars":55771,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 retrieval 相关；摘要显示其主要贡献为：Text-to-image models can generate visually plausible city streets, but whether their outputs correspond to a requested road segment rather than a generic city prior remains unclear. We introduce GeoFidelity-Bench, a reference-panel benchmark for segment-condi...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:15+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23665v1","title":"PHAST-Net: Attention-Guided, Physics-Informed Network for Unified Estimation of Ideal Time-Frequency Representations","abstract":"We introduce PHAST-Net, an attention-guided, physics-informed network for unified estimation of Ideal Time-Frequency Representations (ITFRs), spanning spectral, tempo-based, metrical, and harmonic representations such as Spectrograms, Tempograms, and Metrograms. PHAST-Net learns an application-general mapping from a constellation of wavelet transforms, the proposed Continuous Log-frequency Adaptive Wavelet Transform (CLAWT), to high-resolution, cross-term-suppressed time-frequency (T-F) representations. The proposed constellation of CLAWTs is selected through Cohen's class kernel analysis to maximise curvature coverage in a logarithmic-frequency T-F plane tailored to harmonic signal structure. PHAST-Net further incorporates a proposed physics-informed auxiliary reprojection loss designed to reconstruct the idealised observed CLAWT constellation from the predicted ITFR and the corresponding Cohen's class kernels during training. This auxiliary objective promotes transform consistency and energy conservation, mitigates pathological target sparsity, and enhances optimisation stability. Attention layers further promote effective cross-term suppression across the input constellation. The log-frequency formulation also enables Harmonic PHAST-Net, which estimates a Harmonic ITFR that isolates fundamental structure, supporting robust fundamental-only representations for speech and music, such as derived fundamental Tempograms and Metrograms. We further introduce Spline-PHAST-Net, which parameterises detected and associated T-F ridges as continuous spline trajectories, enabling arbitrary-grid re-rendering and signal reconstruction. Trained on an effectively unbounded procedurally generated dataset, PHAST-Net demonstrates improved accuracy over established approaches, providing a unified framework for high-resolution, cross-term-robust analysis of speech, music, and broader nonstationary signals.","authors":["James M. Cozens","Simon J. Godsill"],"published":"2026-06-22T17:49:00Z","updated":"2026-06-22T17:49:00Z","abstract_url":"https://arxiv.org/abs/2606.23665v1","html_url":"https://arxiv.org/html/2606.23665v1","pdf_url":"https://arxiv.org/pdf/2606.23665v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":121745,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：We introduce PHAST-Net, an attention-guided, physics-informed network for unified estimation of Ideal Time-Frequency Representations (ITFRs), spanning spectral, tempo-based, metrical, and harmonic representations such as Spectrograms, Tempograms, and Metrogra...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:16+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23653v1","title":"Lightweight Neural Framework for Robust 3D Volume and Surface Estimation from Multi-View Images","abstract":"Accurate volume and surface area estimation is critical for diverse applications, from marine ecology to medical diagnostics. However, existing methods often suffer from high computational costs and poor performance with sparse and noisy data. We propose a fully feed-forward framework that regresses scale-normalized volume and surface area and their associated uncertainties directly from multi-view images. By fusing 3D point cloud reconstructions with view-aligned 2D features through a graph-based decoder, our model bypasses iterative optimization, ensuring exceptional scalability and rapid inference. Experimental results demonstrate that our approach outperforms state-of-the-art methods, particularly when operating with a low number of input images. Validated across coral monitoring, dietary analysis, and anthropometry, our proposed framework provides a robust, adaptable solution for quantitative shape analysis. This architecture provides a high-speed, scalable alternative for precise geometric estimation from visual data, maintaining high performance even in resource-constrained or sparse-view scenarios.","authors":["Diego E. Farchione","Ramzi Idoughi","Peter Wonka"],"published":"2026-06-22T17:39:18Z","updated":"2026-06-22T17:39:18Z","abstract_url":"https://arxiv.org/abs/2606.23653v1","html_url":"https://arxiv.org/html/2606.23653v1","pdf_url":"https://arxiv.org/pdf/2606.23653v1.pdf","matched_keywords":["3d"],"source_used":"html","source_text_chars":66848,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：Accurate volume and surface area estimation is critical for diverse applications, from marine ecology to medical diagnostics. However, existing methods often suffer from high computational costs and poor performance with sparse and noisy data. We propose a fu...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:16+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23610v1","title":"Vera: A Layered Diffusion Model for Content-Preserving Video Editing","abstract":"Video diffusion models have enabled remarkable progress in video generation and editing. However, content preservation remains a core challenge: existing methods regenerate every pixel and often alter elements that should remain unchanged, such as characters or background scenes. We introduce Vera, a layered diffusion framework for content-preserving video editing. Instead of regenerating the entire video, Vera generates an edit layer along with an alpha matte for compositing with the source video, separating creative editing from content preservation by design. To encourage coherent composition with the source video, we extend the text-to-video DiT into a Mixture-of-Transformers (MoT) architecture, with separate DiTs for each layer that interact through joint self-attention. To support the training of Vera, we further construct a high-quality layered dataset with accurate alpha mattes, diverse scenes and dynamics, and visual effects. Across our quantitative benchmark and human preference study, Vera outperforms leading open-source video editing models in content preservation while remaining competitive in edit quality, using 486K frames of layered training data.","authors":["Hongkai Zheng","Ta-Ying Cheng","Benjamin Klein","Yisong Yue","Zhuoning Yuan"],"published":"2026-06-22T17:11:11Z","updated":"2026-06-22T17:11:11Z","abstract_url":"https://arxiv.org/abs/2606.23610v1","html_url":"https://arxiv.org/html/2606.23610v1","pdf_url":"https://arxiv.org/pdf/2606.23610v1.pdf","matched_keywords":["video","diffusion"],"source_used":"html","source_text_chars":87444,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, diffusion 相关；摘要显示其主要贡献为：Video diffusion models have enabled remarkable progress in video generation and editing. However, content preservation remains a core challenge: existing methods regenerate every pixel and often alter elements that should remain unchanged, such as characters...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:16+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23604v1","title":"Polycepta: Object-Centric Appearance Estimation for Multi-Object Tracking","abstract":"The tracking-by-detection paradigm in multi-object tracking (MOT) typically relies on static appearance descriptors to complement motion estimation. However, these descriptors are frame-independent, limiting their robustness as visual cues. Since such descriptors are often obtained from computationally intensive pretrained backbones, real-time MOT systems frequently abandon appearance cues altogether and rely solely on motion prediction and geometric association. In this work, we introduce Polycepta, an object-centric appearance state estimation framework that reformulates appearance modeling as a recursive estimation problem rather than a frame-wise matching task. Polycepta constructs and continuously updates an independent appearance state for each tracked object, enabling future appearance representations to be estimated from accumulated observations. Polycepta is encouraged to learn the appearance-state construction of object-specific representations rather than memorize them through a proposed learning strategy, enabling appearance estimation for unseen classes. A key property of Polycepta is that the quality of appearance estimation improves as object states evolve during inference. While conventional appearance descriptors remain static or degrade over time, Polycepta progressively refines appearance estimates as additional observations are accumulated. Extensive experiments on KITTI, the Waymo Open Dataset, and MOT17 demonstrate consistent reductions in identity switches and improvements in tracking performance when integrated into the tracking-by-detection pipelines. Polycepta operates at 90.57 Hz and delivers state-of-the-art performance on the KITTI benchmark when integrated into the RobMOT framework, achieving a MOTA of 92.27\\%.","authors":["Mohamed Nagy","Naoufel Werghi","Jorge Dias","Majid Khonji"],"published":"2026-06-22T17:06:32Z","updated":"2026-06-22T17:06:32Z","abstract_url":"https://arxiv.org/abs/2606.23604v1","html_url":"https://arxiv.org/html/2606.23604v1","pdf_url":"https://arxiv.org/pdf/2606.23604v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":83033,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：The tracking-by-detection paradigm in multi-object tracking (MOT) typically relies on static appearance descriptors to complement motion estimation. However, these descriptors are frame-independent, limiting their robustness as visual cues. Since such descrip...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:16+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23593v1","title":"Real-Time Multimodal Activity-Aware Error Detection in Robot-Assisted Surgery","abstract":"Robot-assisted minimally invasive surgery improves surgical precision but introduces complexity, making technical error detection essential for ensuring patient safety. Current executional error detection methods using video data often overlook fine-grained contextual descriptions of activities and error types within the hierarchical structure of surgical procedures. They also under-utilize complementary multimodal information. We propose a unified framework for executional error detection that leverages multimodal input, including video, kinematics, and descriptive textual prompts. Through activity prompting, we integrate descriptive language in gesture-level activities, instrument-object interactions, and error definitions. We also introduce activity-aware visual embeddings derived from vision encoders pretrained on surgical activity labels to compare the effectiveness of contrastive language-image embeddings with traditional image-based embeddings for error detection. By seamlessly integrating kinematic data with video and textual modalities, our framework significantly improves error detection performance. Achieving up to 5\\% and 16.6\\% F1 score improvements over state-of-the-art baselines on the JIGSAWS and SAR-RARP50 datasets, respectively, we demonstrate the value of combining curated textual prompts with multimodal data for accurate error detection.","authors":["Seyed Hamid Reza Roodabeh","Zongyu Li","Homa Alemzadeh"],"published":"2026-06-22T17:01:45Z","updated":"2026-06-22T17:01:45Z","abstract_url":"https://arxiv.org/abs/2606.23593v1","html_url":"https://arxiv.org/html/2606.23593v1","pdf_url":"https://arxiv.org/pdf/2606.23593v1.pdf","matched_keywords":["video","multimodal"],"source_used":"html","source_text_chars":52339,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, multimodal 相关；摘要显示其主要贡献为：Robot-assisted minimally invasive surgery improves surgical precision but introduces complexity, making technical error detection essential for ensuring patient safety. Current executional error detection methods using video data often overlook fine-grained c...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:16+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23581v1","title":"Kamera: Unified Position-Invariant Multimodal KV Cache for Training-Free Reuse","abstract":"Multimodal agents repeatedly re-examine the same video frames, UI screenshots, and rendered artifacts as their context window slides and reasoning iterates, yet every look-back re-encodes from scratch, because prefix caches serve reuse only at a fixed leading position. We show this recompute is avoidable, and identify exactly what naive KV reuse loses: the cross-chunk conditioning a chunk absorbs from its neighbours. This loss is asymmetric. The direct readout of a cached chunk is recovered exactly and for free by the standard state-merge. What remains is a diffuse, low-rank residue concentrated in deep layers, invisible to single-hop retrieval but precisely what multi-hop reasoning binds on. Blind reuse therefore leaves single-hop recall intact while halving multi-hop accuracy; this is the failure mode prior position-independent caches, designed for single-context or single-image reuse, do not address. We repair it with a small, training-free low-rank conditioning patch stored alongside each position-free chunk. Reuse reduces to one operator across MLA, GQA, and MHA: exact RoPE re-rotation to any target position, plus the patch that restores cross-chunk binding. This makes three window operations cheap: reorder (one patch serves every ordering of a cached set), sliding-window survival (surviving chunks relocate via rotation only, zero re-encode), and recall (an evicted chunk is rehydrated by its patch, never re-encoded). A rank-m patch recovers full task accuracy on cross-chunk-binding benchmarks, MM-NIAH across two attention families and two-page doc-QA, at a fraction of the KV footprint, and reconstructs re-prefill KV to within bf16 rounding in a production SGLang kernel across six backbones. The conditioning signal is strongest in redundant vision and video streams, making our solution most impactful where multimodal agents spend their recompute budget.","authors":["Bole Ma","Jan Eitzinger","Harald Koestler","Gerhard Wellein"],"published":"2026-06-22T16:47:00Z","updated":"2026-06-22T16:47:00Z","abstract_url":"https://arxiv.org/abs/2606.23581v1","html_url":"https://arxiv.org/html/2606.23581v1","pdf_url":"https://arxiv.org/pdf/2606.23581v1.pdf","matched_keywords":["video","retrieval","agent","multimodal"],"source_used":"html","source_text_chars":78723,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, retrieval, agent, multimodal 相关；摘要显示其主要贡献为：Multimodal agents repeatedly re-examine the same video frames, UI screenshots, and rendered artifacts as their context window slides and reasoning iterates, yet every look-back re-encodes from scratch, because prefix caches serve reuse only at a fixed leading...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:17+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23565v1","title":"HoloAgent-0: A Unified Embodied Agent Framework with 3D Spatial Memory","abstract":"LLM agents follow a practical execution loop in digital environments: they reason over structured states, invoke tools, inspect feedback, and revise actions. Extending this loop to physical robots is difficult because physical execution is continuous, embodiment-dependent, uncertain, and constrained by safety. Existing embodied-AI systems have advanced manipulation, spatial understanding, navigation, and humanoid control, but these capabilities often remain specialized modules or loosely coupled decision loops. In this work, we introduce HoloAgent-0, a unified embodied agent framework for real-world robot deployment. Embodied AgentOS converts language instructions into executable skill graphs, schedules robot resources, monitors execution, and triggers clarification or re-planning from runtime feedback. HoloAgent-0 organizes heterogeneous robot models and controllers through three coupled layers: Embodied AgentOS for closed-loop execution, 3D spatial memory for physical world grounding, and embodied skills for robot action. We deploy HoloAgent-0 on real hardware and evaluate its spatial memory, long-horizon navigation, and closed-loop execution across motion generation, object search, cross-robot coordination, and mobile manipulation.","authors":["Xiaolin Zhou","Liu Liu","Tingyang Xiao","Wei Feng","Fa Fu","Xinrui Meng","Xinjie Wang","Jialiang Han","Boyang Yu","Yun Du","Wei Sui","Zhizhong Su"],"published":"2026-06-22T16:31:48Z","updated":"2026-06-22T16:31:48Z","abstract_url":"https://arxiv.org/abs/2606.23565v1","html_url":"https://arxiv.org/html/2606.23565v1","pdf_url":"https://arxiv.org/pdf/2606.23565v1.pdf","matched_keywords":["3d","agent"],"source_used":"abstract","source_text_chars":1326,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, agent 相关；摘要显示其主要贡献为：LLM agents follow a practical execution loop in digital environments: they reason over structured states, invoke tools, inspect feedback, and revise actions. Extending this loop to physical robots is difficult because physical execution is continuous, embodim...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"abstract","created_at":"2026-06-23T04:56:17+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23557v1","title":"Dense Reward for Multi-View 3D Reasoning with Global Maps and Local Views","abstract":"Multi-view 3D Visual Question Answering (MV3D-VQA) requires integrating partial observations into a coherent 3D scene representation and selecting informative viewpoints for multi-step spatial reasoning. However, current multimodal LLMs are typically trained with sparse, answer-level supervision, which often yields inconsistent cross-view reasoning and brittle view selection. We present DR-MV3D (Dense Reward for MV3D-VQA), a map-grounded learning framework that provides dense, verifiable rewards to supervise the reasoning process. Our approach decomposes MV3D-VQA into (i) allocentric global map construction, (ii) question-conditioned view-trajectory planning, and (iii) egocentric grounding for answer prediction. To make intermediate steps learnable without manual annotations, we introduce two rewards: a global consistency reward that aligns the predicted map with geometry-consistent pseudo targets from frozen 3D vision foundation models (e.g., VGGT + SAM3), and a local trajectory reward that supervises ordered viewpoint selection. We optimize the full pipeline with trajectory-level policy optimization (GRPO). Experiments on MindCube, VSI-Bench, and BLINK (MV) show that DR-MV3D consistently improves over strong multi-image baselines, supporting the effectiveness of process-level dense supervision for multi-view 3D reasoning.","authors":["Jiho Choi","Seonho Lee","Seojeong Park","Hyunjung Shim"],"published":"2026-06-22T16:28:11Z","updated":"2026-06-22T16:28:11Z","abstract_url":"https://arxiv.org/abs/2606.23557v1","html_url":"https://arxiv.org/html/2606.23557v1","pdf_url":"https://arxiv.org/pdf/2606.23557v1.pdf","matched_keywords":["3d","representation","multimodal"],"source_used":"abstract","source_text_chars":1420,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, representation, multimodal 相关；摘要显示其主要贡献为：Multi-view 3D Visual Question Answering (MV3D-VQA) requires integrating partial observations into a coherent 3D scene representation and selecting informative viewpoints for multi-step spatial reasoning. However, current multimodal LLMs are typically trained...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"abstract","created_at":"2026-06-23T04:56:17+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23543v1","title":"VeriEvol: Scaling Multimodal Mathematical Reasoning via Verifiable Evol-Instruct","abstract":"Scaling reinforcement learning for visual mathematical reasoning requires more than generating harder questions: as data volume grows, the reward labels themselves must remain reliable. Yet existing data pipelines scale supervision while trusting the labeller, and policy-side methods assume the underlying answers are already correct. We instead treat scaling as a verifiable data-construction problem and decouple two axes before any policy update: prompt difficulty, expanded by route-specific evolution operators, and answer reliability, enforced by offline hypothesis-test falsification. We instantiate this as VeriEvol, an iterative framework with two extensible components: a type-aware evolution module that rewrites low-difficulty image-question seeds into harder, image-grounded prompts; and HTV-Agent, a verifier that accepts an answer only after multi-source counter-evidence has failed to refute it. The resulting verified data scales in volume, extends by adding evolution routes or verifier channels, and plugs directly into existing GRPO-style RL recipes. On a five-benchmark visual-math suite, scaling evolved SFT data from 10K to 250K samples raises the mean accuracy from 35.42 to 54.73; then, with backbone, SFT initialization, and GRPO recipe held fixed, VeriEvol adds a cumulative +3.88 over an un-evolved RL baseline, of which +1.82 comes from evolved prompts and +2.06 from the HTV-Agent verifier. We release the prompts, data, models, code, and the full verifier trace of every sample, so that downstream work can scale and audit the pipeline rather than only inspect its outputs.","authors":["Haoling Li","Kai Zheng","Jie Wu","Can Xu","Qingfeng Sun","Han Hu","Yujiu Yang"],"published":"2026-06-22T16:17:30Z","updated":"2026-06-22T16:17:30Z","abstract_url":"https://arxiv.org/abs/2606.23543v1","html_url":"https://arxiv.org/html/2606.23543v1","pdf_url":"https://arxiv.org/pdf/2606.23543v1.pdf","matched_keywords":["agent","multimodal"],"source_used":"html","source_text_chars":106479,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 agent, multimodal 相关；摘要显示其主要贡献为：Scaling reinforcement learning for visual mathematical reasoning requires more than generating harder questions: as data volume grows, the reward labels themselves must remain reliable. Yet existing data pipelines scale supervision while trusting the labeller...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:17+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23539v1","title":"LightSTAR: Efficient Visual Document Retrieval via Lightweight Selection with Vision-Adaptive Refinement","abstract":"Visual document retrieval requires rapidly locating relevant pages from large multi-modal corpora in response to user queries. While recent methods powered by Multi-modal Large Language Models (MLLMs) show competitive accuracy, they suffer from prohibitive computational costs by applying intensive MLLM encoding to every single page. Meanwhile, we observe that user queries are typically keyword-anchored, containing semantically rich words that are expected to appear directly in the visible text of relevant pages, offering an efficient cue for quickly narrowing down candidate pages. Building on this insight, we propose LightSTAR, an efficient framework that decomposes visual document retrieval into: 1) LLM-free Visual Selection, which utilizes content-grounded query encoding to focus on informative words and employs LLM-free visual embeddings to produce a high-recall candidate set; and 2) Vision-adaptive Semantic Refinement, which further performs fine-grained semantic matching exclusively on these top candidates via adaptive region-wise feature fusion to effectively combine textual and layout cues, optimized through a hardness-aware contrastive objective. Experimental results demonstrate that LightSTAR achieves state-of-the-art retrieval accuracy while reducing end-to-end latency by several-fold, offering a highly practical solution to the accuracy-efficiency trade-off in visual document retrieval. Code is available at https://github.com/bokufa/LightSTAR.","authors":["Tongkun Guan","Haocheng Wang","Wei Shen","Xiaokang Yang"],"published":"2026-06-22T16:16:24Z","updated":"2026-06-22T16:16:24Z","abstract_url":"https://arxiv.org/abs/2606.23539v1","html_url":"https://arxiv.org/html/2606.23539v1","pdf_url":"https://arxiv.org/pdf/2606.23539v1.pdf","matched_keywords":["retrieval"],"source_used":"html","source_text_chars":57900,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 retrieval 相关；摘要显示其主要贡献为：Visual document retrieval requires rapidly locating relevant pages from large multi-modal corpora in response to user queries. While recent methods powered by Multi-modal Large Language Models (MLLMs) show competitive accuracy, they suffer from prohibitive co...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:17+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23514v1","title":"Arbor: Explicit Geometric Conditioning for Controllable 3D Asset Generation","abstract":"Text and image conditioned 3D models now generate convincing assets, but they still offer little direct control over the space an object should occupy or avoid. In authoring, this spatial intent is often known before generation starts. A chair should fit a seating envelope, a prop should leave clearance for motion, or a part should expose a contact surface. Prompts and image views are poor carriers for such constraints, requiring the need for an explicit control interface. We present Arbor, a trainable attachment for text conditioned latent 3D generation. Arbor introduces constraint meshes as a native 3D control interface. The interface uses hull regions where geometry should exist, avoidance regions that should remain empty, and touch regions the object should contact. Unlike completion or whole object scaffold control, these meshes are not target evidence. They are local typed requirements and can include regions where no surface should appear. Arbor keeps this signal as geometry by converting constraint meshes into tokens and learning a routed attachment inside a frozen denoiser. Each latent region can therefore receive the part of the constraint that matters for its spatial location. We evaluate Arbor on automatic and artist curated control benchmarks with hull, avoidance, and touch constraints, and compare the metric trends to a user preference study. Even without dedicated compliance losses, Arbor improves constraint obedience while preserving object quality and variation under fixed constraints.","authors":["Jan-Niklas Dihlmann","Andreas Engelhardt","Simon Donne","Hendrik P. A. Lensch","Mark Boss"],"published":"2026-06-22T16:00:05Z","updated":"2026-06-22T16:00:05Z","abstract_url":"https://arxiv.org/abs/2606.23514v1","html_url":"https://arxiv.org/html/2606.23514v1","pdf_url":"https://arxiv.org/pdf/2606.23514v1.pdf","matched_keywords":["3d"],"source_used":"html","source_text_chars":80014,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：Text and image conditioned 3D models now generate convincing assets, but they still offer little direct control over the space an object should occupy or avoid. In authoring, this spatial intent is often known before generation starts. A chair should fit a se...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:17+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23503v1","title":"UniverSat: Resolution- and Modality-Agnostic Transformers for Earth Observation","abstract":"Vision Transformers (ViT) dominate computer vision. However, their reliance on rigid patch projectors hinders transfer to Earth Observation (EO), where input modalities, scales, and resolutions vary widely. We introduce UniverSat, a ViT-style backbone built around a Universal Patch Encoder that maps patches from arbitrary spatial, spectral, and temporal resolutions, and from both optical and non-optical sensors, into a shared embedding space with a shared set of weights. This enables training a single model on heterogeneous multimodal corpora via self-supervision, yielding robust, sensor-agnostic spatial features. We validate this approach with strong results across classification and segmentation on standard EO benchmarks from GeoBench, PANGEABench, and SpectralEarth. Our code and models are available at https://github.com/gastruc/UniverSat.","authors":["Yohann Perron","Guillaume Astruc","Nicolas Gonthier","Clement Mallet","Loic Landrieu"],"published":"2026-06-22T15:49:45Z","updated":"2026-06-22T15:49:45Z","abstract_url":"https://arxiv.org/abs/2606.23503v1","html_url":"https://arxiv.org/html/2606.23503v1","pdf_url":"https://arxiv.org/pdf/2606.23503v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":935,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：Vision Transformers (ViT) dominate computer vision. However, their reliance on rigid patch projectors hinders transfer to Earth Observation (EO), where input modalities, scales, and resolutions vary widely. We introduce UniverSat, a ViT-style backbone built a...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"abstract","created_at":"2026-06-23T04:56:17+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23494v1","title":"Brain-Adapter: A Dual-Stream Vision-Language MIL Framework for Comprehensive 3D CT Diagnosis of Acute Intracranial Pathologies","abstract":"Automated diagnosis of 3D brain CT scans is essential for critical care, yet it remains challenging due to the heavy reliance on manual annotations and the limited semantic understanding of conventional models. While 2D foundation vision-language models (VLMs) have shown remarkable generalization, effectively transferring their representational power to 3D volumes remains an open problem. In this paper, we propose Brain-Adapter, a novel dual-stream multiple instance learning (MIL) framework that leverages pre-trained 2D biomedical VLMs and raw diagnostic reports for robust scan-level multi-label classification. Specifically, we introduce a Text-Conditioned Attention (TCA) mechanism, utilizing raw diagnostic sentences as semantic queries to dynamically align visual cues with specific disease concepts. Concurrently, a parallel visual MIL stream captures global scan characteristics, supervised by structured labels extracted via a Large Language Model (LLM). To ensure representation coherence, a consistency constraint enforces synergy between the two streams. During inference, an Uncertainty-Aware Refinement (UAR) module dynamically calibrates and fuses these dual-stream predictions to resolve ambiguous cases. Extensive experiments demonstrate that our method significantly outperforms state-of-the-art 3D models and standard MIL approaches. By eliminating the reliance on dense annotations, Brain-Adapter provides a highly scalable and clinically viable solution for 3D acute intracranial pathology analysis.","authors":["Zhenyu Yi","Zhiyun Song","Yusong Sun","Zelin Liu","Manman Fei","Zhenhao Li","Jiaxuan Zhao","Xu Han","Lichi Zhang"],"published":"2026-06-22T15:41:16Z","updated":"2026-06-22T15:41:16Z","abstract_url":"https://arxiv.org/abs/2606.23494v1","html_url":"https://arxiv.org/html/2606.23494v1","pdf_url":"https://arxiv.org/pdf/2606.23494v1.pdf","matched_keywords":["3d","representation","instance"],"source_used":"html","source_text_chars":30625,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, representation, instance 相关；摘要显示其主要贡献为：Automated diagnosis of 3D brain CT scans is essential for critical care, yet it remains challenging due to the heavy reliance on manual annotations and the limited semantic understanding of conventional models. While 2D foundation vision-language models (VLMs...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:18+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23489v1","title":"MeshFlow: Mesh Generation with Equivariant Flow Matching","abstract":"Meshes are among the most common 3D scene representations, but directly generating meshes is challenging because the representation contains important symmetries, including permutation invariance of faces and vertices. MeshFlow learns to generate triangle meshes directly as triangle soups, avoiding the need to serialize meshes into long autoregressive sequences. We adopt equivariant optimal-transport flow matching models that respect the key symmetries of triangle soups: arbitrary permutations of faces and permutations of the vertices within each face. Toward this goal, we propose a simple yet effective modification to the Diffusion Transformer architecture, resulting in a scalable network capable of modeling a velocity field while maintaining the desired equivariance. We further introduce an optimal-transport-based training objective that improves convergence by eliminating supervision signals that violate these symmetries. MeshFlow achieves mesh quality comparable to state-of-the-art autoregressive mesh generators while providing about an 18$\\times$ speedup during inference. Project page is at https://qiisun.github.io/MeshFlow/.","authors":["Qi Sun","Kiyohiro Nakayama","Jing Nathan Yan","Qixing Huang","Alexander Rush","Leonidas Guibas","Gordon Wetzstein","Jing Liao","Guandao Yang"],"published":"2026-06-22T15:35:30Z","updated":"2026-06-22T15:35:30Z","abstract_url":"https://arxiv.org/abs/2606.23489v1","html_url":"https://arxiv.org/html/2606.23489v1","pdf_url":"https://arxiv.org/pdf/2606.23489v1.pdf","matched_keywords":["3d","representation","diffusion"],"source_used":"html","source_text_chars":103648,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, representation, diffusion 相关；摘要显示其主要贡献为：Meshes are among the most common 3D scene representations, but directly generating meshes is challenging because the representation contains important symmetries, including permutation invariance of faces and vertices. MeshFlow learns to generate triangle mes...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-23T04:56:18+00:00","status":"fallback"},"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23473v1","title":"C^2GR: Coupled Comprehensive Generative Replay for a Continually Learnable Universal Segmentation Model","abstract":"Universal segmentation models exhibit significant potential for diverse tasks involving different imaging modalities and segmentation objectives. Task-Incremental Learning provides a privacy-preserving approach to continually evolve a universal model on tasks from sequentially-arriving medical departments. However, training the model solely on the incoming task induces forgetting on past tasks, since consecutive tasks exhibit concurrent shifts in image appearance and segmentation objective. To address this problem, we propose a novel Coupled Comprehensive Generative Replay (C^2GR) framework that simultaneously synthesizes image-mask pairs of previous tasks to mitigate forgetting under concurrent appearance and objective shifts. This requires preserving image-mask correspondence for structure-realistic generation and bridging asynchronous optimization of the generator and segmentor for segmentation-oriented generation. Specifically, we propose a Bayesian Joint Diffusion (BJD) method that formulates the correspondence as conditional distributions optimized via conditional denoising. Furthermore, we develop a Relation-aware Unified Prompt Synchronization (RUPS) scheme to simultaneously modulate the generator and segmentor via a shared task-relation-aware prompt for synchronizing their optimization. Experiments on 20 tasks spanning diverse modalities and objectives demonstrate that C^2GR exhibits only a 2.44% drop in overall performance compared to joint training with all task data, effectively alleviating forgetting from the concurrent shifts. Our code will be made publicly available at https://github.com/mar-cry/C2GR.","authors":["Wei Li","Jingyang Zhang","Guoan Wang","Junzhi Ning","Yang Chen","Guang Yang","Lixu Gu"],"published":"2026-06-22T15:19:03Z","updated":"2026-06-22T15:19:03Z","abstract_url":"https://arxiv.org/abs/2606.23473v1","html_url":"https://arxiv.org/html/2606.23473v1","pdf_url":"https://arxiv.org/pdf/2606.23473v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23455v1","title":"MeGAS: Thermomechanical Dynamic Gaussian Splatting for Thermophysical Scene Editing","abstract":"Recent advances integrate physically grounded Newtonian dynamics with neural rendering frameworks, narrowing the gap between photorealistic scene reconstruction and physics-based animation. However, existing approaches focus on mechanically driven dynamics while neglecting temperature, a fundamental yet invisible physical factor underlying phenomena such as melting, solidification, and other thermomechanical processes. In this paper, we propose MeGAS, a novel framework that incorporates thermomechanical phase-change dynamics into 3D Gaussian Splatting (3DGS). Specifically, we propose a new thermomechanical dynamic Gaussian Splatting representation that augments 3DGS with temperature attributes and employs a heat advection-diffusion solver with MPM dynamics incorporating phase transitions, enabling physically plausible and visually realistic synthesis of thermophysical phenomena. Furthermore, a new topology-adaptive Gaussian rendering strategy is proposed to mitigate cracking and floaters under extreme deformation. Extensive experiments demonstrate that MeGAS produces physically consistent thermomechanical behavior while maintaining high-fidelity photorealistic rendering, advancing toward physics-integrated world models.","authors":["Zesong Yang","Yuanhang Lei","Liyuan Cui","Yihang Chen","Jiaer Huang","Boming Zhao","Peter Yichen Chen","Hujun Bao","Zhaopeng Cui"],"published":"2026-06-22T15:05:59Z","updated":"2026-06-22T15:05:59Z","abstract_url":"https://arxiv.org/abs/2606.23455v1","html_url":"https://arxiv.org/html/2606.23455v1","pdf_url":"https://arxiv.org/pdf/2606.23455v1.pdf","matched_keywords":["3d","representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23436v1","title":"Rethinking Object-Centric Representations for Video Dynamics Modeling","abstract":"Unsupervised video object tracking aims to decompose dynamic scenes into persistent, object-centric entities without manual annotations. Many recent approaches rely on slot-based representations, where a fixed set of latent variables (\"slots\") represent individual objects across frames. To preserve object identity, these models enforce temporal consistency on slot embeddings. However, when appearance and pose are entangled, this consistency objective conflicts with object motion and viewpoint changes. As a result, slots tend to lock onto static regions (e.g., background) to satisfy the consistency objective, while foreground objects become fragmented across multiple slots or frequently swap identities. To address these limitations, we propose STAITUS, a unified framework that explicitly disentangles each slot into appearance and geometric pose (position/scale). Leveraging this disentanglement, STAITUS enforces within-frame spatial separation and applies temporal alignment only in appearance space, yielding sharper masks and more persistent identities under motion, occlusion, and object entry/exit. Furthermore, to mitigate over-segmentation, we introduce an adaptive gating mechanism that dynamically adjusts the number of active slots to match scene complexity. Extensive experiments on synthetic and real-world benchmarks demonstrate that STAITUS substantially outperforms state-of-the-art baselines in segmentation quality and tracking stability.","authors":["Amaury Wei","Ismail Nejjar","Olga Fink"],"published":"2026-06-22T14:55:41Z","updated":"2026-06-22T14:55:41Z","abstract_url":"https://arxiv.org/abs/2606.23436v1","html_url":"https://arxiv.org/html/2606.23436v1","pdf_url":"https://arxiv.org/pdf/2606.23436v1.pdf","matched_keywords":["video","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23373v1","title":"Polynomial Dice Loss for Medical Image Segmentation","abstract":"Medical image segmentation is a fundamental task for medical image processing and computer-assisted intervention, yet data imbalance and small lesion detection pose significant challenges. Dice Loss, which measures the overlap between predicted and ground truth regions, is widely used to mitigate these issues. To further emphasize its properties, we propose Polynomial Dice Loss, a polynomial extension of Dice Loss. Specifically, by leveraging the geometric characteristics of Dice Loss and formulating the loss function as a polynomial representation via Taylor expansion, we enable the adjustment of the contribution of higher-order components to the loss function. In our experiments, we evaluate the proposed method against loss functions derived from conventional Dice and Tversky coefficients. Experimental results and further analysis show that the polynomial formulation provides a simple way to control the loss shape and achieves competitive performance across multiple segmentation settings.","authors":["Hiroaki Aizawa"],"published":"2026-06-22T14:07:33Z","updated":"2026-06-22T14:07:33Z","abstract_url":"https://arxiv.org/abs/2606.23373v1","html_url":"https://arxiv.org/html/2606.23373v1","pdf_url":"https://arxiv.org/pdf/2606.23373v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23362v1","title":"TooBad: Backdoor Diffusion Models with Ultra-Low Poison Rate and Imperceptible Trigger","abstract":"Diffusion models (DMs), despite their impressive capabilities across a wide range of generative tasks, have been shown to be vulnerable to backdoor attacks. However, existing backdoor methods face critical trade-offs among key factors: attack performance, stealthiness, time complexity, and required poison rates. For example, achieving high attack performance typically demands a high poison rate and prolonged training, which undermines stealthiness, making the attack more detectable by backdoor defenses. This paper proposes TooBad (trigger optimization for backdoor diffusion models), a backdoor framework which introduces a novel DM-tailored trigger optimization technique to dramatically enhance the performance of backdoor attacks on DMs. Experiments on representative benchmarks such as CIFAR-10 show that TooBad can achieve high ASRs ($> 85$%) at only 0.5% poison rate, significantly lower than the 10% typically required by prior work on the same datasets. At 5% poison rate, TooBad reaches nearly 100% ASR within just 3-5 backdoor injection epochs, whereas existing methods need at least 30-50 epochs at double the poison rate for comparable results. Despite its potency, TooBad easily evades SOTA defenses and maintains high utility. These results reveal a critical threat on DMs and highlight the need for more robust defenses against such stealthy yet efficient attacks.","authors":["Vu Tuan Truong","Long Bao Le"],"published":"2026-06-22T14:00:06Z","updated":"2026-06-22T14:00:06Z","abstract_url":"https://arxiv.org/abs/2606.23362v1","html_url":"https://arxiv.org/html/2606.23362v1","pdf_url":"https://arxiv.org/pdf/2606.23362v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23356v1","title":"Changing Modalities: Adapting Remote Sensing Models to New Satellites and Sensors","abstract":"Machine learning models for remote sensing are trained and deployed on a static set of modalities. However, as we equip newer satellites with novel sensors and retire old ones, practitioners may wish to deploy an existing model on a substitution, superset, or subset of modalities with minimal retraining given data availability or practical computational constraints. We study the setting of updating existing models to changing modalities and identify three main scenarios: Modality Transfer (substitution), Addition (superset), and Peeking (subset). We propose DeluluNet, an architecture with modular components for all three changing modality scenarios. DeluluNet is trained end-to-end, learning a multi-modal model from a unimodal teacher and unlabeled multimodal data via modality hallucination--predicting missing modality representations from those that are present. As a result, DeluluNet can keep predicting even when input modalities change, providing a practical alternative to re-labeling and re-training in a changing world.","authors":["Tim G. Zhou","Anthony Fuller","Geoff Pleiss","Evan Shelhamer"],"published":"2026-06-22T13:56:12Z","updated":"2026-06-22T13:56:12Z","abstract_url":"https://arxiv.org/abs/2606.23356v1","html_url":"https://arxiv.org/html/2606.23356v1","pdf_url":"https://arxiv.org/pdf/2606.23356v1.pdf","matched_keywords":["representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23354v1","title":"Faithful Grounded Visual Reasoning via Learned Proxy-Tokens","abstract":"Multimodal Large Language Models (MLLMs) have achieved remarkable success in Visual Question Answering (VQA), yet their \"black-box\" nature hinders deployment in critical domains. Grounded Visual Reasoning (GVR) approaches attempt to improve interpretability by explicitly couple textual rationales with visual grounding information, which are typically textual coordinates. This mechanism lacks a learnable semantic link to the visual features, often resulting in a semantic-spatial gap where the model hallucinates coordinates that do not correspond to image evidences. In this work, we introduce Composer, a MLLM that leverages a novel visual grounding mechanism based on learned proxy-tokens to promote faithful interpretability. These discrete symbolic pointers explicitly index the image latent space, allowing the model to manipulate visual regions as addressable, semantically manipulable sets. To rigorously validate our novel grounding mechanism, we constructed ComposerGCoT, a dataset synthesized to enable holistic assessment of reasoning consistency and grounding accuracy. Experimental results indicate that Composer achieves performance parity with its coordinate-based counterpart in final answer accuracy, while improving visual grounding accuracy by +9.0 points. By demonstrating that discrete proxy-tokens capture spatial semantics more effectively than typical textual coordinates, we establish that visual grounding mechanisms with learnable semantic links represent a promising path toward trustworthy and reliable MLLMs.","authors":["Tom Hodemon","Mohamed Chaouch","Aboubacar Tuo","Angelique Loesch"],"published":"2026-06-22T13:54:48Z","updated":"2026-06-22T13:54:48Z","abstract_url":"https://arxiv.org/abs/2606.23354v1","html_url":"https://arxiv.org/html/2606.23354v1","pdf_url":"https://arxiv.org/pdf/2606.23354v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23344v1","title":"RT-DocLayout: Real-Time End-to-End Document Layout Analysis with Reading Order in the Wild","abstract":"Accurate document layout analysis remains a critical bottleneck for document parsing systems, due to the intricate coupling among heterogeneous document layout elements, geometric distortions (\\eg, paper warping and bending, perspective variations), and reading order within diverse layout structures. Existing approaches typically rely on fragmented multi-stage pipelines or computationally heavy generative Transformer architectures, leading to error propagation and limited efficiency. In this paper, we present RT-DocLayout, a highly efficient end-to-end framework for document layout analysis, designed as a front-end for document parsing tasks. The proposed model unifies classification, detection, pixel-level segmentation, and reading order prediction for layout elements within a single 33M-parameter architecture. Built upon the RT-DETR, our key contribution is a unified multi-task formulation within a single query-based decoder that simultaneously classifies, regresses bounding box, generates masks, and constructs relationship to reason reading order. By jointly learning geometric and structural representations, RT-DocLayout introduces multi-task optimization that substantially improves robustness under real-world document distortions. Extensive experiments on public benchmarks demonstrate state-of-the-art performance in document layout analysis while maintaining real-time inference speed(132.1 FPS). When coupled with downstream OCR engines, RT-DocLayout significantly improves full-document reconstruction quality, providing a scalable and practical foundation for real-world document intelligence systems.","authors":["Cheng Cui","Tingquan Gao","Xueqing Wang","Changda Zhou","Hongen Liu","Ting Sun","Yubo Zhang","Zelun Zhang","Jiaxuan Liu","Manhui Lin","Yue Zhang","Suyin Liang","Yiqing Xiang","Yi Liu"],"published":"2026-06-22T13:48:39Z","updated":"2026-06-22T13:48:39Z","abstract_url":"https://arxiv.org/abs/2606.23344v1","html_url":"https://arxiv.org/html/2606.23344v1","pdf_url":"https://arxiv.org/pdf/2606.23344v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23327v1","title":"VideoAgent: All-in-One Framework for Video Understanding and Editing","abstract":"Video editing has become essential in digital media creation, yet existing automated systems are restricted to short segment processing and domain-specific tasks. They face two critical limitations: i) inability to handle diverse video comprehension and editing operations, and ii) lack of long-video understanding for coherent narrative creation. We propose VideoAgent, an all-in-one agentic framework addressing these challenges through two key innovations. First, we develop automated video shot creation with shot planning agents for coherent narratives and cross-modal retrieval for aligned visual content. Second, we design a multi-agent orchestration framework integrating over thirty specialized editing agents. Intent parsing filters relevant tools while textual-gradient graph optimization assembles complex editing pipelines. Extensive experiments on our newly-proposed VideoEdit benchmark and public datasets demonstrate VideoAgent's superiority over existing multimodal LLMs and agentic systems. VideoAgent achieves 87-95% orchestration success rates while reducing API costs by 60%. Human evaluation across six video categories shows VideoAgent produces professional-quality content approaching human-level performance, with ratings only 4% below human-created videos. We release our code at https://github.com/HKUDS/VideoAgent.","authors":["Hengji Zhou","Lingxuan Huang","Jian Wang","Bing Zhou","Si Wu","Lianghao Xia","Chao Huang"],"published":"2026-06-22T13:37:08Z","updated":"2026-06-22T13:37:08Z","abstract_url":"https://arxiv.org/abs/2606.23327v1","html_url":"https://arxiv.org/html/2606.23327v1","pdf_url":"https://arxiv.org/pdf/2606.23327v1.pdf","matched_keywords":["video","retrieval","agent","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23298v1","title":"Ocean4D: Generative Underwater 4D Reconstruction via Medium-Aware Video Diffusion","abstract":"Underwater 4D reconstruction remains challenging due to the coupling between degraded light transport in participating media and dynamic water variations. Most existing Methods are developed under in-air assumptions and do not explicitly account for underwater absorption and backscatter. Additionally, near-static assumptions make these approaches sensitive to drifting particles and dynamic distractors , leading to unstable geometry and inconsistent cross-view results. To address these issues, we propose a generative framework for underwater 4D reconstruction, named Ocean4D, which is built on two complementary components. Specifically, 4D-GCC constructs 4D geometrically consistent conditioning with improved cross-frame coverage, while the Medium-Aware Block performs implicit medium-aware denoising in the latent diffusion process to stabilize underwater appearance under absorption and scattering. Given a monocular video and target cameras, our method generates videos along the target trajectories while preserving global structure and cross-view consistency. Extensive experiments on both dynamic and static underwater benchmarks demonstrate state-of-the-art performance on underwater reconstruction.","authors":["Yuqiang Huang","Yuxi Wang","Junyu Dong","Zhaoxiang Zhang"],"published":"2026-06-22T13:10:26Z","updated":"2026-06-22T13:10:26Z","abstract_url":"https://arxiv.org/abs/2606.23298v1","html_url":"https://arxiv.org/html/2606.23298v1","pdf_url":"https://arxiv.org/pdf/2606.23298v1.pdf","matched_keywords":["video","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23270v1","title":"BoxCtrl: 3D-Aware Visual Prompting for Geometric Image Editing","abstract":"As instruction-based editing models and multimodal large language models advance, diverse image editing tasks have become feasible. However, achieving precise and consistent geometric image editing, such as translating, scaling, and rotating in 3D space, remains a major challenge. In this work, we introduce BoxCtrl, a 3D-aware visual prompting framework. Unlike text-only or coarse 2D-guided approaches, our method introduces informative RGB 3D bounding boxes projected onto 2D images as visual prompts. The three orthogonal faces of each box are painted with distinct RGB colors, simultaneously encoding position, size, and orientation to provide a compact, intuitive in-context visual example. The key to BoxCtrl's success lies in these well-designed bounding boxes, which decouple geometric control from appearance control. This enables the model to learn consistent correspondences between faces of the same color in the latent space, leading to a precise understanding of geometric intentions and accurate editing results. We introduce a two-stage training paradigm: Supervised Fine-Tuning (SFT) followed by Reinforcement Learning (RL). To address paired data scarcity, we construct a large-scale synthetic dataset for SFT, equipping the model with fundamental editing capabilities. To bridge the synthetic-to-real domain gap, we incorporate an online RL stage leveraging unpaired real-world data. Guided by a reward function evaluating geometric accuracy and visual fidelity, our SFT-RL strategy significantly enhances geometric precision while maintaining photorealistic quality. Extensive experiments demonstrate that BoxCtrl achieves state-of-the-art performance across translation, rotation, scaling, and composite editing tasks.","authors":["Feifei Wang","Shiyuan Yang","Xiaoyu Li","Jing Liao"],"published":"2026-06-22T12:49:29Z","updated":"2026-06-22T12:49:29Z","abstract_url":"https://arxiv.org/abs/2606.23270v1","html_url":"https://arxiv.org/html/2606.23270v1","pdf_url":"https://arxiv.org/pdf/2606.23270v1.pdf","matched_keywords":["3d","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23267v1","title":"Safe Few-Step Generation via Velocity Editing","abstract":"Flow matching has recently emerged as a strong paradigm for state-of-the-art text-to-image (T2I) generation, enabling high-quality generation with a small number of sampling steps. As these models are increasingly integrated into real-world applications, ensuring safe and non-sensitive content generation has become a critical requirement. However, adapting safety and concept removal methods to this new generation framework remains an open challenge. Specifically, prior methods largely rely on iterative trajectory steering across a number of denoising steps or on CLIP-centric prompt embedding manipulation. These design assumptions pose fundamental bottlenecks for safety in flow matching-based T2I generation, where limited sampling steps constrain iterative correction and modern context-aware text encoders diminish the effectiveness of embedding-level interventions. In this paper, we propose VESFlow, a training-free safety method tailored to flow matching with extremely few sampling steps. Leveraging the fact that flow matching models learn the marginal velocity, we directly edit the velocity field via a safe-conditional posterior. VESFlow steers the trajectory toward safe outputs while leaving the conditioning prompt unchanged. Building on the observation that VESFlow leaves outputs unchanged under benign prompts, we further introduce a risk score-based filtering that bypasses velocity editing to reduce computational cost while preserving benign prompt generation. Based on this filtering, we propose VESFlow+, a stronger variant of VESFlow that not only edits the velocity toward the safe direction, but also pushes it away from the unsafe direction. Experimental results show that VESFlow+ removes the target concept, reducing the attack success rate by NudeNet to 6.3% on Ring-A-Bell and 6.8% on MMA-Diffusion on the 4-step MeanFlow model, while preserving fidelity on benign prompts.","authors":["Yujin Choi","Jaehong Yoon"],"published":"2026-06-22T12:47:57Z","updated":"2026-06-22T12:47:57Z","abstract_url":"https://arxiv.org/abs/2606.23267v1","html_url":"https://arxiv.org/html/2606.23267v1","pdf_url":"https://arxiv.org/pdf/2606.23267v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23256v1","title":"P-JEPA: Procedural Video Representation Learning via Joint Embedding Predictive Architecture","abstract":"The increasing maturity of embodied AI platforms has driven a growing interest in procedural video representation learning to support intelligent assistance systems for complex, multi-step tasks. Leveraging large-scale latent predictive training, video foundation models capture video dynamics, enabling downstream tasks such as activity understanding, spatiotemporal localization, and predictive control. However, procedural videos include actions with long-range dependencies that these models do not support, due to the quadratic complexity of self-attention. Distinct actions, for example, may be visually similar despite appearing at different points in the procedure, such as turning the stove on versus off. Here, we propose a backbone-agnostic approach that learns long-duration video representations by reducing the problem to a dense, frame-aligned action space and predicting pooled masked latent vectors. This approach allows our Procedural Joint Embedding Predictive Architecture (P-JEPA) to ingest videos over 30 minutes long, enabling effective long-form understanding of procedural steps. We evaluate P-JEPA using features extracted with VJEPA2.1, TSM, and I3D over the EgoExo4D, EgoProceL, and Assembly101 datasets, finding that it consistently improves linear separability, streaming inference, and temporal action segmentation performance, achieving state-of-the-art results on EgoExo4D fine-grained action classification while using an order of magnitude fewer parameters than LLM-based methods and running in real time.","authors":["Felix Tristram","Stefano Gasperini","Benjamin Killeen","Marcel Walch","Christian Benz","Nassir Navab","Ghazal Ghazaei"],"published":"2026-06-22T12:38:36Z","updated":"2026-06-22T12:38:36Z","abstract_url":"https://arxiv.org/abs/2606.23256v1","html_url":"https://arxiv.org/html/2606.23256v1","pdf_url":"https://arxiv.org/pdf/2606.23256v1.pdf","matched_keywords":["video","3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23254v1","title":"SteerVTE: Seamless Video Text Editing with Style and Glyph Control","abstract":"Visual text editing aims to precisely modify text in images and videos while preserving stylistic consistency and visual realism. Despite significant advances in the image domain, video text editing remains largely unexplored: it is a localized task demanding stroke-level precision within small text regions, which compounds the challenges of cross-frame accuracy, temporal coherence, and stylistic fidelity. We introduce SteerVTE, a unified framework that \\underline{\\textbf{steer}}s a frozen video diffusion model to perform precise \\underline{\\textbf{V}}ideo \\underline{\\textbf{T}}ext \\underline{\\textbf{E}}diting through style and glyph control. Built on a frozen diffusion transformer, SteerVTE attaches a lightweight text context adapter with two complementary modules: a style encoder capturing the original text's visual attributes, and dual-granularity glyph encoders encoding the target text at both the line and character levels. To overcome the inherently weak text rendering priors of video foundation models, we further propose a glyph-aware spatial-focal loss and a three-stage progressive training curriculum that scales from image to video data. To support large-scale training, we also develop an automatic synthesis pipeline and construct SteerVTE-1M, a dataset of one million triplets spanning diverse scenes, fonts, and stylistic effects. Extensive experiments demonstrate that SteerVTE substantially outperforms existing video editing baselines across text accuracy, style consistency, and temporal coherence.","authors":["Kai Zeng","Moran Li","Zhengwei Wang","Yingchen Yu","Yiheng Lin","Ruichuan An","Ming Lu","Qi She","Wentao Zhang"],"published":"2026-06-22T12:37:15Z","updated":"2026-06-22T12:37:15Z","abstract_url":"https://arxiv.org/abs/2606.23254v1","html_url":"https://arxiv.org/html/2606.23254v1","pdf_url":"https://arxiv.org/pdf/2606.23254v1.pdf","matched_keywords":["video","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23226v1","title":"PhysFlow: Frequency Decoupled with Dual-Field Rectified Flow for Remote Photoplethysmography","abstract":"Remote Photoplethysmography (rPPG) enables contactless pulse estimation from facial videos, serving as a vital tool for health monitoring. However, current deep learning methods often struggle under complex disturbances, particularly varying illumination, facial expressions, and unconstrained head movements. In such scenarios, subtle physiological signals are easily dominated by external interference, making the recovered rPPG waveform unstable and unreliable. One important reason is that most existing methods directly model the rPPG signal in a unified manner, where different signal components are coupled during reconstruction. This makes it difficult to preserve weak pulse-related variations when strong disturbance-induced changes are present. To address this challenge, we propose PhysFlow, a frequency-decoupled dual-field rectified flow framework tailored for robust rPPG estimation. Specifically, the ground-truth rPPG signal is decomposed into trend and amplitude components, which are used as separate supervisory targets. Based on the extracted facial features, PhysFlow learns two component-specific conditional velocity fields to model the two components separately. This design reduces mutual interference between different components and improves the robustness of rPPG reconstruction under complex disturbances. Moreover, the rectified flow formulation enables efficient waveform reconstruction with only a few ordinary differential equation (ODE) integration steps. Extensive experiments on multiple benchmark datasets demonstrate that PhysFlow outperforms state-of-the-art methods in both heart-rate estimation and rPPG waveform reconstruction across diverse challenging scenarios.","authors":["Zixu Li","jianjun Qian","Hang Shao","Lei Luo","Jian Yang"],"published":"2026-06-22T12:14:37Z","updated":"2026-06-22T12:14:37Z","abstract_url":"https://arxiv.org/abs/2606.23226v1","html_url":"https://arxiv.org/html/2606.23226v1","pdf_url":"https://arxiv.org/pdf/2606.23226v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23221v1","title":"RS-Gen: A Multi-Stage Agentic Framework for Reasoning and Search-Augmented Image Generation","abstract":"Recent years have witnessed remarkable progress in image generation and editing, particularly regarding instruction following and visual fidelity. However, when handling ambiguous intentions, logical reasoning, and Out-of-Distribution (OOD) knowledge, existing image models often yield sub-optimal results due to a lack of deep reasoning capabilities and real-time external information. Although emerging unified understanding-and-generation models attempt to bridge this gap, they remain constrained by their intrinsic parameter scales and static knowledge gaps. Inspired by agentic paradigms, we propose RS-Gen: a plug-and-play, training-free, multi-stage image agentic framework. RS-Gen innovatively introduces a \"Questioning-and-Solving\" closed-loop mechanism to accurately identify logical issues and knowledge gaps, autonomously planning actions to bridge information deficits and execute deep logical reasoning. Extensive experiments demonstrate that RS-Gen significantly expands the capability boundaries of foundational image generation and editing models. Specifically, on the WISE Verified and RISEBench benchmarks, RS-Gen yields substantial absolute performance gains of 0.313 for Qwen-Image and 19.70 for Qwen-Image-Edit-2511, respectively, successfully elevating both to the state-of-the-art (SOTA) level among open-source models.","authors":["Feifei Bian","Zhimin Zheng","Wei Deng","Daiguo Zhou","Jian Luan"],"published":"2026-06-22T12:09:29Z","updated":"2026-06-22T12:09:29Z","abstract_url":"https://arxiv.org/abs/2606.23221v1","html_url":"https://arxiv.org/html/2606.23221v1","pdf_url":"https://arxiv.org/pdf/2606.23221v1.pdf","matched_keywords":["agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23129v1","title":"Spectral Gating via Damped Oscillations for Adaptive Implicit Neural Representations","abstract":"Implicit Neural Representations (INRs) have been proven successful in encoding continuous signals through coordinate-based networks, yet facing a spectral dilemma: periodic activations capture fine details but act as all-pass filters that memorise noise, while spatially compact activations regularise effectively but suffer from low-frequency bias. Existing attempts to resolve this trade-off introduce computational overhead or tuning frailty. We propose to model each neuron's activation as the steady-state response of a sinusoidally-forced damped harmonic oscillator, whose amplitude naturally governs the network's spectral selectivity during training. By jointly optimising the oscillator parameters alongside the network weights, our method adapts to the target signal's spectral content without explicit regularisation. Initialised in the stopband, the network exhibits a coarse-to-fine learning curriculum that progressively expands its spectral gate, capturing low-frequency structures first and high-frequency details only when justified by the reconstruction objective. Comprehensive experiments show that our approach consistently achieves state-of-the-art or competitive results against established INRs, while requiring no task-specific tuning of any hyperparameters.","authors":["Alex Costanzino","Pierluigi Zama Ramirez","Giuseppe Lisanti","Luigi Di Stefano"],"published":"2026-06-22T11:59:47Z","updated":"2026-06-22T11:59:47Z","abstract_url":"https://arxiv.org/abs/2606.23129v1","html_url":"https://arxiv.org/html/2606.23129v1","pdf_url":"https://arxiv.org/pdf/2606.23129v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23212v1","title":"Temporally Aware Densification for Dynamic 3D Gaussian Splatting","abstract":"Despite modeling temporal motion, dynamic 3D Gaussian Splatting (3DGS) methods still inherit a static densification strategy that is ill-suited for dynamic scenes. This neglect of temporal behavior leads to under-reconstructed and blurry dynamic regions, as short-lived Gaussians receive sparse supervision and fail to densify effectively. We propose a Visibility-Aware Densification (VAD) framework that integrates temporal visibility into the densification process, ensuring that Gaussians are refined based on their actual temporal presence. A Temporally-Adaptive Thresholding (TAT) mechanism further adjusts each Gaussian's densification threshold according to its temporal lifespan, promoting balanced refinement of both static and dynamic regions. Finally, a Temporal Offset Warping (TOW) design enhances deformation capacity around temporal centers, extending the lifespan of highly dynamic Gaussians and facilitating more effective densification. Our approach achieves substantial improvements in the visual quality of dynamic regions, outperforming existing methods across three dynamic multi-view benchmark datasets. Moreover, the proposed VAD module generalizes across diverse dynamic 3DGS methods, consistently improving dynamic reconstruction as a plug-and-play component.","authors":["Vikram Sandu","Mayurdeep Pathak","Rajiv Soundararajan"],"published":"2026-06-22T11:55:21Z","updated":"2026-06-22T11:55:21Z","abstract_url":"https://arxiv.org/abs/2606.23212v1","html_url":"https://arxiv.org/html/2606.23212v1","pdf_url":"https://arxiv.org/pdf/2606.23212v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23206v1","title":"CFPO: Counterfactual Policy Optimization for Multimodal Reasoning","abstract":"Large Vision-Language Models (LVLMs) have demonstrated remarkable capabilities in multimodal reasoning. However, prevailing reinforcement learning (RL) paradigms lack explicit counterfactual enhancement and causal learning mechanisms. This fundamental deficiency results in severe grounding failures, manifesting as a tendency to ignore visual evidence in favor of language priors or exhibiting hallucination drift during long chain-of-thought reasoning. To address this root cause, we propose CounterFactual Policy Optimization (CFPO), a novel framework that enforces causal consistency between visual perception and textual reasoning. CFPO introduces a cross-modal counterfactual enhancement mechanism, which regularizes the policy by maximizing the discrepancy between the model's predictions and those from a counterfactual state where critical visual cues are suppressed. This approach seamlessly integrates with standard algorithms like GRPO and DAPO without requiring external reward models or additional supervision. Extensive experiments demonstrate that CFPO significantly improves reasoning fidelity, achieving consistent gains of 3.17%-6.25% over standard RL baselines and 1.32%-2.13% over the state-of-the-art perception-aware method (PAPO). Code is available at https://github.com/Raven-July/CFPO.","authors":["Zhangyuan Yu","Wanran Sun","Guangjing Yang","Xiaohu Wu","Qicheng Lao"],"published":"2026-06-22T11:51:51Z","updated":"2026-06-22T11:51:51Z","abstract_url":"https://arxiv.org/abs/2606.23206v1","html_url":"https://arxiv.org/html/2606.23206v1","pdf_url":"https://arxiv.org/pdf/2606.23206v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23204v1","title":"Unmasking LAION-5B: Age, Gender, Race, and Emotion Biases in Large-Scale Image Datasets","abstract":"Large-scale image-text datasets, such as LAION-5B, are foundational to modern AI systems, yet their vast scale and uncurated nature raise significant concerns about demographic and stereotypical biases. This study presents a comprehensive analysis of the demographic composition and representational, stereotypical, and intersectional biases in LAION-2B-en and LAION-2B-multi, the two main components of the LAION-5B dataset. Using state-of-the-art models -- FairFace, DeepFace, and Emo-AffectNet -- we analyze faces detected in the dataset to identify biases across age, gender, race, and expressed emotion. Our findings reveal substantial overrepresentation of young adults (20--39), White individuals, and males, alongside consistent underrepresentation of minority racial groups and middle-aged or older women across both dataset components. We also observe stereotypical associations between demographic attributes and emotions, such as ``Anger'' being predominantly linked to males and ``Happiness'' to females, pointing to systemic imbalances in the data. The consistency of these patterns across two demographic models and both components of LAION-5B demonstrates that these biases are deeply embedded in one of the most widely-used training datasets. Given the scale at which LAION-5B is used to train generative models, these demographic imbalances could shape the behavior and outputs of numerous downstream AI systems.","authors":["Iris Dominguez-Catena","Daniel Paternain","Mikel Galar"],"published":"2026-06-22T11:49:23Z","updated":"2026-06-22T11:49:23Z","abstract_url":"https://arxiv.org/abs/2606.23204v1","html_url":"https://arxiv.org/html/2606.23204v1","pdf_url":"https://arxiv.org/pdf/2606.23204v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23200v1","title":"NGPS: Structure-Preserving Self-Supervised Denoising via Neighbor-Guided Patch Sampling","abstract":"Neighboring-slice self-supervised denoising is attractive for volumetric medical imaging, yet inter-slice misalignment breaks anatomical correspondence and often yields ghosting and blurred margins when adjacent slices are used naively as targets. We propose Neighbor-Guided Patch Sampling (NGPS), a lightweight framework that constructs neighboring supervision under local inter-slice misalignment without explicit registration. To avoid learning from misleading targets, prior methods commonly mask discrepant regions, but this stabilizes training at the cost of leaving a non-trivial portion of neighboring evidence unexploited, particularly around high-frequency anatomical boundaries. NGPS addresses this by decoupling structure matching from signal retrieval: for each masked location, it searches a local neighborhood for structurally similar candidate patches using a simple guide image (e.g., fast bilateral filtering), while retrieving the supervision signal directly from the raw noisy neighbor at the matched coordinates. By matching on a noise-attenuated guide while retrieving raw values from neighboring slices, NGPS constructs local pseudo targets without a learned registration module. Across the evaluated CT and synthetic-Rician MRI settings, NGPS improves fidelity and structure-sensitive metrics. Code is available at https://github.com/cv-cho/NGPS .","authors":["Jaehyun Cho","YoungJoon Yoo"],"published":"2026-06-22T11:46:34Z","updated":"2026-06-22T11:46:34Z","abstract_url":"https://arxiv.org/abs/2606.23200v1","html_url":"https://arxiv.org/html/2606.23200v1","pdf_url":"https://arxiv.org/pdf/2606.23200v1.pdf","matched_keywords":["retrieval"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23186v1","title":"StreamPPG: Low-Latency rPPG Estimation via Consistent Privileged Learning","abstract":"Remote photoplethysmography (rPPG) estimates the blood volume pulse (BVP) signal from facial videos, enabling contact-free health monitoring. Conventional clip-wise approaches, which use video clips as input, require capturing over one hundred frames before inference, thus introducing several seconds of delay and hindering real-time use. Meanwhile, frame-wise approaches struggle to capture long-range temporal and periodic features of physiological rhythms, and therefore lead to reduced estimation accuracy. To overcome these issues, we propose StreamPPG, a unified architecture that enables low-latency frame-wise physiological signal estimation while achieving competitive accuracy compared with clip-wise approaches. StreamPPG is trained under a consistent privileged learning (CPL) strategy, which leverages ground-truth rPPG signals as privileged information to enhance the model's representation capability. Extensive experiments demonstrate that StreamPPG achieves state-of-the-art accuracy across multiple datasets while maintaining real-time throughput on edge devices.","authors":["Yiming Li","Yihan Yang","Yuguang Chu","Yuanhui Hu","Si-Yuan Cao","Xiaohan Zhang","Xiaokai Bai","Zhe Wu","Hui-Liang Shen"],"published":"2026-06-22T11:31:01Z","updated":"2026-06-22T11:31:01Z","abstract_url":"https://arxiv.org/abs/2606.23186v1","html_url":"https://arxiv.org/html/2606.23186v1","pdf_url":"https://arxiv.org/pdf/2606.23186v1.pdf","matched_keywords":["video","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23132v1","title":"T-VSS: Test-Time Visual Subspace Steering for Adversarial Robustness of Vision-Language Models","abstract":"Vision-language models (VLMs) achieve strong zero-shot recognition, but they remain highly vulnerable to adversarial perturbations. Recent test-time adaptations improve robustness without retraining, but they do not directly adapt the corrupted visual representation itself. Prompt-based methods adapt the learnable text prompts, while input-space methods optimize pixels or padding at test time. These approaches can improve predictions, but they do so through an indirect and expensive optimization path. We propose Test-time Visual Subspace Steering (T-VSS), a lightweight defense that performs test-time adaptation directly in the visual feature space. T-VSS first builds a sample-specific low-rank subspace from multi-view feature residuals anchored at the attacked image. It then learns a shared feature correction within this subspace using reliability-weighted entropy minimization. By constraining adaptation to a compact visual geometry, T-VSS steers attacked features toward more stable and discriminative predictions while avoiding noisy full-space updates. Experiments on fine-grained, ImageNet, and ImageNet-OOD benchmarks show that T-VSS improves adversarial robustness while maintaining competitive clean accuracy and better efficiency than prior test-time adaptations.","authors":["Jaehyuk Jang","Minseok Seo. Seungju Cho","Kangwook Ko","Changick Kim"],"published":"2026-06-22T10:21:24Z","updated":"2026-06-22T10:21:24Z","abstract_url":"https://arxiv.org/abs/2606.23132v1","html_url":"https://arxiv.org/html/2606.23132v1","pdf_url":"https://arxiv.org/pdf/2606.23132v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23126v1","title":"MambaADv2: Evolving Duality-enhanced State Space Model for Unsupervised Anomaly Detection","abstract":"While recent advancements in anomaly detection have demonstrated the efficacy of CNN- and Transformer-based approaches, these architectures face inherent limitations: CNNs struggle to capture long-range dependencies, whereas Transformers suffer from quadratic computational complexity. Consequently, Mamba-based architectures have attracted considerable attention, as they successfully combine superior long-range dependency modeling with linear computational complexity. By critically rethinking the structural evolution across the Mamba lineage 1-3 series, this paper proposes MambaADv2, a framework tailored for multi-class unsupervised anomaly detection. MambaADv2 comprises a pre-trained encoder and a Mamba-inspired decoder, equipped with Duality-enhanced State Space (DSS) modules across multiple scales. The proposed DSS module effectively models both global dependencies and local representations by integrating parallel-cascaded Hybrid State Space (HSS) blocks and frequency-enhanced convolution operations. The structure of the Hybrid State Space (HSS) block is tailored by following the SSD-based Mamba lineage and incorporating Mamba3-style position-aware state-space modeling, leveraging the dual computational paths of linear recurrence and parallel matrix formulation to model local continuity and global contextual comparison, thereby better serving the core anomaly detection objective of precisely reconstructing normal representations while magnifying anomalous deviations. Additionally, we propose a semantics-adaptive progressive scanning strategy that decays scanning complexity along the feature pyramid.","authors":["Xiaobin Hu","Haoyang He","Bo Yin","Yu He","Lei Xie","Jiangning Zhang","Yu-Gang Jiang","Shuicheng Yan"],"published":"2026-06-22T10:14:06Z","updated":"2026-06-22T10:14:06Z","abstract_url":"https://arxiv.org/abs/2606.23126v1","html_url":"https://arxiv.org/html/2606.23126v1","pdf_url":"https://arxiv.org/pdf/2606.23126v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23118v1","title":"LUMINA-26: Low-Light Understanding for Modeling and Interpreting Night-time Actions","abstract":"Low-light human action recognition remains a challenging problem due to poor illumination, amplified noise, motion ambiguity, and diverse real-world scenes. Existing low-light datasets often lack sufficient action diversity, capture realism, or balanced class distribution, limiting the development of robust models. To address this, we introduce LUMINA-26: Low-Light Understanding for Modeling and Interpreting Night-time Actions, comprising 6,784 clips across 26 action classes, recorded from 22 subjects across 20 indoor and outdoor locations under naturally occurring low-light conditions. We also propose Illumi-Net: An Illumination-Adaptive Mixture-of-Experts Network, which leverages video-level illumination cues to guide adaptive enhancement and transformer-based spatio-temporal feature extraction, with expert-conditioned decision fusion. Our method surpasses previous state-of-the-art performance on ELLAR (Top-1: 55.13%, Top-5: 78.87%) and establishes a strong baseline on LUMINA-26 (Top-1: 75.95%, Top-5: 93.58%), offering a practical benchmark for future low-light action recognition research.","authors":["Aman Kumar Pandey","Anil Singh Parihar"],"published":"2026-06-22T10:03:37Z","updated":"2026-06-22T10:03:37Z","abstract_url":"https://arxiv.org/abs/2606.23118v1","html_url":"https://arxiv.org/html/2606.23118v1","pdf_url":"https://arxiv.org/pdf/2606.23118v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23105v1","title":"Compression and Retrieval: Implicit Memory Retrieval for Video World Models","abstract":"Video world models hold promise for simulating interactive environments, yet maintaining consistent long-term memory across complex camera trajectories remains a critical challenge. Existing methods typically rely on computationally expensive context scaling or rigid heuristic retrieval mechanisms, which lacks generalization to varying camera trajectories and environments. In this paper, we propose Compression and Retrieval (CaR), an attention-driven implicit memory retrieval mechanism to overcome these limitations. By injecting viewpoint information via positional encoding, our method performs flexible memory retrieval through attention computation. To efficiently process extended contexts with minimal computational overhead, we further introduce a lightweight context compression network. Furthermore, we construct SceneFly, a large-scale synthetic dataset featuring realistic camera trajectories and frame-level annotations to train and evaluate long-horizon video world models. Extensive experiments demonstrate that our approach achieves state-of-the-art results on established benchmarks and exhibits strong generalization to open-domain scenes.","authors":["Zhan Peng","Jie Ma","Huiqiang Sun","Chong Gao","Zhijie Xue","Zhiyu Pan","Zhiguo Cao","Jun Liang","Jing Li"],"published":"2026-06-22T09:46:36Z","updated":"2026-06-22T09:46:36Z","abstract_url":"https://arxiv.org/abs/2606.23105v1","html_url":"https://arxiv.org/html/2606.23105v1","pdf_url":"https://arxiv.org/pdf/2606.23105v1.pdf","matched_keywords":["video","retrieval"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23069v1","title":"Rethinking Prototype-based Similarity Learning for Few-Shot Object Detection","abstract":"Few-shot object detection aims to detect novel object categories from only a few labeled examples, avoiding costly large-scale annotation. Recent prototype-based similarity learning approaches enable training-free adaptation by matching query features with class prototypes. However, they suffer from two fundamental limitations: (i) class confusion arising from inter-class similarity margin collapse, and (ii) insufficient visual cues for precise localization, as similarity scores capture only class-level semantic affinity while providing limited spatial information. To address these issues, we introduce two complementary components. Text-Anchored Semantic Mask (TSMa) leverages class-level text features as semantic anchors to identify semantically aligned channels through channel-wise interaction between visual and text features. By suppressing style-induced spurious responses and emphasizing class-intrinsic signals, TSMa enlarges inter-class similarity margins and mitigates class confusion. We further propose Stage-Aligned Hierarchical Autoregressive Regression (SHARe), which reformulates localization as a hierarchical autoregressive process that progressively refines bounding boxes across multiple stages. SHARe leverages the layer-wise characteristics of ViT representations by aligning feature abstraction levels with regression stages: deeper layers guide early coarse localization, while shallower layers rich in edge and texture cues refine spatial details in later stages. Experiments on COCO demonstrate a new state of the art, outperforming the previous best by +10.1 nAP, with extensive analysis validating each component. The code is available at https://github.com/VisualScienceLab-KHU/ReSet.","authors":["KunHo Heo","Seungjae kim","Wongyu Lee","SuYeon Kim","MyeongAh Cho"],"published":"2026-06-22T09:18:00Z","updated":"2026-06-22T09:18:00Z","abstract_url":"https://arxiv.org/abs/2606.23069v1","html_url":"https://arxiv.org/html/2606.23069v1","pdf_url":"https://arxiv.org/pdf/2606.23069v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23063v1","title":"Attention-Spectrum Regularization for Replay-Free Continual Multimodal LLMs","abstract":"Multimodal large language models (MLLMs) are increasingly required to adapt to non-stationary streams of visual domains, question types, and user instructions, yet continual fine-tuning often causes severe forgetting of previously acquired multimodal skills. Existing continual vision-language methods mainly preserve outputs, replay data or pseudo-data, regularize embedding geometry, or allocate task-specific parameters, but they provide limited control over how internal cross-modal attention patterns supporting old skills drift during adaptation. We propose Attention-Spectrum Regularization (ASR), a replay-free continual learning framework that preserves skill-conditioned structures of cross-modal attention. ASR treats cross-attention maps as two-dimensional signals, summarizes their scale and directional properties into compact spectral statistics, and stores only skill-wise prototype distributions instead of replaying past image-question pairs, generated pseudo-examples, or old-stage teacher snapshots. In later stages, a phase-invariant spectral regularizer constrains harmful drift of these prototypes while allowing instance-level attention to adapt to new tasks. We provide theoretical analysis showing that skill-conditioned spectral drift controls forgetting under a spectral sufficiency assumption, and that Fourier power spectra are stable to spatial translations and bounded perturbations. Experiments on continual VQA and multimodal instruction-tuning benchmarks, including VQA v2, VQACL, CLT-VQA, CoIN, and UCIT, show that ASR consistently improves final performance and reduces forgetting over strong replay-, regularization-, and adapter-based baselines. Preserving skill-level attention structure is an effective and lightweight mechanism for continual MLLMs. Code is available at https://github.com/Creative-zcx/attention-spectrum-replay","authors":["Chuangxin Zhao","Canran Xiao","Siyuan Ma","Mengyao Lyu","Yanbiao Ma","Jun Xia","Guiguang Ding","Yang Liu"],"published":"2026-06-22T09:13:53Z","updated":"2026-06-22T09:13:53Z","abstract_url":"https://arxiv.org/abs/2606.23063v1","html_url":"https://arxiv.org/html/2606.23063v1","pdf_url":"https://arxiv.org/pdf/2606.23063v1.pdf","matched_keywords":["instance","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23062v1","title":"VolHuMe: a High-Resolution Large Scale Dataset of Volumetric Human Meshes","abstract":"We introduce VolHuMe, a dataset of high-quality 4D human scans captured with a state-of-the-art volumetric studio using 64 RGB and 32 depth cameras. VolHuMe contains individual captures of 104 subjects and provides extensive ground truth, including SMPL-X, high-resolution meshes, multi-view RGB/depth images, rigged meshes, point clouds, garment segmentation, and detailed hand and facial geometry. Unlike prior datasets that primarily rely on full-body imagery, VolHuMe uses a close-range, high-resolution capture setup that preserves fine-grained body-part details, improving geometric fidelity and texture resolution. We benchmark VolHuMe on state-of-the-art methods across 3D and 4D human reconstruction tasks, showcasing the dataset's quality and exposing the limitations of current evaluation testbeds.","authors":["Giulia Martinelli","Niccolò Bisagno","Nicola Garau","Esa Rahtu","Nicola Conci"],"published":"2026-06-22T09:13:52Z","updated":"2026-06-22T09:13:52Z","abstract_url":"https://arxiv.org/abs/2606.23062v1","html_url":"https://arxiv.org/html/2606.23062v1","pdf_url":"https://arxiv.org/pdf/2606.23062v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23061v1","title":"MotionHalluc: Diagnosing Kinematic Hallucinations in Fine-Grained Motion Reasoning","abstract":"Motion instruction generation in cross-video comparison aims to produce corrective feedback that describes the differences between a query and a reference motion. However, existing models often generate instructions that exhibit motion hallucinations, failing to reflect actual kinematic differences between paired videos. To systematically investigate these hallucinations, we introduce MotionHalluc, a dedicated benchmark for evaluating motion hallucinations in paired-video comparison. MotionHalluc comprises 1540 fine-grained questions over 553 video pairs, evaluating hallucinations along three core dimensions: (1)directional hallucination, (2)attributional hallucination, and (3)temporal hallucination. Extensive evaluations of state-of-the-art large multimodal models demonstrate high susceptibility to these hallucinations. Furthermore, we provide Perceive-Parse-Verify (PPV) as a training-free measurements extraction and verification baseline that converts candidate instructions into executable measurement queries and supplies kinematic measurements at inference time. Our results show that this simple measurements injection yields an average 10.6% performance gain across models, suggesting that motion reasoning with explicit quantitative measurements is a key factor in reducing hallucinations in cross-video comparison. Our code and dataset will be made publicly available upon acceptance.","authors":["Weile Guo","Shenghong He","Danying Mo","Chengdong Xu","Xuexun Liu","Chao Yu"],"published":"2026-06-22T09:13:19Z","updated":"2026-06-22T09:13:19Z","abstract_url":"https://arxiv.org/abs/2606.23061v1","html_url":"https://arxiv.org/html/2606.23061v1","pdf_url":"https://arxiv.org/pdf/2606.23061v1.pdf","matched_keywords":["video","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23058v1","title":"Three-Step Hierarchical Transformer for Multi-Pedestrian Trajectory Prediction","abstract":"Pedestrian trajectory prediction requires modeling temporal dynamics, multimodal cues, and social interactions in crowded environments. Existing methods often address these factors separately or entangle them in costly attention blocks, limiting scalability, flexibility, and interpretability. We propose a three-step hierarchical Transformer that explicitly separates temporal encoding, multimodal fusion, and scene-level interaction reasoning. Lightweight GRU summaries enable efficient cross-modal attention, while social attention over time--agent tokens captures inter-pedestrian influences at manageable cost. Experiments on JTA, JRDB, and the Pedestrians and Cyclists in Road Traffic dataset show state-of-the-art performance on real-world datasets (JRDB, Urban) and competitive results on JTA. Ablation and qualitative analyses confirm the contribution of each stage and the model's ability to anticipate complex behaviors such as early turning.","authors":["Raphaël Delécluse","Hazem Wannous","Laurent Grisoni","Laurent Guimas"],"published":"2026-06-22T09:11:20Z","updated":"2026-06-22T09:11:20Z","abstract_url":"https://arxiv.org/abs/2606.23058v1","html_url":"https://arxiv.org/html/2606.23058v1","pdf_url":"https://arxiv.org/pdf/2606.23058v1.pdf","matched_keywords":["agent","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23046v1","title":"UECP: Uncertainty-Enhanced Collaborative Perception","abstract":"Collaborative perception serves as a pivotal solution to enhance the perception capability of individual agents in autonomous driving, where a core challenge lies in seeking reliable evidence to quantify and weight the contribution of each participating agent. Existing methods typically rely on a confidence map, which is co-trained with the detection head, but it is inherently correlated with the detection results and thus fails to provide unbiased physical evidence. Furthermore, how to deeply integrate evidence into the cooperative fusion process remains an open question. To address these issues, this paper first proposes an uncertainty map, a physically grounded and unambiguous metric for evaluating perception quality. This map is directly supervised by real-time sensor signals, i.e., LiDAR point density, ensuring decoupling from detection noise and thereby providing physical scenario-aware evidence for weighting agent contribution. Based on this map, we develop the Uncertainty-Enhanced Collaborative Perception (UECP) framework, centered on the Uncertainty-Aware Pyramid Fusion (UAPF) module. UAPF uses a coarse-to-fine strategy, with two key components: Uncertainty-Weighted Downsampling (UWD) for high-fidelity feature preservation, and Uncertainty-Guided Residual Fusion (UGRF) to reinforce ego features, suppressing noise and ensuring robust fusion. Extensive experiments on real-world datasets show UECP outperforms state-of-the-art methods in effectiveness and robustness by embedding the uncertainty map into fusion. Code will be publicly available.","authors":["Kang Yang","Tianci Bu","Peng Wang","Deying Li","Wen Jie","Yongcai Wang"],"published":"2026-06-22T08:55:10Z","updated":"2026-06-22T08:55:10Z","abstract_url":"https://arxiv.org/abs/2606.23046v1","html_url":"https://arxiv.org/html/2606.23046v1","pdf_url":"https://arxiv.org/pdf/2606.23046v1.pdf","matched_keywords":["agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23041v1","title":"SPAR: Semantic-Pixel Self-Alignment and Adaptive Routing for Unified Multimodal Models","abstract":"Multimodal Large Language Models (MLLMs) have achieved remarkable success in visual understanding but remain constrained in visual generation due to the fundamental feature discrepancy between semantic perception and pixel-level reconstruction. Bridging this gap requires overcoming two core challenges: endowing semantic encoders with high-fidelity reconstruction capabilities, and effectively aligning generative models with semantic spaces without relying on external teachers. To this end, we propose a novel unified multimodal framework featuring \\textbf{S}emantic-\\textbf{P}ixel self-alignment and \\textbf{A}daptive \\textbf{R}outing (\\textbf{SPAR}). First, to reconcile semantic perception with pixel-level reconstruction, we introduce an asymmetric dual-stream unified tokenizer. A lightweight semantic stream anchors discriminative features, while a Transformer-augmented pixel stream recovers fine-grained visual details into a unified compact latent space. Second, to eliminate external dependencies, we propose a self-aligned generation paradigm that natively leverages this optimized tokenizer as an internal alignment teacher for the diffusion model. Furthermore, to facilitate flexible multimodal interaction within this unified space, we introduce Dynamic Token Routing, which enables each token to adaptively aggregate multi-layer MLLM features based on its distinct semantic demands. Extensive experiments demonstrate that SPAR establishes the state-of-the-art for unified architectures, achieving exceptional generation and reconstruction quality while preserving foundational visual understanding capabilities.","authors":["Hongxiang Li","Hongxu Chen","Chenyang Zhu","Xiaoshuang Huang","Jiayin Cai","Xiaolong Jiang","Yao Hu","Long Chen"],"published":"2026-06-22T08:48:19Z","updated":"2026-06-22T08:48:19Z","abstract_url":"https://arxiv.org/abs/2606.23041v1","html_url":"https://arxiv.org/html/2606.23041v1","pdf_url":"https://arxiv.org/pdf/2606.23041v1.pdf","matched_keywords":["multimodal","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23031v1","title":"DrivingVoxels: Compositional Sparse Voxel Rasterization for Dynamic Driving Scene Reconstruction","abstract":"Reconstructing dynamic urban scenes remains challenging due to the unbounded nature of driving environments and the presence of multiple dynamic objects. Currently, potentially faster sparse voxel methods are mainly designed for static scenarios. On the other hand, dynamic approaches based on 3D Gaussian Splatting, despite their high-fidelity, are often time-consuming for driving scenarios and exhibit uncontrollable memory growth in large scenes. To address these limitations, we present DrivingVoxels, a compositional sparse voxel rendering framework for dynamic driving scenes. Our method jointly rasterizes sparse voxels from multiple independent octrees within a single rendering pass. Each rigid dynamic object is represented by an octree defined in its local coordinate frame, while a separate static octree models the stationary background. DrivingVoxels adopts a fully explicit, neural-free representation together with a LiDAR-guided structural initialization that efficiently captures scene geometry. We evaluate our framework on the PandaSet benchmark, demonstrating that DrivingVoxels performs on par on perceptual metrics and better on structural metrics for NVS and reconstruction while requiring shorter training times than previous 3DGS-base methods to an efficient optimization workflow anchored by a strong LiDAR prior.","authors":["Tania Aguirre","Luis Roldão","Moussab Bennehar","Nathan Piasco","Dzmitry Tsishkou","Simone Rossi","Pietro Michiardi"],"published":"2026-06-22T08:42:16Z","updated":"2026-06-22T08:42:16Z","abstract_url":"https://arxiv.org/abs/2606.23031v1","html_url":"https://arxiv.org/html/2606.23031v1","pdf_url":"https://arxiv.org/pdf/2606.23031v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23027v1","title":"Learning Stable Canonical Worlds for Novel View Synthesis and Beyond","abstract":"Feed-forward Gaussian splatting (FFGS) facilitates real-time novel view synthesis, yet current methods often remain tied to view-dependent predictions. As more input views are added, they may accumulate noisy or redundant evidence instead of converging to a stable scene representation. In this paper, we introduce CanonicalGS, a feed-forward pipeline that maps cluttered multi-view observations into a stable, scene-centric representation. CanonicalGS first extracts view-centric evidence from depth, semantic features, and uncertainty estimates, and then aggregates this evidence in a canonical latent world using uncertainty-aware fusion. By emphasizing reliable observations while suppressing uncertain or redundant ones, CanonicalGS produces representations that scale more effectively for novel view synthesis and transfer to downstream visual perception tasks. Experiments show up to a $2.5$ dB improvement in peak signal-to-noise ratio for synthesizing novel views and an $11\\%$ gain in semantic segmentation accuracy.","authors":["Xiaoyu Xu","Jian Zou","Sheyang Tang","Zhihua Wang","Jing Liao","Kede Ma"],"published":"2026-06-22T08:38:39Z","updated":"2026-06-22T08:38:39Z","abstract_url":"https://arxiv.org/abs/2606.23027v1","html_url":"https://arxiv.org/html/2606.23027v1","pdf_url":"https://arxiv.org/pdf/2606.23027v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23023v1","title":"Boosting Neural Video Codec via Scale-Driven Online Flow Refinement","abstract":"Although state-of-the-art neural video codecs (NVCs) have achieved remarkable performance, they suffer from limited generalization when encountering complex motion patterns unseen during training. To bridge this domain gap without the expensive cost of online fine-tuning, we propose a Training-Free Scale-Driven Online Flow Refinement (SOFR) method. Serving as a plug-and-play module, SOFR integrates motion information from coarse and fine scales and dynamically fuses them according to warping accuracy, effectively rectifying motion estimation errors with negligible computational overhead. Furthermore, we design a rate-aware strategy that selects different dynamic fusion strategies according to bitrate modes, and employs a reliability check based on warping error to ensure robustness. Extensive experiments on the USTC-TD dataset verify the effectiveness and generalization of SOFR across various NVC frameworks, including DCVC-SDD, DCVC-FM, and EHVC. Notably, it brings an average of 2.84% and 4.05% bitrate savings in terms of PSNR and MS-SSIM, respectively, to DCVC-FM with negligible coding time increase. Our code is available at https://github.com/SunnyMass/SOFR.","authors":["Tiange Zhang","Rongqun Lin","Haocheng Tang","Xiandong Meng","Weijia Jiang","Zhimeng Huang","Siwei Ma"],"published":"2026-06-22T08:36:23Z","updated":"2026-06-22T08:36:23Z","abstract_url":"https://arxiv.org/abs/2606.23023v1","html_url":"https://arxiv.org/html/2606.23023v1","pdf_url":"https://arxiv.org/pdf/2606.23023v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23019v1","title":"ScalingAttention: Discovering Intrinsic Sparse Attention Topology for Video Diffusion Transformers","abstract":"While Diffusion Transformers (DiTs) have revolutionized high-fidelity video generation, their reliance on 3D full attention creates a quadratic computational bottleneck. Existing sparse methods face a dilemma: dynamic pruning suffers from prohibitive runtime overhead and memory fragmentation, while static heuristics fail to capture fine-grained dependencies. In this work, we propose ScalingAttention, a training-free framework grounded in a key inductive bias: while individual activations are input-dependent, the high-mass attention regions for each head rapidly converge to a stable, prompt-agnostic Intrinsic Sparse Topology. This topology is weight-encoded, scale-invariant, and efficient to extract. ScalingAttention decouples topology discovery from sparsity control via: (1) WEST (Weight-Encoded Sparse Topology), which extracts a robust block-sparse prior mask offline to eliminate runtime search; (2) FAST (Fidelity-Aware Sensitivity Tuning), which adaptively tunes head-wise sparsity based on diffusion fidelity requirements. To ensure practical acceleration, we co-design a hardware-aligned bit-wise block-sparse kernel. Experiments on Wan2.1 show up to 1.90X end-to-end speedup with superior fidelity, establishing a new Pareto frontier over state-of-the-art baselines.","authors":["Ruiliang Zhou","Xuecheng Wu","Kang He","Guangyun Han","Bin Liu","Qinqin Chen","Wende Xu","Qingjie Zhao","Chengru Song"],"published":"2026-06-22T08:32:07Z","updated":"2026-06-22T08:32:07Z","abstract_url":"https://arxiv.org/abs/2606.23019v1","html_url":"https://arxiv.org/html/2606.23019v1","pdf_url":"https://arxiv.org/pdf/2606.23019v1.pdf","matched_keywords":["video","3d","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.23005v1","title":"From Point Estimates to Distributions: GMM Pooling for MIL in Preterm Birth Prediction","abstract":"Preterm birth (PTB) prediction can enable targeted surveillance and timely intervention, yet most ultrasound-based models use a single selected transvaginal ultrasound (TVUS) frame per patient despite routine exams acquiring multiple cervical images. We formulate PTB prediction as a multiple instance learning (MIL) problem, representing each patient as a variable-sized bag of TVUS images with a single outcome label. To move beyond standard MIL aggregators that collapse a bag into a point estimate, we propose a Gaussian Mixture Model (GMM) pooling, which summarizes all images in a bag into a fixed-length representation by modeling their feature distribution. This design captures intra-patient variability. We evaluate the method on a private clinical cohort and on a public lymph node metastasis benchmark. For PTB prediction, GMM pooling improves over the instance-based model PR-AUC from 0.44 to 0.56. On the lymph node benchmark, it achieves state-of-the-art performance with 0.91 F1-score and 0.89 ROC-AUC for classification and 0.18 MAE for regression. The code is publicly available at https://github.com/HussainAlasmawi/GMM_Pooling.","authors":["Hussain Alasmawi","Numan Saeed","Soha Said","Mohammad Yaqub"],"published":"2026-06-22T08:18:08Z","updated":"2026-06-22T08:18:08Z","abstract_url":"https://arxiv.org/abs/2606.23005v1","html_url":"https://arxiv.org/html/2606.23005v1","pdf_url":"https://arxiv.org/pdf/2606.23005v1.pdf","matched_keywords":["representation","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22999v1","title":"Black-Box Continual Learning for Vision-Language Models","abstract":"The rapid deployment of Vision-Language Models (VLMs) in dynamic environments necessitates the ability to learn continuously without forgetting. However, traditional continual learning (CL) settings often rely on white-box paradigms, which is increasingly invalidated by the shift toward cloud-hosted models. In this paper, we introduce Black-CL, a more realistic benchmark for VLMs that enforces three primary real-world challenges: weight and architecture inaccessibility, constrained computation, and task-agnostic inference. The learner can query only output embeddings or logits, with no gradient flow through or structural modification of the backbone. Current CL methodologies, which rely on backbone backpropagation or complex parameter expansion, are fundamentally incompatible with these constraints. Under this setting, we propose BETA, a simple yet effective baseline built on the key insight that solely optimizing textual prototypes can navigate the complexities of CL. BETA integrates three core components: Semantic Projection Accumulation (SPA) for incremental knowledge acquisition, Latent Distribution Replay (LDR) for anchoring the embedding space against catastrophic forgetting, and Test-Time Prototype Adaptation (TTPA) for dynamic, instance-aware boundary refinement. Extensive experiments across ten diverse datasets and various backbones demonstrate that BETA significantly outperforms existing black-box tuners. Remarkably, with only 0.05 M trainable parameters, a 180--3000$\\times$ reduction compared to competitive methods, BETA achieves performance on par with or even exceeding white-box CL methods. We believe Black-CL and BETA provide a foundational framework for future advancements in continual learning and accelerates the transition of continual learning from academia to real-world systems.","authors":["Yuting Li","Weihang Fang","Haoyuan Gao","Linghe Kong","Yexin Li","Lichao Sun","Weiran Huang"],"published":"2026-06-22T08:14:55Z","updated":"2026-06-22T08:14:55Z","abstract_url":"https://arxiv.org/abs/2606.22999v1","html_url":"https://arxiv.org/html/2606.22999v1","pdf_url":"https://arxiv.org/pdf/2606.22999v1.pdf","matched_keywords":["instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22987v1","title":"Can Single-View Mesh Reconstruction Generalize to Robot Camera Rotation?","abstract":"Single-view mesh reconstruction predicts object meshes and spatial layouts from a single observation, making it attractive for fast robot spatial reasoning and real-to-sim digital twins. However, robot-mounted cameras naturally rotate during manipulation and navigation, while learned single-view reconstruction models often rely on view-dependent priors and may generalize poorly to out-of-distribution camera rotations. Such rotations can introduce 3D inconsistencies, incorrect layouts, and violations of physical constraints, but this failure mode remains under-evaluated. We introduce an evaluation protocol with controlled axis-wise roll, pitch, and yaw sweeps to trace errors in monocular depth estimation (MDE), canonical object meshes, camera-space layout, and physical plausibility within a representative SAM3D-style pipeline. On the Aria Digital Twin dataset and a real Franka wrist-camera sequence, camera rotations induce MDE distortion, layout drift, and collision penetration, while canonical mesh predictions remain relatively stable. A two-stage SAM3D+FoundationPose pipeline is more robust than one-stage feed-forward layout prediction, and our Gravity-Aware Refinement reduces one-stage pairwise ICP-based layout-orientation error by 47.1$\\%$. Our evaluation reveals that current single-view mesh reconstruction methods generalize poorly to robot camera rotation, and suggests that explicit gravity cues are important for reliable robotic single-view mesh reconstruction.","authors":["Yu Zhan","Guangcheng Chen","Hanjing Ye","Zhiqin Cheng","Zanjia Tong","Wenjun Xu","Hong Zhang"],"published":"2026-06-22T08:05:45Z","updated":"2026-06-22T08:05:45Z","abstract_url":"https://arxiv.org/abs/2606.22987v1","html_url":"https://arxiv.org/html/2606.22987v1","pdf_url":"https://arxiv.org/pdf/2606.22987v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22986v1","title":"Subject-Level Unknown-Identity Identification from Leap Motion Controller 2 Hand Landmarks","abstract":"This work studies subject recognition from Leap Motion Controller 2 (LMC2) hand landmark data under a subject-level unknown-identity identification protocol on the Multi View Leap2 Hand Pose (ML2HP) dataset. Using only the landmark modality, we retain the original geometric representation and enrich it with fingertip-to-palm distances and palm-normalized inter-finger angular descriptors. Evaluation is performed under a Leave-One-Subject-Out (LOSO) protocol in which, for each outer fold, one subject is excluded from the enrolled set and treated as unknown at test time. To avoid tuning on the true outer unknown subject, the unknown-rejection threshold is selected in an inner validation step by temporarily withholding one enrolled subject from the inner gallery and using it only for threshold estimation. We compare a tree ensemble baseline with two neural alternatives: a learned embedding baseline based on centroid matching and cosine-similarity-based rejection, and an MLP+OpenMax model, which represents a more established open-set recognition approach. Under this evaluation setup, Extra Trees remains the strongest overall method, indicating that the main challenge on this benchmark is not enrolled-subject discrimination alone, but robust score separation between known and unknown probes. The results support the feasibility of compact, interpretable landmark-based descriptors for contactless hand-based unknown-subject rejection and identification on a small-cohort dataset.","authors":["Bahar Moharrer","Susanna Cifani","Marco Raoul Marini","Luigi Cinque","Maria De Marsico"],"published":"2026-06-22T08:05:27Z","updated":"2026-06-22T08:05:27Z","abstract_url":"https://arxiv.org/abs/2606.22986v1","html_url":"https://arxiv.org/html/2606.22986v1","pdf_url":"https://arxiv.org/pdf/2606.22986v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22971v1","title":"Humanoid-OmniOcc: Stereo-Based Full-View Occupancy Dataset for Embodied AI","abstract":"Occupancy prediction at voxel-level granularity is essential for safe robotic navigation and interaction in complex environments. Existing occupancy datasets, however, are predominantly designed for autonomous driving with vehicle-centric biases -- forward-facing cameras, far-field geometry, and static road priors -- limiting their applicability to embodied humanoid perception. We present Humanoid-OmniOcc, a large-scale panoramic stereo-based occupancy dataset tailored for humanoid robots. The dataset encompasses 15 diverse simulated indoor scenes and 5 real-world environments, yielding over 155K samples with broad scene and style diversity. Importantly, the dataset is designed around a Real2Sim2Real closed-loop paradigm: real sensor specifications drive physically accurate simulation, simulation produces large-scale annotated training data, and models trained in simulation are directly evaluated on real-world captures -- enabling iterative refinement of the sim-to-real pipeline. We further propose \\textbf{H}umanoid \\textbf{S}urround \\textbf{S}tereo-guided \\textbf{Occ}upancy model (Humanoid-OmniOcc) that exploits robust depth priors for accurate 2D-to-3D lifting. Extensive experiments show that Humanoid-OmniOcc consistently outperforms monocular baselines and generalizes well to both unseen simulated test scenes and real-world environments, validating the effectiveness of the Real2Sim2Real design. Code and data will be available upon acceptance at https://d-robotics-ai-lab.github.io/humanoid-omniocc.","authors":["Xianda Guo","Bohao Zhang","Chenwei Huang","Shiyuan Chen","Ruilin Wang","Yiqun Duan","Cong Yang","Qin Zou","Wei Sui"],"published":"2026-06-22T07:52:25Z","updated":"2026-06-22T07:52:25Z","abstract_url":"https://arxiv.org/abs/2606.22971v1","html_url":"https://arxiv.org/html/2606.22971v1","pdf_url":"https://arxiv.org/pdf/2606.22971v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22959v1","title":"The Impact of VAE Design on Latent Pose Representations for Diffusion-based Sign Language Production","abstract":"Latent diffusion approaches to sign language production (SLP) rely on an initial stage that learns an encoding of sign pose sequences, enabling generative modeling in the resulting latent space. The autoencoder used in this stage is typically evaluated in terms of reconstruction quality using geometric metrics common in SLP. While informative, these metrics do not fully capture latent space properties that may influence the training and performance of the downstream generative model. In this work, we investigate how architectural and training objective design choices in a variational autoencoder (VAE) for sign pose encoding affect latent space structure, and how these differences translate into the performance of a latent diffusion model for text-to-sign generation. Our experiments on Phoenix14T dataset show that variations in generative performance, measured through back-translation BLEU scores, can sometimes be better explained by differences in latent space properties than by VAE reconstruction accuracy alone.","authors":["Guilhem Fauré","Mostafa Sadeghi","Sam Bigeard","Slim Ouni"],"published":"2026-06-22T07:38:55Z","updated":"2026-06-22T07:38:55Z","abstract_url":"https://arxiv.org/abs/2606.22959v1","html_url":"https://arxiv.org/html/2606.22959v1","pdf_url":"https://arxiv.org/pdf/2606.22959v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22958v1","title":"PG-MAP: Joint MAP Optimization for Inference-Time Alignment of Diffusion and Flow-Matching Models","abstract":"Inference-time alignment of pretrained text-to-image models is typically performed along a single control axis, such as classifier-free guidance, attention editing, or reward-based latent perturbations. This limitation prevents modeling joint dependencies between conditioning and latent variables and hinders transfer across generative transports. We propose PG-MAP, a training-free framework that formulates inference-time alignment as a trajectory-level Gibbs-MAP / proximal energy optimization over the conditioning $c$ and latent state $z_t$ via a forward-consistency coupling, optionally guided by a frozen preference reward. This joint formulation enables coordinated updates across modalities while remaining compatible with both diffusion and flow-matching models through transport-specific adaptations. Across diffusion backbones (SD~1.5, SDXL), PG-MAP consistently improves alignment metrics such as PickScore and Aesthetic, and can be effectively combined with tuned classifier-free guidance to achieve the strongest overall performance. On flow-matching models (SD3.5-medium), the framework reduces to a latent-only variant, achieving $\\mathbf{91.9\\%}$ PickScore and $75.7\\%$ HPS win rates against a static baseline, with controlled experiments ruling out noise-related artifacts. Human evaluations further confirm consistent preference over strong baselines, including tuned CFG and compute-matched universal guidance. Finally, an oracle-routing analysis shows that the relative importance of conditioning and latent optimization depends on prompt types, surfacing further headroom that a per-prompt selector could exploit.","authors":["Ruolan Sun","Pawel Polak"],"published":"2026-06-22T07:36:36Z","updated":"2026-06-22T07:36:36Z","abstract_url":"https://arxiv.org/abs/2606.22958v1","html_url":"https://arxiv.org/html/2606.22958v1","pdf_url":"https://arxiv.org/pdf/2606.22958v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22955v1","title":"Evo-RAD: Navigating Rare Retinal Disease Diagnosis via Self-Evolving Agentic Retrieval","abstract":"Large-scale pretrained foundation models have revolutionized general medical screening, but often falter on rare diseases because such conditions are underrepresented in real-world clinical datasets. While retrieval-augmented diagnosis attempts to mitigate this, conventional static methods frequently succumb to the hubness problem, retrieving visually similar but semantically incorrect common diseases. To address this, we propose Evo-RAD, a self-evolving agentic framework that transforms evidence acquisition into a dynamic decision-making task. We formulate retrieval as a Markov Decision Process (MDP) where a graphbased agent observes the reference set state and executes actions to purge discordant evidence (DELETE), acquire pathologically consistent samples (INSERT), or conclude the evolution (TERMINATE). Optimized via Group Relative Policy Optimization (GRPO) with a homogeneityaware reward, the agent learns to maximize the diagnostic homogeneity of the support reference set. Experiments on retinal disease benchmarks show that Evo-RAD substantially improves rare-disease diagnosis, outperforming retinal foundation models by +21.04%, while also surpassing retrieval-based and parameter-efficient fine-tuning methods by +3.56%. Code is available at https://github.com/SDH-Lab/Evo-RAD.","authors":["Wangding Xia","Ye Du","Jiashi Lin","Meng Wang","Danli Shi","Shujun Wang"],"published":"2026-06-22T07:33:51Z","updated":"2026-06-22T07:33:51Z","abstract_url":"https://arxiv.org/abs/2606.22955v1","html_url":"https://arxiv.org/html/2606.22955v1","pdf_url":"https://arxiv.org/pdf/2606.22955v1.pdf","matched_keywords":["retrieval","agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22948v1","title":"ENVS: Environment-Native Verified Search for Long-Horizon GUI Agents","abstract":"As multimodal agents move from interface understanding to real software control, successful trajectory discovery in live desktop environments becomes a key challenge. GUI tasks require long-horizon sequences of precise mouse and keyboard actions, while feedback is sparse, delayed, and costly to obtain through VM rollouts. We propose Environment-Native Verified Search (ENVS), a training-time search-and-filter pipeline that uses the environment to construct verified supervision before policy optimization: it branches over behaviorally distinct GUI actions in live OSWorld VMs, verifies successful leaves, and trains from globally balanced step-level supervision. To evaluate robustness under realistic desktop interruptions, we also introduce OSWorld-Noisy, a dynamic benchmark for recoverable desktop interruptions that preserves the original tasks while testing whether agents can refocus, dismiss, wait, or recover under live perturbations. On the 300-task OSWorld pool, ENVS reaches 30.3 pass@8 on original evaluations and 29.0 on OSWorld-Noisy, outperforming matched ARPO-style online RL while reducing compute from 184-192 to 138-153 GPU-hours; even with only 30% of its search data, ENVS reaches 27.0 pass@8, exceeding ARPO from the base model. Training from noisy environments also better preserves visual-reasoning abilities on auxiliary benchmarks, including OSWorld-G Refusal (16.7 vs. 1.9) and BLINK Functional Correspondence (26.2 vs. 23.1).","authors":["Yincheng Zhou","Athena Zhuoming Zhong","Shijie Zhang","Kevin Zhang","Teresa Xiaotao Shang","Shanghang Zhang"],"published":"2026-06-22T07:28:55Z","updated":"2026-06-22T07:28:55Z","abstract_url":"https://arxiv.org/abs/2606.22948v1","html_url":"https://arxiv.org/html/2606.22948v1","pdf_url":"https://arxiv.org/pdf/2606.22948v1.pdf","matched_keywords":["agent","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22945v1","title":"Controllable Texture Tiling with Transformed RoPE-Enhanced Diffusion Models","abstract":"Realistic integration of user-specified textures into scene images is a fundamental task in computer graphics and image editing. While existing material transfer and reference-guided inpainting methods can edit surface appearances, they often fail to address the specific requirements of texture tiling. This task necessitates precisely repeating a reference pattern according to user-defined parameters such as frequency, orientation, and scale. Furthermore, current generative approaches often struggle to maintain the structural fidelity of the reference texture, limited by either destructive pixel-level resampling or the lack of fine-grained spatial information in semantic image encoders, and they frequently fail to preserve the coherent lighting and geometry of the original scene. In this paper, we propose a novel framework for controllable and high-fidelity texture tiling based on Diffusion Transformers. Our approach introduces two key technical innovations to decouple spatial manipulation from content generation. First, we propose a Coordinate-Transformed Rotary Embedding mechanism. By applying 2D affine transformations directly to the relative positional embeddings between the target latent and the image condition, we achieve precise control over tiling patterns without explicit pixel warping, thereby utilizing the full information of the reference condition without degradation. Second, a Disjoint Attention Mask is employed to shield reference features from semantic leakage. This preserves structural integrity while seamlessly blending the synthesized texture with the scene's original lighting and geometry. Extensive experiments demonstrate that our method outperforms state-of-the-art baselines in both control accuracy and texture fidelity.","authors":["Junrong Huang","Zhiyuan Zhang","Rui Tang","Hongbo Fu","Jnig Liao"],"published":"2026-06-22T07:24:15Z","updated":"2026-06-22T07:24:15Z","abstract_url":"https://arxiv.org/abs/2606.22945v1","html_url":"https://arxiv.org/html/2606.22945v1","pdf_url":"https://arxiv.org/pdf/2606.22945v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22943v1","title":"Evaluating self-supervised echocardiographic representations across downstream extraction strategies for left-ventricular segmentation and ejection fraction estimation","abstract":"Self-supervised learning (SSL) is increasingly used in medical imaging to reduce annotation requirements, but representation quality is often judged using a single downstream evaluation setting. For dense clinical tasks, this can confound representation quality with the capacity of the downstream model used to recover task-relevant information. We present a systematic evaluation of self-supervised representations for left-ventricular segmentation and ejection fraction (EF) estimation from apical four-chamber echocardiography on EchoNet-Dynamic. Rather than relying on a single downstream probe, we compare a hierarchy of extraction strategies with increasing expressivity: heuristic extraction without mask-supervised training, frozen linear probes, frozen lightweight decoder probes, and partial fine-tuning. We apply this framework to two complementary representation families: generic frozen self-DIstillation with NO labels (DINOv3) features and a task-adapted dense self-supervised representation, Bootstrap Your Own Segmentation (BYOS). In both families, heuristic extraction substantially understated what was recoverable from the frozen representation. For DINOv3, performance improved from Dice 0.684 and EF mean absolute error (MAE) 13.01 under heuristic extraction to Dice 0.906 and EF MAE 9.65 with a frozen lightweight decoder, approaching a supervised U-Net baseline (Dice 0.915, EF MAE 9.72). For BYOS, performance improved from Dice 0.687 and EF MAE 17.83 under heuristic extraction to Dice 0.902 and EF MAE 8.74 with a frozen lightweight decoder. These results show that conclusions about self-supervised representation quality in dense echocardiographic analysis depend strongly on the downstream extraction strategy used for evaluation. We therefore argue that multi-strategy evaluation is an important methodological consideration for SSL in dense medical image analysis.","authors":["Sylwia Majchrowska","Philip Teare"],"published":"2026-06-22T07:21:43Z","updated":"2026-06-22T07:21:43Z","abstract_url":"https://arxiv.org/abs/2606.22943v1","html_url":"https://arxiv.org/html/2606.22943v1","pdf_url":"https://arxiv.org/pdf/2606.22943v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22931v1","title":"BEV-Denoise: Learning Intrinsic Noise for Accurate Bird's-Eye-View Semantic Segmentation","abstract":"In this paper, we present a framework dubbed \\textbf{BEV-Denoise} that estimates and removes intrinsic noise from learned Bird's-Eye-View (BEV) features to achieve accurate BEV semantic segmentation. Inspired by the noise estimation capability of Denoising Diffusion Probabilistic Models (DDPM), we design a UNet-based noise estimation module that learns to estimate the noise from the learned BEV features. The estimated noise is then subtracted from the BEV features and fed to BEV map decoders for the final prediction results. To facilitate supervision for the noise estimation module, we follow a sequential learning paradigm called Task Decomposition (TD) where a pre-trained BEV map autoencoder is employed to train a view transformation (VT) encoder. We share three key insights learned from our intensive experiments that are critical for improved performance. We apply our framework to four existing models, encompassing the three major VT paradigms. Experimental results on a large-scale real-world dataset, nuScenes, demonstrate the effectiveness of our framework.","authors":["Dooseop Choi","Kyounghwan An","Kyoung-Wook Min"],"published":"2026-06-22T07:06:46Z","updated":"2026-06-22T07:06:46Z","abstract_url":"https://arxiv.org/abs/2606.22931v1","html_url":"https://arxiv.org/html/2606.22931v1","pdf_url":"https://arxiv.org/pdf/2606.22931v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22924v1","title":"MythraGen: Two-Stage Retrieval Augmented Art Generation Framework","abstract":"Text-to-image generation has seen rapid advancements, especially with the development of generative models. However, challenges remain in achieving high-quality, contextually accurate image outputs that faithfully match the provided textual descriptions, especially in artistic generation. In this paper, we present a simple yet efficient retrieval augmented generation framework, namely MythraGen, for text-to-artistic image generation by integrating an art retrieval mechanism with LoRA-based model fine-tuning. Our method extracts features from a large-scale art dataset, optimizing the generation process by combining artist-specific styles and content. Particularly, retrieved images from an external art database that have the highest similarity to the query prompt are used to finetune Stable Diffusion using LoRA for desired art generation. Experimental results and user studies on the WikiArt dataset show that our proposed method can generate artworks that closely match the user's input, significantly outperforming existing solutions.","authors":["Quang-Khai Le","Cong-Long Nguyen","Minh-Triet Tran","Trung-Nghia Le"],"published":"2026-06-22T07:02:33Z","updated":"2026-06-22T07:02:33Z","abstract_url":"https://arxiv.org/abs/2606.22924v1","html_url":"https://arxiv.org/html/2606.22924v1","pdf_url":"https://arxiv.org/pdf/2606.22924v1.pdf","matched_keywords":["retrieval","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22918v1","title":"Each Judge Its Own Yardstick: Discovering Per-VLM Taxonomies for Physical Video Evaluation","abstract":"Maintaining physical consistency in video generators and world models increasingly relies on vision-language models (VLMs) as automated judges that provide reward signals, ranking decisions, and data-filtering criteria. Yet VLMs differ substantially in training data and architecture, encoding physical phenomena through distinct internal representations. A single global evaluation schema therefore gives every VLM the same axes of competence, regardless of what each can actually perceive. We propose JudgeFit, an iterative refinement procedure that discovers a per-VLM evaluation taxonomy. An initial taxonomy is constructed by prompting the target VLM to enumerate physics errors on a small set of videos and clustering the resulting descriptions. The taxonomy is then refined through a diagnostic step: we calibrate the VLM's per-dimension scores to human physical-commonsense ratings, diagnose which dimensions it scores unreliably or redundantly, and prompt an LLM to repair them, iterating until convergence. We further instantiate this procedure as a benchmark and apply it to 16 VLMs spanning eight model families. The refined taxonomy outperforms the global-schema baseline on held-out videos for every VLM tested, with a mean relative improvement of approximately 32%. Beyond aggregate accuracy, the per-VLM profiles expose model-specific blind spots that overall rankings cannot anticipate, with reliability patterns differing markedly across model families.","authors":["Yu Cao","Ziquan Liu","Zhensong Zhang","Jiankang Deng","Shaogang Gong","Jifei Song"],"published":"2026-06-22T06:58:39Z","updated":"2026-06-22T06:58:39Z","abstract_url":"https://arxiv.org/abs/2606.22918v1","html_url":"https://arxiv.org/html/2606.22918v1","pdf_url":"https://arxiv.org/pdf/2606.22918v1.pdf","matched_keywords":["video","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22913v1","title":"Intend, Reflect, Refine: An Adaptive Multimodal Reflection Framework for Autonomous Driving","abstract":"Recent Vision-Language-Action (VLA) models have advanced end-to-end autonomous driving by incorporating reasoning for better interpretability and planning quality. However, most existing approaches directly generate the final trajectory without explicitly examining its future consequences, which limits their reliability in complex and dynamic environments. To address this limitation, we propose IRR-Drive (Intend, Reflect, Refine), an adaptive multimodal reflection framework for autonomous driving. Specifically, to tightly couple high-level reasoning with physical constraints, IRR-Drive first generates a preliminary textual intention and anticipates potential interactions by predicting future semantic bird's-eye view (BEV) representations. This dual-modality (Text + BEV) reflection space explicitly models anticipated scene evolution, enabling the model to rigorously self-correct and refine its initial intent before generating the final trajectory. Furthermore, to balance planning performance and computational efficiency, we construct reflection-oriented training data and design an adaptive reflection reward, enabling the model to adaptively select its reasoning mode according to scene complexity. Instead of using reasoning primarily as an auxiliary interpretation, IRR-Drive directly integrates an adaptive reflection mechanism into the planning framework, enabling grounded, decision-aware trajectory correction that is driven by scene complexity. Our method achieves state-of-the-art performance on the NAVSIM benchmark in both PDMS and EPDMS. Extensive experiments demonstrate the effectiveness of our multimodal reflection framework and validate the efficacy of the proposed adaptive reflection strategy.","authors":["Zisheng Chen","Yuping Qiu","Jianhua Han","Tao Tang","Xiuwei Chen","Likui Zhang","Ying-Cong Chen","Hang Xu","Xiaodan Liang"],"published":"2026-06-22T06:53:58Z","updated":"2026-06-22T06:53:58Z","abstract_url":"https://arxiv.org/abs/2606.22913v1","html_url":"https://arxiv.org/html/2606.22913v1","pdf_url":"https://arxiv.org/pdf/2606.22913v1.pdf","matched_keywords":["representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22907v1","title":"Improving Robotic Imitation Learning via Trajectory Standardization","abstract":"Imitation learning for robotic manipulation relies on large sets of human demonstration trajectories, which are often noisy and temporally irregular due to variable operator speed, intermittent pauses, and inconsistent action density. A common preprocessing strategy is time-uniform downsampling to shorten sequences, but it cannot effectively remove speed-induced non-uniformity or redundant pauses. This mismatch degrades data quality and hinders policy learning. To address this issue, we propose Information-Standardized Trajectory Resampling (ISR), an offline preprocessing method for effective imitation learning. ISR resamples each trajectory by enforcing approximately equal information distance between adjacent points. Specifically, we map trajectories onto an information-modulated Riemannian manifold and perform geodesic-equidistant parameterization. We construct an information-intensity field from velocity and acceleration norms: the velocity term removes small-motion redundancy, while the acceleration term preserves high-curvature and fine-manipulation phases. We evaluate ISR on three real-world manipulation tasks with mainstream imitation learning policies. Compared with the baseline time-uniform 3x downsampling, ISR improves task success rates by about 25%, remains robust across datasets collected from different operators, and reduces both dataset size and training cost. The code and videos are publicly available at https://d-robotics-ai-lab.github.io/isr.page.","authors":["Licheng Yang","Lingfeng Qian","Fei Zheng","Yonghao He","Wei Sui","Shuangshuang Li","Hu Su"],"published":"2026-06-22T06:46:26Z","updated":"2026-06-22T06:46:26Z","abstract_url":"https://arxiv.org/abs/2606.22907v1","html_url":"https://arxiv.org/html/2606.22907v1","pdf_url":"https://arxiv.org/pdf/2606.22907v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22905v1","title":"InteractiveAvatar: Real-Time Streaming Video Generation for Consistent and Intent-Aware Avatars","abstract":"Recent diffusion-based models have enabled realistic audio-driven avatar generation in real-time streaming. However, existing approaches struggle to maintain visual temporal consistency and fail to explicitly perceive user intent in complex interactive streaming scenarios. To address these challenges, we propose InteractiveAvatar, a real-time infinite-streaming video generation framework that supports visually consistent avatar video generation and intent-aware interactions. With autoregressive distillation, InteractiveAvatar achieves real-time str-eaming generation of human avatars over arbitrarily long durations. For visual consistency, we introduce a Long-Short Visual Memory (LSVM) mechanism that flexibly compresses historical visual information into compact tokens, preserving both short-range coherence and long-term consistency. To generate avatars with speeches and actions aligned with user intent, we propose a Reasoning-Reaction Module (RRM), which incorporates a State-Cycling strategy and a Cache-Switching mechanism. Extensive experimental results over diverse scenarios demonstrate that our method achieves state-of-the-art visual consistency in long-duration generation, while enabling complex user-avatar interaction in real time.","authors":["Quanyue Song","Yishan He","Yanfei Zhang","Shihao Cheng","Zhixiang He","Zhizhi Guo","Chi Zhang","Xuelong Li","Caigui Jiang"],"published":"2026-06-22T06:41:17Z","updated":"2026-06-22T06:41:17Z","abstract_url":"https://arxiv.org/abs/2606.22905v1","html_url":"https://arxiv.org/html/2606.22905v1","pdf_url":"https://arxiv.org/pdf/2606.22905v1.pdf","matched_keywords":["video","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22890v1","title":"PHOEBI: An Open-World Benchmark for Bacterial Identification in Phase-Contrast Microscopy","abstract":"Optical microscopy enables rapid, label-free imaging of live bacteria and is the standard instrument for species identification across clinical, environmental, and industrial microbiology. Yet field samples are routinely polymicrobial and may contain organisms that were never seen during system training, and no computer-vision benchmark tests multi-label species identification from phase-contrast microscopy (PCM) of such mixtures. We introduce Phase-contrast Optical bEnchmark for Bacterial Identification ($\\textbf{PHOEBI}$), a wet-lab-prepared dataset of $120{,}000$ PCM images covering $40$ combinations of six rod-shaped species, paired with a leave-combinations-out (LCO) evaluation protocol that holds out entire species combinations to mirror the practical scenario of a model trained on catalogued mixtures that must generalise to unseen ones. On LCO, every gradient-trained per-image aggregator we test drops $0.39$ to $0.57$ F1 from the in-distribution to the held-out split, a systematic open-world recognition failure in the aggregator, not the visual representation. A linear probe of thirteen different encoders over the same features spreads only about six percentage points of F1 across general-purpose and biomedical pretraining objectives, confirming the representation is sound. We propose three lightweight $\\textit{anchor-based}$ decoders that capture per-species presence geometrically over a shared frozen tile-feature pool, scoring $\\textit{higher}$ on held-out combinations than on in-distribution validation.","authors":["Aaditya Baranwal","Md Jahid Hasan","Shruti Vyas"],"published":"2026-06-22T06:01:09Z","updated":"2026-06-22T06:01:09Z","abstract_url":"https://arxiv.org/abs/2606.22890v1","html_url":"https://arxiv.org/html/2606.22890v1","pdf_url":"https://arxiv.org/pdf/2606.22890v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"},{"id":"2606.22875v1","title":"FedOT: Ownership Verification and Leakage Tracing via Watermarks for Federated LDMs","abstract":"Training Latent Diffusion Models (LDMs) within Federated Learning (FL) has attracted increasing attention due to its ability to combine the powerful generative capacity of LDMs with the privacy-preserving properties of FL. However, FL requires sharing the global model with multiple participants, which risks unauthorized model distribution or resale by malicious clients. While an intuitive approach is to adopt existing VAE-based watermarking techniques for LDMs in FL, this strategy falls short in addressing such threats due to two fundamental challenges: (1) Existing methods support ownership verification but lack the ability to trace model leakage to a specific malicious client; (2) VAE-based watermarks are vulnerable, as they can be removed simply by replacing the decoder with a clean counterpart. In this paper, we propose FedOT, the first framework for ownership verification and leakage tracing in federated LDMs. Specifically, to address the first challenge, we design a chunked watermark, where the first part is for ownership verification, and the second part is used for client identification. Furthermore, to overcome the second challenge and secure the model against VAE replacement attack, we introduce Latent Vector Transformation (LVT), which strengthens the connection between the VAE and U-Net latent spaces by modifying the original latent distribution of the VAE. Consequently, any attempt to replace the VAE for watermark removal leads to significant image quality degradation, making the LDM model unusable. Extensive experiments demonstrate that FedOT achieves superior performance in both ownership verification and traceability. Project page: https://spyzixuan.github.io/FedOT/.","authors":["Wenlong Cheng","Yuan Gan","Yunqiu Xu","Jiaxu Miao"],"published":"2026-06-22T05:39:46Z","updated":"2026-06-22T05:39:46Z","abstract_url":"https://arxiv.org/abs/2606.22875v1","html_url":"https://arxiv.org/html/2606.22875v1","pdf_url":"https://arxiv.org/pdf/2606.22875v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-23T04:56:14+00:00","last_seen_at":"2026-06-23T04:56:14+00:00"}],"tracked_paper_count":76,"storage_mode":"latest_overwrite"}};
